import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export type UserRole = 'rider' | 'driver' | 'admin' | null;

export interface User {
    id: string;
    name: string;
    email: string;
    avatar?: string;
    role: UserRole;
    rating?: number;
}

export interface Ride {
    id: string;
    pickup: string;
    destination: string;
    fare: number;
    status: 'searching' | 'assigned' | 'arrived' | 'in_progress' | 'completed' | 'cancelled';
    driverId?: string;
    riderId: string;
    vehicleType: 'eco' | 'plus' | 'lux';
    timestamp: number;
}

export interface DriverStats {
    todayEarnings: number;
    weekEarnings: number;
    ridesCompleted: number;
    acceptanceRate: number;
    onlineHours: number;
}

export interface VehicleOption {
    id: 'eco' | 'plus' | 'lux';
    name: string;
    multiplier: number;
    eta: number;
    image: string;
}

export interface Notification {
    id: string;
    title: string;
    message: string;
    type: 'info' | 'success' | 'warning' | 'error';
    read: boolean;
}

import { create } from 'zustand';
import { User, Ride, UserRole } from './types';

interface AppState {
    user: User | null;
    currentRole: UserRole;
    activeRide: Ride | null;
    isDarkMode: boolean;
    notifications: any[];

    // Actions
    setUser: (user: User | null) => void;
    setRole: (role: UserRole) => void;
    startRide: (ride: Ride) => void;
    updateRideStatus: (status: Ride['status']) => void;
    toggleDarkMode: () => void;
}

export const useAppStore = create<AppState>((set) => ({
    user: {
        id: 'u1',
        name: 'Alex Morgan',
        email: 'alex@itaxi.com',
        role: 'rider',
        rating: 4.85
    },
    currentRole: 'rider', // Default start role
    activeRide: null,
    isDarkMode: true,
    notifications: [],

    setUser: (user) => set({ user }),
    setRole: (role) => set({ currentRole: role }),
    startRide: (ride) => set({ activeRide: ride }),
    updateRideStatus: (status) => set((state) => ({
        activeRide: state.activeRide ? { ...state.activeRide, status } : null
    })),
    toggleDarkMode: () => set((state) => ({ isDarkMode: !state.isDarkMode })),
}));

// This mimics a real WebSocket service for the frontend structure
import { useAppStore } from '../store';

class MockSocketService {
    private isConnected: boolean = false;
    private listeners: Record<string, Function[]> = {};

    connect() {
        console.log("🔌 Connecting to iTaxi Realtime Server...");
        setTimeout(() => {
            this.isConnected = true;
            console.log("✅ Connected securely.");
            this.emit('connection_status', 'connected');
        }, 800);
    }

    disconnect() {
        this.isConnected = false;
        console.log("❌ Disconnected.");
    }

    on(event: string, callback: Function) {
        if (!this.listeners[event]) {
            this.listeners[event] = [];
        }
        this.listeners[event].push(callback);
    }

    off(event: string, callback: Function) {
        if (!this.listeners[event]) return;
        this.listeners[event] = this.listeners[event].filter(cb => cb !== callback);
    }

    // Simulate sending data to backend
    emit(event: string, data: any) {
        console.log(`📡 Emitting [${event}]:`, data);

        // Simulate backend responses for demo purposes
        if (event === 'request_ride') {
            setTimeout(() => {
                const store = useAppStore.getState();
                if (store.activeRide) {
                    store.updateRideStatus('assigned');
                    this.triggerListeners('ride_update', { status: 'assigned', driverId: 'd99' });
                }
            }, 3000); // Driver accepts after 3s
        }
    }

    // Helper to trigger local listeners (simulating incoming message)
    private triggerListeners(event: string, data: any) {
        if (this.listeners[event]) {
            this.listeners[event].forEach(cb => cb(data));
        }
    }
}

export const socketService = new MockSocketService();

import React from 'react';

interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
    variant?: 'primary' | 'secondary' | 'glass' | 'danger' | 'ghost';
    size?: 'sm' | 'md' | 'lg';
    isLoading?: boolean;
    icon?: React.ReactNode;
}

export const Button: React.FC<ButtonProps> = ({ 
    children, 
    variant = 'primary', 
    size = 'md', 
    isLoading, 
    icon,
    className = '',
    ...props 
}) => {
    const baseStyles = "relative overflow-hidden rounded-xl font-medium transition-all duration-300 flex items-center justify-center gap-2 active:scale-95 disabled:opacity-50 disabled:cursor-not-allowed";

    const variants = {
        primary: "bg-brand-600 hover:bg-brand-500 text-white shadow-lg shadow-brand-900/20",
        secondary: "bg-dark-800 hover:bg-dark-700 text-slate-200 border border-slate-700",
        glass: "glass-button text-brand-400 hover:text-brand-300 hover:bg-brand-500/10",
        danger: "bg-red-500/10 text-red-400 border border-red-500/20 hover:bg-red-500/20",
        ghost: "bg-transparent hover:bg-white/5 text-slate-400 hover:text-white"
    };

    const sizes = {
        sm: "px-3 py-1.5 text-xs",
        md: "px-5 py-2.5 text-sm",
        lg: "px-6 py-3.5 text-base w-full"
    };

    return (
        <button 
            className={`${baseStyles} ${variants[variant]} ${sizes[size]} ${className}`}
            disabled={isLoading || props.disabled}
            {...props}
        >
            {isLoading ? (
                <div className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin" />
            ) : (
                <>
                    {icon && <span className="text-current">{icon}</span>}
                    {children}
                </>
            )}
        </button>
    );
};

