    const handleSearch = (e: React.FormEvent) => {
        e.preventDefault();
        setStep('selecting');
    };

    const handleRequest = () => {
        const newRide: Ride = {
            id: 'ride_' + Date.now(),
            pickup: 'Current Location',
            destination: destination,
            fare: 24.50, // Mock fare
            status: 'searching',
            riderId: 'u1',
            vehicleType: selectedVehicle,
            timestamp: Date.now()
        };
        startRide(newRide);
        setStep('idle'); // Reset local step, UI will now show activeRide state

        // Simulate finding a driver
        setTimeout(() => {
            updateRideStatus('assigned');
        }, 3000);
    };

    // Active Ride Status UI
    if (activeRide) {
        return (
            <div className="relative h-full w-full">
                <MapBackground />
                <div className="absolute bottom-0 left-0 w-full p-4 z-10 md:p-6 md:w-96 md:bottom-auto md:top-4 md:left-4">
