                                {activeRide.status === 'searching' && "Finding your driver..."}
                                {activeRide.status === 'assigned' && "Driver is on the way"}
                                {activeRide.status === 'arrived' && "Driver arrived"}
                                {activeRide.status === 'in_progress' && "On trip"}
                            </h3>
                            <span className="px-2 py-1 bg-brand-500/20 text-brand-400 text-xs rounded-md uppercase font-bold tracking-wider animate-pulse">
                                {activeRide.status.replace('_', ' ')}
