                                <div className="relative w-16 h-16 mb-4">
                                    <div className="absolute inset-0 border-4 border-brand-500/30 rounded-full animate-ping"></div>
                                    <div className="absolute inset-0 border-4 border-brand-500 rounded-full"></div>
