    const [isOnline, setIsOnline] = useState(false);
    const [incomingRequest, setIncomingRequest] = useState<boolean>(false);
    const { startRide } = useAppStore();

    // Simulate incoming request loop when online
    React.useEffect(() => {
        let timer: any;
        if (isOnline) {
            timer = setTimeout(() => {
                setIncomingRequest(true);
            }, 3000);
        } else {
            setIncomingRequest(false);
        }
        return () => clearTimeout(timer);
    }, [isOnline]);

    const handleAccept = () => {
        setIncomingRequest(false);
        startRide({
            id: 'ride_d1',
            pickup: '242 Main St',
            destination: 'Airport Terminal 1',
            fare: 45.00,
            status: 'assigned',
            riderId: 'r1',
            vehicleType: 'plus',
            timestamp: Date.now()
        });
    };

    return (
        <div className="relative h-full w-full flex flex-col">
            <MapBackground />

            {/* Top Stats Bar */}
            <div className="absolute top-0 left-0 right-0 p-4 z-10 flex justify-center">
                <div className="bg-dark-950/90 backdrop-blur-md rounded-full px-6 py-2 border border-white/10 shadow-xl flex items-center gap-8">
                    <div className="text-center">
