                        <div className="text-xl font-bold text-white">$124.50</div>
                    </div>
                    <div className="w-px h-8 bg-white/10"></div>
                    <div className="text-center">
                        <div className="text-[10px] text-slate-400 uppercase tracking-wider font-semibold">Rides</div>
                        <div className="text-xl font-bold text-brand-400">8</div>
                    </div>
                     <div className="w-px h-8 bg-white/10"></div>
