                    <div className="w-16 h-16 bg-gradient-to-tr from-brand-500 to-blue-600 rounded-2xl mx-auto flex items-center justify-center mb-4 shadow-lg shadow-brand-500/20">
                        <span className="text-3xl font-bold text-white">iT</span>
                    </div>
                    <h1 className="text-2xl font-bold text-white mb-2">Welcome to iTaxi</h1>
                    <p className="text-slate-400 text-sm">The premium ride-hailing experience.</p>
                </div>

                {step === 'phone' ? (
                    <form onSubmit={handleSendOtp} className="space-y-6 animate-in fade-in slide-in-from-right-8 duration-300">
                        <div className="space-y-2">
                            <label className="text-xs font-semibold text-slate-400 uppercase tracking-wider ml-1">Mobile Number</label>
                            <div className="relative">
                                <Smartphone className="absolute left-4 top-3.5 text-slate-500" size={18} />
                                <input 
                                    type="tel"
                                    placeholder="+1 (555) 000-0000"
                                    className="w-full bg-dark-950/50 border border-white/10 rounded-xl py-3 pl-11 pr-4 text-white placeholder:text-slate-600 focus:outline-none focus:border-brand-500 focus:ring-1 focus:ring-brand-500 transition-all"
                                    value={phone}
                                    onChange={(e) => setPhone(e.target.value)}
                                    required
                                />
                            </div>
                        </div>
                        <Button type="submit" size="lg" isLoading={loading} className="w-full">
                            Continue <ArrowRight size={18} />
                        </Button>
                    </form>
                ) : (
                    <form onSubmit={handleVerifyOtp} className="space-y-6 animate-in fade-in slide-in-from-right-8 duration-300">
                         <div className="text-center">
                            <div className="text-sm text-slate-300 mb-6">
                                Enter the 4-digit code sent to <br/><span className="text-brand-400 font-medium">{phone}</span>
                            </div>
                            <div className="flex justify-center gap-3 mb-6">
                                {otp.map((digit, idx) => (
                                    <input
                                        key={idx}
                                        id={`otp-${idx}`}
                                        type="text"
                                        inputMode="numeric"
                                        maxLength={1}
                                        className="w-14 h-16 bg-dark-950/50 border border-white/10 rounded-xl text-center text-2xl font-bold text-white focus:outline-none focus:border-brand-500 focus:ring-1 focus:ring-brand-500 transition-all"
                                        value={digit}
                                        onChange={(e) => handleOtpChange(idx, e.target.value)}
                                    />
                                ))}
                            </div>
                         </div>
                        <Button type="submit" size="lg" isLoading={loading} className="w-full">
                            Verify & Login <KeyRound size={18} />
                        </Button>
                        <button 
                            type="button" 
                            onClick={() => setStep('phone')}
                            className="w-full text-xs text-slate-500 hover:text-white transition-colors"
                        >
                            Change Phone Number
                        </button>
                    </form>
                )}

                <div className="mt-8 text-center">
                    <p className="text-[10px] text-slate-600">
                        By continuing, you agree to our Terms of Service and Privacy Policy.
                    </p>
                </div>
            </Card>
        </div>
    );
};

