};

import React, { useState, useRef, useEffect } from 'react';
import { Send, X, Phone, User } from 'lucide-react';
import { Button } from '../ui/Button';

interface Message {
    id: string;
    text: string;
    sender: 'me' | 'other';
    time: string;
}

interface ChatSheetProps {
    isOpen: boolean;
    onClose: () => void;
    recipientName: string;
    recipientRole: string;
}

export const ChatSheet: React.FC<ChatSheetProps> = ({ isOpen, onClose, recipientName, recipientRole }) => {
    const [messages, setMessages] = useState<Message[]>([
        { id: '1', text: 'Hi! I am on my way.', sender: 'other', time: '12:30 PM' },
    ]);
    const [input, setInput] = useState('');
    const messagesEndRef = useRef<HTMLDivElement>(null);

    const scrollToBottom = () => {
        messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
    };

    useEffect(() => {
        if (isOpen) scrollToBottom();
    }, [messages, isOpen]);

    const handleSend = (e: React.FormEvent) => {
        e.preventDefault();
        if (!input.trim()) return;
        setMessages([...messages, { 
            id: Date.now().toString(), 
            text: input, 
            sender: 'me', 
            time: new Date().toLocaleTimeString([], { hour: '2-digit', minute:'2-digit' }) 
        }]);
        setInput('');

        // Simulate reply
        setTimeout(() => {
            setMessages(prev => [...prev, {
                id: Date.now().toString() + 'r',
                text: "Sounds good, see you soon!",
                sender: 'other',
                time: new Date().toLocaleTimeString([], { hour: '2-digit', minute:'2-digit' })
            }]);
        }, 2000);
    };

    if (!isOpen) return null;

    return (
        <div className="fixed inset-0 z-50 flex items-end md:items-center justify-center pointer-events-none">
            {/* Backdrop */}
            <div className="absolute inset-0 bg-black/60 backdrop-blur-sm pointer-events-auto" onClick={onClose} />

            {/* Chat Window */}
            <div className="pointer-events-auto w-full md:w-[400px] h-[80vh] md:h-[600px] bg-slate-900 md:rounded-2xl rounded-t-2xl shadow-2xl border border-white/10 flex flex-col animate-in slide-in-from-bottom-10 duration-300">
                {/* Header */}
                <div className="p-4 border-b border-white/5 flex items-center justify-between bg-white/5 md:rounded-t-2xl">
                    <div className="flex items-center gap-3">
                        <div className="w-10 h-10 rounded-full bg-slate-700 flex items-center justify-center border border-white/10">
                            <User size={20} className="text-slate-400" />
                        </div>
                        <div>
                            <div className="font-bold text-white text-sm">{recipientName}</div>
                            <div className="text-xs text-brand-400">{recipientRole}</div>
                        </div>
                    </div>
                    <div className="flex gap-2">
                        <button className="p-2 rounded-full hover:bg-white/10 text-brand-400 transition-colors">
                            <Phone size={18} />
                        </button>
                        <button onClick={onClose} className="p-2 rounded-full hover:bg-white/10 text-slate-400 transition-colors">
                            <X size={18} />
                        </button>
                    </div>
                </div>

                {/* Messages Area */}
                <div className="flex-1 overflow-y-auto p-4 space-y-4 bg-slate-950/50">
                    <div className="text-center text-xs text-slate-500 my-4">Today</div>
                    {messages.map((msg) => (
                        <div key={msg.id} className={`flex ${msg.sender === 'me' ? 'justify-end' : 'justify-start'}`}>
                            <div className={`max-w-[80%] rounded-2xl px-4 py-3 text-sm ${
                                msg.sender === 'me' 
                                ? 'bg-brand-600 text-white rounded-br-none' 
                                : 'bg-slate-800 text-slate-200 rounded-bl-none'
                            }`}>
                                {msg.text}
                                <div className={`text-[10px] mt-1 opacity-70 ${msg.sender === 'me' ? 'text-brand-100' : 'text-slate-400'}`}>
                                    {msg.time}
                                </div>
                            </div>
                        </div>
                    ))}
                    <div ref={messagesEndRef} />
                </div>

                {/* Input Area */}
                <form onSubmit={handleSend} className="p-4 border-t border-white/5 bg-slate-900 flex gap-2">
                    <input 
                        type="text" 
                        value={input}
                        onChange={(e) => setInput(e.target.value)}
                        placeholder="Type a message..."
                        className="flex-1 bg-slate-950 border border-white/10 rounded-xl px-4 py-3 text-sm text-white focus:outline-none focus:border-brand-500 transition-colors"
                    />
                    <Button type="submit" size="sm" className="w-12 h-12 !px-0 rounded-xl flex items-center justify-center">
                        <Send size={18} />
                    </Button>
                </form>
            </div>
        </div>
    );
};

