import React, { useEffect } from 'react';
import { Layout } from './components/Layout/Layout';
import { RiderHome } from './pages/Rider/RiderHome';
import { DriverHome } from './pages/Driver/DriverHome';
import { AdminDashboard } from './pages/Admin/AdminDashboard';
import { WalletPage } from './pages/Shared/WalletPage';
import { SettingsPage } from './pages/Shared/SettingsPage';
import { ActivityPage } from './pages/Shared/ActivityPage';
import { SupportPage } from './pages/Shared/SupportPage';
import { NotificationsPage } from './pages/Shared/NotificationsPage';
import { LandingPage } from './pages/Landing/LandingPage';
import { LoginPage } from './pages/Auth/LoginPage';
import { ToastContainer } from './components/ui/ToastContainer';
import { RatingModal } from './components/Ride/RatingModal';
import { useAppStore } from './store';
import { socketService } from './services/mockSocket';

const App: React.FC = () => {
    const { user, currentRole, currentView, appMode, isDarkMode } = useAppStore();

    // Sync Dark Mode Class
    useEffect(() => {
        if (isDarkMode) {
            document.documentElement.classList.add('dark');
        } else {
            document.documentElement.classList.remove('dark');
        }
    }, [isDarkMode]);

    useEffect(() => {
        socketService.connect();
        return () => {
            socketService.disconnect();
        };
    }, []);

    // 1. Landing Page Mode
    if (appMode === 'landing') {
        return <LandingPage />;
    }

    // 2. Auth Mode
    if (appMode === 'auth' && !user) {
        return <LoginPage />;
    }

    // 3. Authenticated App Portal
    const renderContent = () => {
        // --- Admin Role Special Routing ---
        if (currentRole === 'admin') {
            if (currentView === 'settings') return <SettingsPage />;
            return <AdminDashboard />;
        }

        // --- Shared Views ---
        if (currentView === 'wallet' || currentView === 'earnings') return <WalletPage />;
        if (currentView === 'profile' || currentView === 'settings') return <SettingsPage />;
        if (currentView === 'activity' || currentView === 'drivers') return <ActivityPage />;
        if (currentView === 'support') return <SupportPage />;
        if (currentView === 'notifications') return <NotificationsPage />;

        // --- Role Specific Home ---
        switch (currentRole) {
            case 'driver':
                return <DriverHome />;
            case 'rider':
            default:
                return <RiderHome />;
        }
    };

    return (
        <>
            <ToastContainer />
            <RatingModal />
            <Layout>
                {renderContent()}
            </Layout>
        </>
    );
};

export default App;

import React from 'react';

interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
    variant?: 'primary' | 'secondary' | 'glass' | 'danger' | 'ghost';
    size?: 'sm' | 'md' | 'lg';
    isLoading?: boolean;
    icon?: React.ReactNode;
}

export const Button: React.FC<ButtonProps> = ({ 
    children, 
    variant = 'primary', 
    size = 'md', 
    isLoading, 
    icon,
    className = '',
    ...props 
}) => {
    const baseStyles = "relative overflow-hidden rounded-xl font-semibold transition-all duration-200 flex items-center justify-center gap-2 active:scale-[0.98] disabled:opacity-50 disabled:cursor-not-allowed";

    const variants = {
        primary: "bg-brand-600 hover:bg-brand-500 text-white shadow-lg shadow-brand-500/20 border border-transparent",
        secondary: "bg-white dark:bg-dark-800 text-slate-700 dark:text-slate-200 border border-slate-200 dark:border-slate-700 hover:bg-slate-50 dark:hover:bg-dark-700",
        glass: "glass-button text-brand-600 dark:text-brand-400 hover:text-brand-500 dark:hover:text-brand-300 hover:bg-brand-50 dark:hover:bg-brand-500/10",
        danger: "bg-red-50 dark:bg-red-500/10 text-red-600 dark:text-red-400 border border-red-200 dark:border-red-500/20 hover:bg-red-100 dark:hover:bg-red-500/20",
        ghost: "bg-transparent hover:bg-slate-100 dark:hover:bg-white/5 text-slate-500 dark:text-slate-400 hover:text-slate-900 dark:hover:text-white"
    };

    const sizes = {
        sm: "px-3 py-1.5 text-xs",
        md: "px-5 py-2.5 text-sm",
        lg: "px-6 py-3.5 text-base w-full"
    };

    return (
        <button 
            className={`${baseStyles} ${variants[variant]} ${sizes[size]} ${className}`}
            disabled={isLoading || props.disabled}
            {...props}
        >
            {isLoading ? (
                <div className="w-4 h-4 border-2 border-current border-t-transparent rounded-full animate-spin opacity-80" />
            ) : (
                <>
                    {icon && <span className="opacity-90">{icon}</span>}
                    {children}
                </>
            )}
        </button>
    );
};

