import { create } from 'zustand';
import { User, Ride, UserRole } from './types';

export type AppMode = 'landing' | 'auth' | 'app';
export type AppView = 'home' | 'activity' | 'wallet' | 'support' | 'profile' | 'settings' | 'earnings' | 'drivers' | 'analytics' | 'notifications' | 'finance';
export type Language = 'en' | 'fa';

export interface Toast {
    id: string;
    type: 'success' | 'error' | 'info' | 'warning';
    message: string;
}

interface AppState {
    appMode: AppMode;
    user: User | null;
    currentRole: UserRole;
    activeRide: Ride | null;
    isDarkMode: boolean;
    language: Language; // Added language state
    notifications: any[];
    toasts: Toast[];
    currentView: AppView;

    // Actions
    setAppMode: (mode: AppMode) => void;
    setUser: (user: User | null) => void;
    setRole: (role: UserRole) => void;
    setView: (view: AppView) => void;
    startRide: (ride: Ride) => void;
    updateRideStatus: (status: Ride['status']) => void;
    toggleDarkMode: () => void;
    setLanguage: (lang: Language) => void; // Added setLanguage action
    logout: () => void;

    // Toast Actions
    addToast: (type: Toast['type'], message: string) => void;
    removeToast: (id: string) => void;
}

export const useAppStore = create<AppState>((set, get) => ({
    appMode: 'landing',
    user: null, 
    currentRole: 'rider',
    activeRide: null,
    isDarkMode: true,
    language: 'en', // Default language
    notifications: [],
    toasts: [],
    currentView: 'home',

    setAppMode: (mode) => set({ appMode: mode }),
    setUser: (user) => set({ user, appMode: 'app' }),
    setRole: (role) => set({ currentRole: role, currentView: 'home' }), 
    setView: (view) => set({ currentView: view }),
    startRide: (ride) => set({ activeRide: ride }),
    updateRideStatus: (status) => set((state) => ({
        activeRide: state.activeRide ? { ...state.activeRide, status } : null
    })),
    toggleDarkMode: () => set((state) => ({ isDarkMode: !state.isDarkMode })),
    setLanguage: (lang) => set({ language: lang }),
    logout: () => set({ user: null, activeRide: null, appMode: 'landing', currentView: 'home' }),

    addToast: (type, message) => {
        const id = Math.random().toString(36).substring(7);
        set((state) => ({ toasts: [...state.toasts, { id, type, message }] }));
        setTimeout(() => get().removeToast(id), 4000);
    },
    removeToast: (id) => set((state) => ({ toasts: state.toasts.filter(t => t.id !== id) }))
}));

import React, { useEffect } from 'react';
import { Layout } from './components/Layout/Layout';
import { RiderHome } from './pages/Rider/RiderHome';
import { DriverHome } from './pages/Driver/DriverHome';
import { AdminDashboard } from './pages/Admin/AdminDashboard';
import { WalletPage } from './pages/Shared/WalletPage';
import { SettingsPage } from './pages/Shared/SettingsPage';
import { ActivityPage } from './pages/Shared/ActivityPage';
import { SupportPage } from './pages/Shared/SupportPage';
import { NotificationsPage } from './pages/Shared/NotificationsPage';
import { LandingPage } from './pages/Landing/LandingPage';
import { LoginPage } from './pages/Auth/LoginPage';
import { ToastContainer } from './components/ui/ToastContainer';
import { RatingModal } from './components/Ride/RatingModal';
import { useAppStore } from './store';
import { socketService } from './services/mockSocket';

const App: React.FC = () => {
    // Select specific state slices to avoid re-rendering App on every store change (e.g. toasts)
    const user = useAppStore((state) => state.user);
    const currentRole = useAppStore((state) => state.currentRole);
    const currentView = useAppStore((state) => state.currentView);
    const appMode = useAppStore((state) => state.appMode);
    const isDarkMode = useAppStore((state) => state.isDarkMode);
    const language = useAppStore((state) => state.language);

    // Sync Dark Mode Class
    useEffect(() => {
        if (isDarkMode) {
            document.documentElement.classList.add('dark');
        } else {
            document.documentElement.classList.remove('dark');
        }
    }, [isDarkMode]);

    // Sync Language & Direction
    useEffect(() => {
        if (language === 'fa') {
            document.documentElement.dir = 'rtl';
            document.documentElement.lang = 'fa';
            document.body.classList.add('font-fa');
            document.body.classList.remove('font-sans');
        } else {
            document.documentElement.dir = 'ltr';
            document.documentElement.lang = 'en';
            document.body.classList.add('font-sans');
            document.body.classList.remove('font-fa');
        }
    }, [language]);

    useEffect(() => {
        socketService.connect();
        return () => {
            socketService.disconnect();
        };
    }, []);

    // 1. Landing Page Mode
    if (appMode === 'landing') {
        return <LandingPage />;
    }

    // 2. Auth Mode
    if (appMode === 'auth' && !user) {
        return <LoginPage />;
    }

    // 3. Authenticated App Portal
    const renderContent = () => {
        // --- Admin Role Special Routing ---
        if (currentRole === 'admin') {
            if (currentView === 'settings') return <SettingsPage />;
            return <AdminDashboard />;
        }

        // --- Shared Views ---
        if (currentView === 'wallet' || currentView === 'earnings') return <WalletPage />;
        if (currentView === 'profile' || currentView === 'settings') return <SettingsPage />;
        if (currentView === 'activity' || currentView === 'drivers') return <ActivityPage />;
        if (currentView === 'support') return <SupportPage />;
        if (currentView === 'notifications') return <NotificationsPage />;

        // --- Role Specific Home ---
        switch (currentRole) {
            case 'driver':
                return <DriverHome />;
            case 'rider':
            default:
                return <RiderHome />;
        }
    };

    return (
        <>
            <ToastContainer />
            <RatingModal />
            <Layout>
                {renderContent()}
            </Layout>
        </>
    );
};

export default App;

