import React from 'react';

interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
    variant?: 'primary' | 'secondary' | 'glass' | 'danger' | 'ghost';
    size?: 'sm' | 'md' | 'lg';
    isLoading?: boolean;
    icon?: React.ReactNode;
}

export const Button: React.FC<ButtonProps> = ({ 
    children, 
    variant = 'primary', 
    size = 'md', 
    isLoading, 
    icon,
    className = '',
    ...props 
}) => {
    const baseStyles = "relative overflow-hidden rounded-xl font-bold transition-all duration-200 flex items-center justify-center gap-2 active:scale-[0.98] disabled:opacity-50 disabled:cursor-not-allowed focus:outline-none focus:ring-2 focus:ring-offset-2 dark:focus:ring-offset-dark-900";

    const variants = {
        primary: "bg-brand-600 hover:bg-brand-500 text-white shadow-lg shadow-brand-500/20 border border-transparent focus:ring-brand-500",
        secondary: "bg-white dark:bg-dark-800 text-dark-900 dark:text-dark-100 border border-dark-200 dark:border-dark-700 hover:bg-dark-50 dark:hover:bg-dark-700 shadow-sm focus:ring-dark-500",
        glass: "glass-button text-brand-700 dark:text-brand-400 hover:bg-brand-50 dark:hover:bg-brand-500/10 focus:ring-brand-500",
        danger: "bg-red-50 dark:bg-red-500/10 text-red-600 dark:text-red-400 border border-red-200 dark:border-red-500/20 hover:bg-red-100 dark:hover:bg-red-500/20 focus:ring-red-500",
        ghost: "bg-transparent hover:bg-dark-100 dark:hover:bg-white/5 text-dark-500 dark:text-dark-400 hover:text-dark-900 dark:hover:text-white focus:ring-dark-500"
    };

    const sizes = {
        sm: "px-3 py-1.5 text-xs",
        md: "px-5 py-2.5 text-sm",
        lg: "px-6 py-4 text-base w-full"
    };

    return (
        <button 
            className={`${baseStyles} ${variants[variant]} ${sizes[size]} ${className}`}
            disabled={isLoading || props.disabled}
            {...props}
        >
            {isLoading ? (
                <div className="w-4 h-4 border-2 border-current border-t-transparent rounded-full animate-spin opacity-80" />
            ) : (
                <>
                    {icon && <span className="opacity-90">{icon}</span>}
                    {children}
                </>
            )}
        </button>
    );
};

