import { MapPin, Navigation, Clock, CreditCard, Star, Search, ShieldAlert, MessageCircle, Plus, Moon, Sun, User } from 'lucide-react';
import { useAppStore } from '../../store';
import { VehicleOption, Ride } from '../../types';

const VEHICLES: VehicleOption[] = [
    { id: 'eco', name: 'iTaxi Eco', multiplier: 1, eta: 4, image: 'https://picsum.photos/seed/car1/100/60' },
    { id: 'plus', name: 'iTaxi Plus', multiplier: 1.4, eta: 8, image: 'https://picsum.photos/seed/car2/100/60' },
    { id: 'lux', name: 'iTaxi Lux', multiplier: 2.2, eta: 12, image: 'https://picsum.photos/seed/car3/100/60' },
];

export const RiderHome: React.FC = () => {
    const { activeRide, startRide, updateRideStatus, addToast, isDarkMode, toggleDarkMode, setView, user } = useAppStore();
    const [step, setStep] = useState<'idle' | 'selecting' | 'confirming'>('idle');
    const [destination, setDestination] = useState('');
    const [selectedVehicle, setSelectedVehicle] = useState<VehicleOption['id']>('eco');
    const [isChatOpen, setIsChatOpen] = useState(false);

    const handleRequest = () => {
        const newRide: Ride = {
            id: 'ride_' + Date.now(),
            pickup: 'Current Location',
            destination: destination,
            fare: 24.50,
            status: 'searching',
            riderId: 'u1',
            vehicleType: selectedVehicle,
            timestamp: Date.now()
        };
        startRide(newRide);
        setStep('idle');
        addToast('info', 'Searching for nearby drivers...');

        setTimeout(() => {
            updateRideStatus('assigned');
            addToast('success', 'Driver found! Michael is on the way.');
        }, 3000);
        setTimeout(() => updateRideStatus('completed'), 10000); 
    };

    const handleCancel = () => {
        updateRideStatus('cancelled');
        addToast('error', 'Ride request cancelled.');
    };

    // --- Mobile Header Component for Quick Access ---
    const MobileHeader = () => (
        <div className="absolute top-4 left-4 right-4 z-30 flex justify-between items-center md:hidden pointer-events-none">
            <button 
                onClick={() => setView('profile')}
                className="pointer-events-auto w-10 h-10 rounded-full bg-white dark:bg-dark-800 shadow-lg border border-dark-100 dark:border-white/10 flex items-center justify-center overflow-hidden"
            >
                 <img src={`https://ui-avatars.com/api/?name=${user?.name || 'User'}&background=2563eb&color=fff`} alt="User" className="w-full h-full object-cover" />
            </button>
            <button 
                onClick={toggleDarkMode}
                className="pointer-events-auto w-10 h-10 rounded-full bg-white/90 dark:bg-dark-800/90 backdrop-blur shadow-lg border border-dark-100 dark:border-white/10 flex items-center justify-center text-dark-600 dark:text-dark-300"
            >
                {isDarkMode ? <Sun size={20} /> : <Moon size={20} />}
            </button>
        </div>
    );

    if (activeRide && activeRide.status === 'completed') {
        return <div className="relative h-full w-full"><MapBackground /><MobileHeader/></div>;
    }

    if (activeRide) {
        return (
            <div className="relative h-full w-full">
                <MapBackground />
                <MobileHeader />
                <ChatSheet 
                    isOpen={isChatOpen} 
                    onClose={() => setIsChatOpen(false)} 
                    recipientName="Michael K." 
                    recipientRole="Driver • Toyota Camry"
                />

                <div className="absolute bottom-20 md:bottom-auto md:top-4 md:left-4 left-4 right-4 md:w-96 z-20">
                    <Card className="shadow-2xl shadow-brand-900/10 dark:shadow-black/50 border-dark-200 dark:border-brand-500/20 backdrop-blur-2xl bg-white/95 dark:bg-dark-900/90">
                        <div className="flex items-center justify-between mb-4 border-b border-dark-100 dark:border-white/5 pb-4">
                            <div>
                                <h3 className="font-bold text-dark-900 dark:text-white text-lg">
                                    {activeRide.status === 'searching' && "Finding driver..."}
                                    {activeRide.status === 'assigned' && "Driver on the way"}
                                    {activeRide.status === 'in_progress' && "Heading to dropoff"}
                                </h3>
                                <p className="text-xs text-brand-600 dark:text-brand-400 font-bold uppercase tracking-wider mt-1">{activeRide.status.replace('_', ' ')}</p>
                            </div>
                            {activeRide.status !== 'searching' && (
                                <div className="text-right">
                                    <div className="text-xl font-bold text-dark-900 dark:text-white">4 min</div>
                                    <div className="text-xs text-dark-500 dark:text-dark-400">ETA</div>
                                </div>
                            )}
                        </div>

                        {activeRide.status === 'searching' ? (
                             <div className="flex flex-col items-center py-8">
                                <div className="relative w-20 h-20 mb-6">
                                    <div className="absolute inset-0 border-4 border-brand-500/30 rounded-full animate-ping"></div>
                                    <div className="absolute inset-0 border-4 border-brand-500 rounded-full animate-spin border-t-transparent"></div>
                                    <div className="absolute inset-0 flex items-center justify-center">
                                        <Search className="text-brand-500" size={24} />
                                    </div>
                                </div>
                                <Button variant="ghost" onClick={handleCancel} className="text-red-500 hover:text-red-600 dark:text-red-400 dark:hover:text-red-300 bg-red-50 dark:bg-red-500/10">Cancel Request</Button>
                             </div>
                        ) : (
                            <div className="space-y-4">
                                <div className="flex items-center gap-4 bg-dark-50 dark:bg-white/5 p-4 rounded-xl border border-dark-100 dark:border-white/5">
                                    <div className="w-14 h-14 rounded-full bg-dark-200 dark:bg-dark-700 overflow-hidden border-2 border-brand-500 shadow-lg relative">
                                        <img src="https://picsum.photos/seed/driver/100/100" alt="Driver" className="w-full h-full object-cover" />
                                        <div className="absolute bottom-0 right-0 w-4 h-4 bg-green-500 border-2 border-white dark:border-dark-900 rounded-full"></div>
                                    </div>
                                    <div className="flex-1">
                                        <div className="font-bold text-dark-900 dark:text-white text-lg">Michael K.</div>
                                        <div className="text-xs text-dark-500 dark:text-dark-400 flex items-center gap-1 mt-1">
                                            <Star size={10} className="text-yellow-400 fill-yellow-400" /> 4.9 • Toyota Camry • ABC-1234
                                        </div>
                                    </div>
                                </div>

                                <div className="grid grid-cols-4 gap-2">
                                    <button 
                                        onClick={() => setIsChatOpen(true)}
                                        className="flex flex-col items-center justify-center p-2 rounded-xl bg-dark-50 dark:bg-white/5 hover:bg-dark-100 dark:hover:bg-white/10 text-dark-500 dark:text-dark-300 hover:text-dark-900 dark:hover:text-white transition-colors"
                                    >
                                        <MessageCircle size={20} className="mb-1"/> <span className="text-[10px] font-semibold">Chat</span>
                                    </button>
                                    <button className="flex flex-col items-center justify-center p-2 rounded-xl bg-dark-50 dark:bg-white/5 hover:bg-dark-100 dark:hover:bg-white/10 text-dark-500 dark:text-dark-300 hover:text-dark-900 dark:hover:text-white transition-colors">
                                        <Navigation size={20} className="mb-1"/> <span className="text-[10px] font-semibold">Share</span>
                                    </button>
                                    <button className="flex flex-col items-center justify-center p-2 rounded-xl bg-red-50 dark:bg-red-500/10 hover:bg-red-100 dark:hover:bg-red-500/20 text-red-600 dark:text-red-400 transition-colors col-span-2 border border-red-100 dark:border-red-500/20">
                                        <ShieldAlert size={20} className="mb-1"/> <span className="text-[10px] font-bold">SOS Emergency</span>
                                    </button>
                                </div>
                            </div>
                        )}
                    </Card>
                </div>
            </div>
        );
    }

    return (
        <div className="relative h-full w-full flex flex-col">
            <MapBackground />
            <MobileHeader />

            <div className="absolute top-24 md:top-4 left-4 right-4 z-10 md:w-96 md:left-4">
                {step === 'idle' && (
                    <Card className="!p-0 overflow-hidden shadow-2xl shadow-dark-900/5 dark:shadow-black/50 backdrop-blur-2xl border-white/50 dark:border-white/10">
                         <div className="p-6 bg-gradient-to-b from-white to-dark-50 dark:from-dark-900/90 dark:to-dark-950/90">
                            <div className="text-[10px] font-bold text-brand-600 dark:text-brand-400 mb-2 uppercase tracking-widest">Good Morning</div>
                            <h2 className="text-2xl font-bold text-dark-900 dark:text-white mb-6 tracking-tight">Where to?</h2>

                            <div 
                                onClick={() => setStep('selecting')}
                                className="w-full bg-white dark:bg-dark-800 text-dark-400 dark:text-dark-400 px-4 py-4 rounded-xl border border-dark-200 dark:border-white/10 flex items-center gap-3 cursor-pointer hover:border-brand-500/50 dark:hover:border-brand-500/50 transition-all shadow-sm hover:shadow-md"
                            >
                                <Search size={20} />
                                <span className="font-medium">Search destination</span>
                            </div>
                         </div>
                         <div className="bg-dark-50 dark:bg-dark-950/95 p-2 flex divide-x divide-dark-200 dark:divide-white/5">
                            <button className="flex-1 py-3 flex flex-col items-center gap-1.5 hover:bg-white dark:hover:bg-white/5 rounded-lg transition-colors group">
                                <div className="bg-brand-100 dark:bg-brand-500/10 p-2 rounded-full text-brand-600 dark:text-brand-400 group-hover:bg-brand-600 group-hover:text-white transition-all"><Clock size={18} /></div>
                                <span className="text-xs text-dark-500 dark:text-dark-400 font-bold group-hover:text-dark-900 dark:group-hover:text-white">Recent</span>
                            </button>
                             <button className="flex-1 py-3 flex flex-col items-center gap-1.5 hover:bg-white dark:hover:bg-white/5 rounded-lg transition-colors group">
                                <div className="bg-purple-100 dark:bg-purple-500/10 p-2 rounded-full text-purple-600 dark:text-purple-400 group-hover:bg-purple-600 group-hover:text-white transition-all"><MapPin size={18} /></div>
                                <span className="text-xs text-dark-500 dark:text-dark-400 font-bold group-hover:text-dark-900 dark:group-hover:text-white">Saved</span>
                            </button>
                         </div>
                    </Card>
                )}

                {step === 'selecting' && (
                    <Card className="flex flex-col h-[75vh] md:h-auto animate-in fade-in slide-in-from-bottom-8 duration-300 shadow-2xl dark:shadow-black/60 border-white/60 dark:border-white/10 bg-white/95 dark:bg-dark-900/95">
                        <div className="flex justify-between items-center mb-4">
                             <h3 className="font-bold text-dark-900 dark:text-white text-lg">Choose a ride</h3>
                             <button onClick={() => setStep('idle')} className="text-dark-400 hover:text-dark-900 dark:hover:text-white p-2 rounded-full hover:bg-dark-100 dark:hover:bg-white/10 transition-colors">✕</button>
                        </div>

                        <div className="relative mb-6">
                            <div className="absolute left-3 top-3 bottom-3 w-0.5 bg-gradient-to-b from-dark-300 dark:from-dark-600 to-brand-500"></div>
                            <div className="space-y-4">
                                <div className="flex items-center gap-3 pl-8 relative">
                                    <div className="absolute left-1.5 w-3 h-3 rounded-full bg-dark-400 dark:bg-dark-500 border-2 border-white dark:border-dark-900"></div>
                                    <input type="text" value="Current Location" readOnly className="w-full bg-transparent text-dark-400 dark:text-dark-400 text-sm font-medium border-b border-dark-100 dark:border-white/10 pb-2 focus:outline-none" />
                                </div>
                                <div className="flex items-center gap-3 pl-8 relative">
                                    <div className="absolute left-1.5 w-3 h-3 rounded-full bg-brand-600 border-2 border-white dark:border-dark-900 shadow-lg shadow-brand-500/50"></div>
                                    <input 
                                        type="text" 
                                        placeholder="Enter destination" 
                                        autoFocus
                                        className="w-full bg-transparent text-dark-900 dark:text-white text-lg font-bold border-b border-brand-500 pb-2 focus:outline-none placeholder:text-dark-300 dark:placeholder:text-dark-600"
                                        value={destination} 
                                        onChange={(e) => setDestination(e.target.value)}
                                    />
                                </div>
                            </div>
                            <button className="absolute right-0 top-1/2 -translate-y-1/2 text-brand-600 dark:text-brand-400 text-xs flex items-center gap-1 bg-brand-50 dark:bg-brand-500/10 px-2.5 py-1.5 rounded-full hover:bg-brand-600 hover:text-white transition-colors font-bold">
                                <Plus size={12} /> Add Stop
                            </button>
                        </div>

                        <div className="flex-1 overflow-y-auto space-y-3 hide-scrollbar mb-4 -mx-2 px-2">
                            {VEHICLES.map((v) => (
                                <div 
                                    key={v.id}
                                    onClick={() => setSelectedVehicle(v.id)}
                                    className={`flex items-center p-3 rounded-xl border cursor-pointer transition-all group ${
                                        selectedVehicle === v.id 
                                        ? 'bg-brand-50 dark:bg-brand-600/10 border-brand-500 ring-1 ring-brand-500 shadow-sm' 
                                        : 'bg-white dark:bg-white/5 border-transparent hover:bg-dark-50 dark:hover:bg-white/10'
                                    }`}
                                >
                                    <div className="w-20 h-12 bg-dark-100 dark:bg-dark-800 rounded-lg mr-4 relative overflow-hidden group-hover:scale-105 transition-transform">
                                        <img src={v.image} alt={v.name} className="object-cover w-full h-full mix-blend-overlay dark:opacity-80 opacity-100" />
                                    </div>
                                    <div className="flex-1">
                                        <div className="font-bold text-dark-900 dark:text-white flex items-center gap-2">
                                            {v.name}
                                            {v.id === 'lux' && <span className="text-[9px] bg-gradient-to-r from-yellow-400 to-orange-500 text-black px-1.5 py-0.5 rounded font-black tracking-wider">PRO</span>}
                                        </div>
                                        <div className="text-xs text-dark-500 dark:text-dark-400 mt-1 font-medium">{v.eta} min • 4 seats</div>
                                    </div>
                                    <div className="text-right">
                                        <div className="font-bold text-dark-900 dark:text-white text-lg">${(24.50 * v.multiplier).toFixed(2)}</div>
                                    </div>
                                </div>
                            ))}
                        </div>

                        <div className="mt-auto pt-4 border-t border-dark-100 dark:border-white/10">
                            <div className="flex items-center justify-between text-xs text-dark-500 dark:text-dark-400 mb-4 bg-dark-50 dark:bg-white/5 p-3 rounded-xl">
                                <div className="flex items-center gap-2 font-medium"><CreditCard size={14} className="text-dark-900 dark:text-white"/> Personal • 4242</div>
                                <div className="text-brand-600 dark:text-brand-400 font-bold cursor-pointer hover:underline">Change</div>
                            </div>
                            <Button size="lg" onClick={handleRequest} className="w-full text-lg h-14 shadow-xl shadow-brand-500/20">
                                Confirm {VEHICLES.find(v => v.id === selectedVehicle)?.name}
                            </Button>
                        </div>
                    </Card>
                )}
            </div>
        </div>
    );
};

