export type AppMode = 'landing' | 'auth' | 'app';
export type AppView = 'home' | 'activity' | 'wallet' | 'support' | 'profile' | 'settings' | 'earnings' | 'drivers' | 'analytics' | 'notifications' | 'finance';
export type Language = 'en' | 'fa';

export interface Location {
    lat: number;
    lng: number;
    bearing?: number; // 0-360 degrees
}

export interface DriverMarker {
    id: string;
    location: Location;
    status: 'available' | 'busy';
    type: 'eco' | 'plus' | 'lux';
}

export interface Toast {
    id: string;
    type: 'success' | 'error' | 'info' | 'warning';
    message: string;
}

interface AppState {
    appMode: AppMode;
    user: User | null;
    currentRole: UserRole;
    activeRide: Ride | null;
    isDarkMode: boolean;
    language: Language;
    notifications: any[];
    toasts: Toast[];
    currentView: AppView;

    // Map & Location Data
    userLocation: Location;
    drivers: DriverMarker[];

    // Actions
    setAppMode: (mode: AppMode) => void;
    setUser: (user: User | null) => void;
    setRole: (role: UserRole) => void;
    setView: (view: AppView) => void;
    startRide: (ride: Ride) => void;
    updateRideStatus: (status: Ride['status']) => void;
    toggleDarkMode: () => void;
    setLanguage: (lang: Language) => void;
    logout: () => void;

    // Map Actions
    updateUserLocation: (loc: Location) => void;
    updateDrivers: (drivers: DriverMarker[]) => void;

    // Toast Actions
    addToast: (type: Toast['type'], message: string) => void;
    removeToast: (id: string) => void;
}

// Default Center: New York City (Manhattan)
const DEFAULT_LOCATION = { lat: 40.758896, lng: -73.985130 };

// Initial Simulated Drivers around NYC
const INITIAL_DRIVERS: DriverMarker[] = [
    { id: 'd1', location: { lat: 40.7595, lng: -73.9860, bearing: 45 }, status: 'available', type: 'eco' },
    { id: 'd2', location: { lat: 40.7570, lng: -73.9840, bearing: 180 }, status: 'available', type: 'plus' },
    { id: 'd3', location: { lat: 40.7610, lng: -73.9880, bearing: 90 }, status: 'busy', type: 'lux' },
    { id: 'd4', location: { lat: 40.7550, lng: -73.9820, bearing: 270 }, status: 'available', type: 'eco' },
    { id: 'd5', location: { lat: 40.7580, lng: -73.9800, bearing: 0 }, status: 'available', type: 'plus' },
];

export const useAppStore = create<AppState>((set, get) => ({
    appMode: 'landing',
    user: null, 
    currentRole: 'rider',
    activeRide: null,
    isDarkMode: true,
    language: 'en',
    notifications: [],
    toasts: [],
    currentView: 'home',

    userLocation: DEFAULT_LOCATION,
    drivers: INITIAL_DRIVERS,

    setAppMode: (mode) => set({ appMode: mode }),
    setUser: (user) => set({ user, appMode: 'app' }),
    setRole: (role) => set({ currentRole: role, currentView: 'home' }), 
    setView: (view) => set({ currentView: view }),
    startRide: (ride) => set({ activeRide: ride }),
    updateRideStatus: (status) => set((state) => ({
        activeRide: state.activeRide ? { ...state.activeRide, status } : null
    })),
    toggleDarkMode: () => set((state) => ({ isDarkMode: !state.isDarkMode })),
    setLanguage: (lang) => set({ language: lang }),
    logout: () => set({ user: null, activeRide: null, appMode: 'landing', currentView: 'home' }),

    updateUserLocation: (loc) => set({ userLocation: loc }),
    updateDrivers: (drivers) => set({ drivers }),

    addToast: (type, message) => {
        const id = Math.random().toString(36).substring(7);
        set((state) => ({ toasts: [...state.toasts, { id, type, message }] }));
        setTimeout(() => get().removeToast(id), 4000);
    },
    removeToast: (id) => set((state) => ({ toasts: state.toasts.filter(t => t.id !== id) }))
}));

import React, { useEffect } from 'react';
import { MapContainer, TileLayer, Marker, Popup, useMap } from 'react-leaflet';
import L from 'leaflet';
import { useAppStore } from '../../store';

// Helper to update view when props change
const MapUpdater: React.FC<{ center: [number, number]; zoom: number }> = ({ center, zoom }) => {
    const map = useMap();
    useEffect(() => {
        map.flyTo(center, zoom, { duration: 2 });
    }, [center, zoom, map]);
    return null;
};

// Custom Icons
const createIcon = (color: string, type: 'car' | 'pin') => {
    const svg = type === 'car' 
        ? `<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="${color}" stroke="white" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" class="w-8 h-8 drop-shadow-lg"><path d="M19 17h2c.6 0 1-.4 1-1v-3c0-.9-.7-1.7-1.5-1.9C18.7 10.6 16 10 16 10s-1.3-1.4-2.2-2.3c-.5-.4-1.1-.7-1.8-.7H5c-.6 0-1.1.4-1.4.9l-1.4 2.9A3.7 3.7 0 0 0 2 12v4c0 .6.4 1 1 1h2"/><circle cx="7" cy="17" r="2"/><circle cx="17" cy="17" r="2"/><path d="M5 17h12"/></svg>`
        : `<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="${color}" stroke="white" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" class="w-10 h-10 drop-shadow-xl"><path d="M20 10c0 6-8 12-8 12s-8-6-8-12a8 8 0 0 1 16 0Z"/><circle cx="12" cy="10" r="3"/></svg>`;

    return L.divIcon({
        className: 'custom-icon',
        html: svg,
        iconSize: type === 'car' ? [32, 32] : [40, 40],
        iconAnchor: type === 'car' ? [16, 16] : [20, 40], // Centered for car, Bottom-center for pin
    });
};

const CarIcon = createIcon('#3b82f6', 'car'); // Brand Blue
const PickupIcon = createIcon('#22c55e', 'pin'); // Green
const DestIcon = createIcon('#ef4444', 'pin'); // Red
const DriverSelfIcon = createIcon('#f59e0b', 'car'); // Orange/Gold for self

interface RealMapProps {
    drivers?: Array<{ id: string; location: { lat: number; lng: number; bearing?: number }; status: string }>;
    pickup?: { lat: number; lng: number } | null;
    destination?: { lat: number; lng: number } | null;
    center?: { lat: number; lng: number };
    zoom?: number;
    showUserLocation?: boolean;
    isDriverView?: boolean;
}

export const RealMap: React.FC<RealMapProps> = ({ 
    drivers = [], 
    pickup, 
    destination, 
    center, 
    zoom = 15,
    showUserLocation = true,
    isDriverView = false
}) => {
    const { isDarkMode, userLocation } = useAppStore();

    // Determine map center priority: User Center -> Pickup -> User Location -> Default
    const mapCenter: [number, number] = center 
        ? [center.lat, center.lng] 
        : pickup 
            ? [pickup.lat, pickup.lng] 
            : [userLocation.lat, userLocation.lng];

    // CartoDB Tiles (Positron for Light, Dark Matter for Dark)
    const tileUrl = isDarkMode 
        ? 'https://{s}.basemaps.cartocdn.com/dark_all/{z}/{x}/{y}{r}.png' 
        : 'https://{s}.basemaps.cartocdn.com/light_all/{z}/{x}/{y}{r}.png';

    return (
        <div className="w-full h-full absolute inset-0 z-0">
            <MapContainer 
                center={mapCenter} 
                zoom={zoom} 
                scrollWheelZoom={true} 
                zoomControl={false}
                className="w-full h-full outline-none"
            >
                <TileLayer
                    url={tileUrl}
                    attribution='&copy; <a href="https://www.openstreetmap.org/copyright">OSM</a> contributors &copy; <a href="https://carto.com/attributions">CARTO</a>'
                />

                <MapUpdater center={mapCenter} zoom={zoom} />

                {/* Pickup Marker */}
                {pickup && (
                    <Marker position={[pickup.lat, pickup.lng]} icon={PickupIcon}>
                        <Popup>Pickup Location</Popup>
                    </Marker>
                )}

                {/* Destination Marker */}
                {destination && (
                    <Marker position={[destination.lat, destination.lng]} icon={DestIcon}>
                        <Popup>Destination</Popup>
                    </Marker>
                )}

                {/* User Current Location (if separate from pickup) */}
                {showUserLocation && !isDriverView && !pickup && (
                    <Marker position={[userLocation.lat, userLocation.lng]} icon={PickupIcon}>
                        <Popup>You are here</Popup>
                    </Marker>
                )}

                {/* Drivers */}
                {drivers.map(driver => (
                    <Marker 
                        key={driver.id} 
                        position={[driver.location.lat, driver.location.lng]} 
                        icon={isDriverView && driver.id === 'self' ? DriverSelfIcon : CarIcon}
                    >
                        {/* Optional: Add bearing rotation via CSS module if needed, simpler here to just show icon */}
                    </Marker>
                ))}
            </MapContainer>
        </div>
    );
};

