                                            </div>
                                            <div className="text-xs text-dark-500 dark:text-dark-400 mt-1 font-medium">{v.eta} min • 4 seats</div>
                                        </div>
                                        <div className="text-right">
                                            <div className="font-bold text-dark-900 dark:text-white text-lg">${(24.50 * v.multiplier).toFixed(2)}</div>
                                        </div>
                                    </div>
                                ))}
                            </div>

                            <div className="mt-auto pt-4 border-t border-dark-100 dark:border-white/10">
                                <div className="flex items-center justify-between text-xs text-dark-500 dark:text-dark-400 mb-4 bg-dark-50 dark:bg-white/5 p-3 rounded-xl">
                                    <div className="flex items-center gap-2 font-medium"><CreditCard size={14} className="text-dark-900 dark:text-white"/> Personal • 4242</div>
                                    <div className="text-brand-600 dark:text-brand-400 font-bold cursor-pointer hover:underline">Change</div>
                                </div>
                                <Button size="lg" onClick={handleRequest} className="w-full text-lg h-14 shadow-xl shadow-brand-500/20">
                                    Confirm {VEHICLES.find(v => v.id === selectedVehicle)?.name}
                                </Button>
                            </div>
                        </>
                        )}
                    </Card>
                )}
            </div>
        </div>
    );
};

