// Helper to update view when center changes
const MapUpdater: React.FC<{ center: [number, number]; zoom: number; route: RouteData | null }> = ({ center, zoom, route }) => {
    const map = useMap();

    useEffect(() => {
        if (route && route.bbox) {
            // If we have a route, fit bounds to the route
            map.fitBounds([
                [route.bbox[0], route.bbox[1]],
                [route.bbox[2], route.bbox[3]]
            ], { padding: [50, 50] });
        } else {
            // Otherwise just fly to center
            map.flyTo(center, zoom, { duration: 1.5 });
        }
    }, [center, zoom, route, map]);

    return null;
};

// Custom Icons
const createIcon = (color: string, type: 'car' | 'pin') => {
