export type UserRole = 'rider' | 'driver' | 'admin' | null;

export interface Location {
    lat: number;
    lng: number;
    bearing?: number; // 0-360 degrees
}

export interface User {
    id: string;
    name: string;
    email: string;
    avatar?: string;
    role: UserRole;
    rating?: number;
}

export interface Ride {
    id: string;
    pickup: string;
    destination: string;
    fare: number;
    status: 'searching' | 'assigned' | 'arrived' | 'in_progress' | 'completed' | 'cancelled';
    driverId?: string;
    riderId: string;
    vehicleType: 'eco' | 'plus' | 'lux';
    timestamp: number;
    route?: RouteData; // The geometry and details of the trip
}

export interface DriverStats {
    todayEarnings: number;
    weekEarnings: number;
    ridesCompleted: number;
    acceptanceRate: number;
    onlineHours: number;
}

export interface VehicleOption {
    id: 'eco' | 'plus' | 'lux';
    name: string;
    multiplier: number;
    eta: number;
    image: string;
}

export interface Notification {
    id: string;
    title: string;
    message: string;
    type: 'info' | 'success' | 'warning' | 'error';
    read: boolean;
}

// --- New Routing & Admin Types ---

export interface RouteData {
    coordinates: [number, number][]; // Array of [lat, lng]
    distance: number; // meters
    duration: number; // seconds
    bbox?: [number, number, number, number]; // [minLat, minLng, maxLat, maxLng]
}

export type RoutingProviderType = 'ors' | 'mapbox' | 'mock';
export type MapProviderType = 'osm' | 'mapbox' | 'google';

export interface AdminSettings {
    routingProvider: RoutingProviderType;
    mapProvider: MapProviderType;
    apiKeys: {
        ors: string;
        mapbox: string;
        google: string;
    };
    simulation: {
        driverUpdateInterval: number; // ms
        defaultCenter: { lat: number; lng: number };
    };
}

import { create } from 'zustand';
import { persist } from 'zustand/middleware';
import { User, Ride, UserRole, AdminSettings, RouteData, Location } from './types';

export type AppMode = 'landing' | 'auth' | 'app';
export type AppView = 'home' | 'activity' | 'wallet' | 'support' | 'profile' | 'settings' | 'earnings' | 'drivers' | 'analytics' | 'notifications' | 'finance' | 'admin_settings';
export type Language = 'en' | 'fa';

export interface DriverMarker {
    id: string;
    location: Location;
    status: 'available' | 'busy';
    type: 'eco' | 'plus' | 'lux';
}

export interface Toast {
    id: string;
    type: 'success' | 'error' | 'info' | 'warning';
    message: string;
}

interface AppState {
    appMode: AppMode;
    user: User | null;
    currentRole: UserRole;
    activeRide: Ride | null;
    isDarkMode: boolean;
    language: Language;
    notifications: any[];
    toasts: Toast[];
    currentView: AppView;

    // Admin & Config
    adminSettings: AdminSettings;

    // Map & Location Data
    userLocation: Location;
    drivers: DriverMarker[];
    currentRoute: RouteData | null;

    // Actions
    setAppMode: (mode: AppMode) => void;
    setUser: (user: User | null) => void;
    setRole: (role: UserRole) => void;
    setView: (view: AppView) => void;
    startRide: (ride: Ride) => void;
    updateRideStatus: (status: Ride['status']) => void;
    toggleDarkMode: () => void;
    setLanguage: (lang: Language) => void;
    logout: () => void;

    // Map Actions
    updateUserLocation: (loc: Location) => void;
    updateDrivers: (drivers: DriverMarker[]) => void;
    setRoute: (route: RouteData | null) => void;

    // Admin Actions
    updateAdminSettings: (settings: Partial<AdminSettings>) => void;

    // Toast Actions
    addToast: (type: Toast['type'], message: string) => void;
    removeToast: (id: string) => void;
}

// Default Center: New York City (Manhattan)
const DEFAULT_LOCATION = { lat: 40.758896, lng: -73.985130 };

// Initial Simulated Drivers around NYC
const INITIAL_DRIVERS: DriverMarker[] = [
    { id: 'd1', location: { lat: 40.7595, lng: -73.9860, bearing: 45 }, status: 'available', type: 'eco' },
    { id: 'd2', location: { lat: 40.7570, lng: -73.9840, bearing: 180 }, status: 'available', type: 'plus' },
    { id: 'd3', location: { lat: 40.7610, lng: -73.9880, bearing: 90 }, status: 'busy', type: 'lux' },
    { id: 'd4', location: { lat: 40.7550, lng: -73.9820, bearing: 270 }, status: 'available', type: 'eco' },
    { id: 'd5', location: { lat: 40.7580, lng: -73.9800, bearing: 0 }, status: 'available', type: 'plus' },
];

const DEFAULT_ADMIN_SETTINGS: AdminSettings = {
    routingProvider: 'mock', // Default to mock to avoid breaking without keys
    mapProvider: 'osm',
    apiKeys: {
        ors: '',
        mapbox: '',
        google: ''
    },
    simulation: {
        driverUpdateInterval: 2000,
        defaultCenter: DEFAULT_LOCATION
    }
};

export const useAppStore = create<AppState>()(
    persist(
        (set, get) => ({
            appMode: 'landing',
            user: null, 
            currentRole: 'rider',
            activeRide: null,
            isDarkMode: true,
            language: 'en',
            notifications: [],
            toasts: [],
            currentView: 'home',

            adminSettings: DEFAULT_ADMIN_SETTINGS,

            userLocation: DEFAULT_LOCATION,
            drivers: INITIAL_DRIVERS,
            currentRoute: null,

            setAppMode: (mode) => set({ appMode: mode }),
            setUser: (user) => set({ user, appMode: 'app' }),
            setRole: (role) => set({ currentRole: role, currentView: 'home' }), 
            setView: (view) => set({ currentView: view }),
            startRide: (ride) => set({ activeRide: ride, currentRoute: ride.route || get().currentRoute }),
            updateRideStatus: (status) => set((state) => ({
                activeRide: state.activeRide ? { ...state.activeRide, status } : null
            })),
            toggleDarkMode: () => set((state) => ({ isDarkMode: !state.isDarkMode })),
            setLanguage: (lang) => set({ language: lang }),
            logout: () => set({ user: null, activeRide: null, appMode: 'landing', currentView: 'home', currentRoute: null }),

            updateUserLocation: (loc) => set({ userLocation: loc }),
            updateDrivers: (drivers) => set({ drivers }),
            setRoute: (route) => set({ currentRoute: route }),

            updateAdminSettings: (newSettings) => set((state) => ({
                adminSettings: { ...state.adminSettings, ...newSettings }
            })),

            addToast: (type, message) => {
                const id = Math.random().toString(36).substring(7);
                set((state) => ({ toasts: [...state.toasts, { id, type, message }] }));
                setTimeout(() => get().removeToast(id), 4000);
            },
            removeToast: (id) => set((state) => ({ toasts: state.toasts.filter(t => t.id !== id) }))
        }),
        {
            name: 'itaxi-storage',
            partialize: (state) => ({ 
                isDarkMode: state.isDarkMode, 
                language: state.language,
                adminSettings: state.adminSettings,
                user: state.user
            }),
        }
    )
);

