import L from 'leaflet';
import { useAppStore } from '../../store';
import { RouteData } from '../../types';

// Custom Icons
const createIcon = (color: string, type: 'car' | 'pin') => {
    const svg = type === 'car' 
        ? `<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="${color}" stroke="white" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" class="w-8 h-8 drop-shadow-lg"><path d="M19 17h2c.6 0 1-.4 1-1v-3c0-.9-.7-1.7-1.5-1.9C18.7 10.6 16 10 16 10s-1.3-1.4-2.2-2.3c-.5-.4-1.1-.7-1.8-.7H5c-.6 0-1.1.4-1.4.9l-1.4 2.9A3.7 3.7 0 0 0 2 12v4c0 .6.4 1 1 1h2"/><circle cx="7" cy="17" r="2"/><circle cx="17" cy="17" r="2"/><path d="M5 17h12"/></svg>`
        : `<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="${color}" stroke="white" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" class="w-10 h-10 drop-shadow-xl"><path d="M20 10c0 6-8 12-8 12s-8-6-8-12a8 8 0 0 1 16 0Z"/><circle cx="12" cy="10" r="3"/></svg>`;

    return L.divIcon({
        className: 'custom-icon',
        html: svg,
        iconSize: type === 'car' ? [32, 32] : [40, 40],
        iconAnchor: type === 'car' ? [16, 16] : [20, 40],
        popupAnchor: [0, -40]
    });
};

const CarIcon = createIcon('#3b82f6', 'car');
const PickupIcon = createIcon('#22c55e', 'pin');
const DestIcon = createIcon('#ef4444', 'pin');
const DriverSelfIcon = createIcon('#f59e0b', 'car');

interface RealMapProps {
    drivers?: Array<{ id: string; location: { lat: number; lng: number; bearing?: number }; status: string }>;
    pickup?: { lat: number; lng: number } | null;
    destination?: { lat: number; lng: number } | null;
    center?: { lat: number; lng: number };
    zoom?: number;
    showUserLocation?: boolean;
    isDriverView?: boolean;
    route?: RouteData | null;
}

export const RealMap: React.FC<RealMapProps> = ({ 
    drivers = [], 
    pickup, 
    destination, 
    center, 
    zoom = 15,
    showUserLocation = true,
    isDriverView = false,
    route
}) => {
    const mapContainerRef = useRef<HTMLDivElement>(null);
    const mapInstanceRef = useRef<L.Map | null>(null);
    const markersRef = useRef<L.LayerGroup | null>(null);
    const routeLayerRef = useRef<L.LayerGroup | null>(null);
    const { isDarkMode, userLocation } = useAppStore();

    // Initialize Map
    useEffect(() => {
        if (!mapContainerRef.current) return;
        if (mapInstanceRef.current) return; // Already initialized

        const map = L.map(mapContainerRef.current, {
            zoomControl: false,
            attributionControl: false
        }).setView([userLocation.lat, userLocation.lng], zoom);

        const tileUrl = isDarkMode 
            ? 'https://{s}.basemaps.cartocdn.com/dark_all/{z}/{x}/{y}{r}.png' 
            : 'https://{s}.basemaps.cartocdn.com/light_all/{z}/{x}/{y}{r}.png';

        L.tileLayer(tileUrl, {
            maxZoom: 20,
            subdomains: 'abcd'
        }).addTo(map);

        markersRef.current = L.layerGroup().addTo(map);
        routeLayerRef.current = L.layerGroup().addTo(map);
        mapInstanceRef.current = map;

        // Cleanup
        return () => {
            map.remove();
            mapInstanceRef.current = null;
        };
    }, []); // Run once

    // Update Tiles when Theme changes
    useEffect(() => {
        const map = mapInstanceRef.current;
        if (!map) return;

        const tileUrl = isDarkMode 
            ? 'https://{s}.basemaps.cartocdn.com/dark_all/{z}/{x}/{y}{r}.png' 
            : 'https://{s}.basemaps.cartocdn.com/light_all/{z}/{x}/{y}{r}.png';

        // Remove old tile layers
        map.eachLayer((layer) => {
            if (layer instanceof L.TileLayer) {
                map.removeLayer(layer);
            }
        });

        L.tileLayer(tileUrl, {
            maxZoom: 20,
            subdomains: 'abcd'
        }).addTo(map);
    }, [isDarkMode]);

    // Update Markers & Route
    useEffect(() => {
        const map = mapInstanceRef.current;
        const markersLayer = markersRef.current;
        const routeLayer = routeLayerRef.current;

        if (!map || !markersLayer || !routeLayer) return;

        // Clear existing layers
        markersLayer.clearLayers();
        routeLayer.clearLayers();

        // 1. Draw Drivers
        drivers.forEach(driver => {
            const icon = isDriverView && driver.id === 'self' ? DriverSelfIcon : CarIcon;
            L.marker([driver.location.lat, driver.location.lng], { icon }).addTo(markersLayer);
        });

        // 2. Draw Pickup
        if (pickup) {
            L.marker([pickup.lat, pickup.lng], { icon: PickupIcon })
             .bindPopup("Pickup Location")
             .addTo(markersLayer);
        }

        // 3. Draw Destination
        if (destination) {
            L.marker([destination.lat, destination.lng], { icon: DestIcon })
             .bindPopup("Destination")
             .addTo(markersLayer);
        }

        // 4. Draw User Location (if not driver view and no pickup set yet)
        if (showUserLocation && !isDriverView && !pickup) {
             L.marker([userLocation.lat, userLocation.lng], { icon: PickupIcon })
             .bindPopup("You are here")
             .addTo(markersLayer);
        }

        // 5. Draw Route
        if (route) {
            const routeColor = isDarkMode ? '#60a5fa' : '#2563eb';

            // Shadow
            L.polyline(route.coordinates, {
                color: isDarkMode ? '#000' : '#ccc',
                weight: 7,
                opacity: 0.3,
                className: 'blur-[2px]' // Tailwind utility might not work inside Leaflet SVG, but we try
            }).addTo(routeLayer);

            // Main Line
            L.polyline(route.coordinates, {
                color: routeColor,
                weight: 5,
                opacity: 0.8,
                lineCap: 'round',
                lineJoin: 'round',
                dashArray: '1, 10'
            }).addTo(routeLayer);

            // Fit bounds
            if (route.bbox) {
                 map.fitBounds([
                    [route.bbox[0], route.bbox[1]],
                    [route.bbox[2], route.bbox[3]]
                ], { padding: [50, 50] });
            }
        } else {
            // If no route, follow the "center" prop logic
            const targetCenter: [number, number] = center 
                ? [center.lat, center.lng] 
                : pickup 
                    ? [pickup.lat, pickup.lng] 
                    : [userLocation.lat, userLocation.lng];

            map.flyTo(targetCenter, zoom, { duration: 1.5 });
        }

    }, [drivers, pickup, destination, center, zoom, showUserLocation, isDriverView, route, userLocation, isDarkMode]);

    return <div ref={mapContainerRef} className="w-full h-full absolute inset-0 z-0 bg-slate-100 dark:bg-slate-900" />;
};

