import React, { useState } from 'react';
import { Button } from '../../components/ui/Button';
import { Card } from '../../components/ui/Card';
import { useAppStore } from '../../store';
import { ArrowRight, Smartphone, KeyRound, ArrowLeft } from 'lucide-react';
import { translations } from '../../constants/translations';

export const LoginPage: React.FC = () => {
    const { setUser, setAppMode, setRole, language } = useAppStore();
    const t = translations[language];
    const isRTL = language === 'fa';
    const ArrowIcon = isRTL ? ArrowLeft : ArrowRight;
    const BackIcon = isRTL ? ArrowRight : ArrowLeft;

    const [step, setStep] = useState<'phone' | 'otp'>('phone');
    const [phone, setPhone] = useState('');
    const [otp, setOtp] = useState(['', '', '', '']);
    const [loading, setLoading] = useState(false);
    const [selectedRole, setSelectedRole] = useState<'rider' | 'driver' | 'admin'>('rider');

    const handleSendOtp = (e: React.FormEvent) => {
        e.preventDefault();
        setLoading(true);
        setTimeout(() => {
            setLoading(false);
            setStep('otp');
        }, 1500);
    };

    const handleVerifyOtp = (e: React.FormEvent) => {
        e.preventDefault();
        setLoading(true);
        setTimeout(() => {
            setLoading(false);
            setRole(selectedRole);
            setUser({
                id: 'u1',
                name: 'Sardar Khan',
                email: 'sardar@itaxi.com',
                role: selectedRole,
                rating: 4.85
            });
        }, 1500);
    };

    const handleOtpChange = (index: number, value: string) => {
        if (value.length > 1) return;
        const newOtp = [...otp];
        newOtp[index] = value;
        setOtp(newOtp);
        if (value && index < 3) {
            document.getElementById(`otp-${index + 1}`)?.focus();
        }
    };

    return (
        <div className="min-h-screen w-full flex items-center justify-center relative overflow-hidden bg-slate-50 dark:bg-slate-950 transition-colors duration-500">
            <button 
                onClick={() => setAppMode('landing')}
                className="absolute top-6 start-6 flex items-center gap-2 text-slate-500 dark:text-slate-400 hover:text-slate-900 dark:hover:text-white transition-colors z-20"
            >
                <BackIcon size={20} /> {t.common.back}
            </button>

            {/* Background Effects */}
            <div className="absolute top-[-20%] left-[-10%] w-[600px] h-[600px] bg-brand-400/20 dark:bg-brand-600/20 rounded-full blur-[120px] pointer-events-none" />
            <div className="absolute bottom-[-20%] right-[-10%] w-[500px] h-[500px] bg-purple-400/10 dark:bg-purple-600/10 rounded-full blur-[100px] pointer-events-none" />

            <Card className="w-full max-w-md mx-4 border-slate-200 dark:border-white/10 shadow-2xl backdrop-blur-xl bg-white/80 dark:bg-slate-900/80 p-8">
                <div className="text-center mb-8">
                    <div className="w-16 h-16 bg-gradient-to-tr from-brand-500 to-blue-600 rounded-2xl mx-auto flex items-center justify-center mb-4 shadow-lg shadow-brand-500/20">
                        <span className="text-3xl font-bold text-white">{language === 'fa' ? 'آ' : 'iT'}</span>
                    </div>
                    <h1 className="text-2xl font-bold text-slate-900 dark:text-white mb-2">{t.auth.welcome_back}</h1>
                    <p className="text-slate-500 dark:text-slate-400 text-sm">{t.auth.sign_in_text}</p>
                </div>

                {/* Role Selector */}
                {step === 'phone' && (
                    <div className="mb-6 bg-slate-100 dark:bg-dark-950/50 p-1 rounded-xl flex border border-slate-200 dark:border-white/10">
                        {(['rider', 'driver', 'admin'] as const).map((r) => (
                            <button
                                key={r}
                                onClick={() => setSelectedRole(r)}
                                className={`flex-1 py-2 text-xs font-bold uppercase rounded-lg transition-all ${selectedRole === r ? 'bg-white dark:bg-brand-600 text-brand-600 dark:text-white shadow-sm' : 'text-slate-500 hover:text-slate-900 dark:hover:text-white'}`}
                            >
                                {t.roles[r]}
                            </button>
                        ))}
                    </div>
                )}

                {step === 'phone' ? (
                    <form onSubmit={handleSendOtp} className="space-y-6 animate-in fade-in slide-in-from-right-4 duration-300">
                        <div className="space-y-2">
                            <label className="text-xs font-semibold text-slate-500 dark:text-slate-400 uppercase tracking-wider ms-1">{t.auth.mobile_label}</label>
                            <div className="relative">
                                <Smartphone className="absolute start-4 top-3.5 text-slate-400 dark:text-slate-500" size={18} />
                                <input 
                                    type="tel"
                                    dir="ltr"
                                    placeholder="079 000 0000"
                                    className="w-full bg-slate-50 dark:bg-dark-950/50 border border-slate-200 dark:border-white/10 rounded-xl py-3 ps-11 pe-4 text-slate-900 dark:text-white placeholder:text-slate-400 dark:placeholder:text-slate-600 focus:outline-none focus:border-brand-500 focus:ring-1 focus:ring-brand-500 transition-all text-start"
                                    value={phone}
                                    onChange={(e) => setPhone(e.target.value)}
                                    required
                                />
                            </div>
                        </div>
                        <Button type="submit" size="lg" isLoading={loading} className="w-full">
                            {t.auth.continue} <ArrowIcon size={18} className="rtl:rotate-180" />
                        </Button>
                    </form>
                ) : (
                    <form onSubmit={handleVerifyOtp} className="space-y-6 animate-in fade-in slide-in-from-right-4 duration-300">
                         <div className="text-center">
                            <div className="text-sm text-slate-500 dark:text-slate-300 mb-6">
                                {t.auth.enter_code} <br/><span className="text-brand-600 dark:text-brand-400 font-medium" dir="ltr">{phone}</span>
                            </div>
                            <div className="flex justify-center gap-3 mb-6" dir="ltr">
                                {otp.map((digit, idx) => (
                                    <input
                                        key={idx}
                                        id={`otp-${idx}`}
                                        type="text"
                                        inputMode="numeric"
                                        maxLength={1}
                                        className="w-14 h-16 bg-slate-50 dark:bg-dark-950/50 border border-slate-200 dark:border-white/10 rounded-xl text-center text-2xl font-bold text-slate-900 dark:text-white focus:outline-none focus:border-brand-500 focus:ring-1 focus:ring-brand-500 transition-all"
                                        value={digit}
                                        onChange={(e) => handleOtpChange(idx, e.target.value)}
                                    />
                                ))}
                            </div>
                         </div>
                        <Button type="submit" size="lg" isLoading={loading} className="w-full">
                            {t.auth.verify_login} <KeyRound size={18} />
                        </Button>
                        <button 
                            type="button" 
                            onClick={() => setStep('phone')}
                            className="w-full text-xs text-slate-500 hover:text-slate-900 dark:hover:text-white transition-colors"
                        >
                            {t.auth.change_phone}
                        </button>
                    </form>
                )}
            </Card>
        </div>
    );
};

export type UserRole = 'rider' | 'driver' | 'admin' | null;

export interface Location {
    lat: number;
    lng: number;
    bearing?: number; // 0-360 degrees
}

export interface User {
    id: string;
    name: string;
    email: string;
    avatar?: string;
    role: UserRole;
    rating?: number;
    phone?: string;
}

export type ServiceType = 'city' | 'intercity' | 'airport' | 'hotel' | 'scheduled' | 'subscription';

export interface Ride {
    id: string;
    pickup: string;
    destination: string;
    pickupLocation: Location;
    destinationLocation: Location;
    fare: number; // Agreed fare
    proposedFare?: number; // Rider's offer
    status: 'searching' | 'negotiating' | 'accepted' | 'arrived' | 'in_progress' | 'completed' | 'cancelled';
    driverId?: string;
    riderId: string;
    serviceType: ServiceType;
    timestamp: number;
    distance: number;
    duration: number;
    route?: RouteData;
}

export interface Hotel {
    id: string;
    name: string;
    address: string;
    rating: number;
    priceRange: string;
    location: Location;
    image: string;
    commission: number;
}

export interface DriverMarker {
    id: string;
    name: string;
    vehicle: string;
    rating: number;
    location: Location;
    status: 'available' | 'busy' | 'offline';
    baseFare: number;
    perKmRate: number;
    type: 'eco' | 'plus' | 'lux';
}

export interface Notification {
    id: string;
    title: string;
    message: string;
    type: 'info' | 'success' | 'warning' | 'error';
    read: boolean;
}

export interface RouteData {
    coordinates: [number, number][]; // Array of [lat, lng]
    distance: number; // meters
    duration: number; // seconds
    bbox?: [number, number, number, number]; // [minLat, minLng, maxLat, maxLng]
}

export type RoutingProviderType = 'ors' | 'mapbox' | 'mock';
export type MapProviderType = 'osm' | 'mapbox' | 'google';

export interface AdminSettings {
    routingProvider: RoutingProviderType;
    mapProvider: MapProviderType;
    apiKeys: {
        ors: string;
        mapbox: string;
        google: string;
    };
    pricing: {
        minFare: number;
        commissionRate: number; // Percentage
        cancellationFee: number;
        intercityMultiplier: number;
    };
    system: {
        defaultCenter: Location;
        driverUpdateInterval: number;
        enableManualFare: boolean;
        radiusLimit: number; // km
    };
    hotelsModule: {
        enabled: boolean;
        commission: number;
    };
}

