    };

    const handleRequestRide = (driverId: string) => {
        const driver = drivers.find(d => d.id === driverId);
        const fare = parseInt(proposedFare) || 100;

        const newRide: Ride = {
            id: `ride_${Date.now()}`,
            pickup: 'Current Location',
            destination: destination,
            pickupLocation: userLocation,
            destinationLocation: destCoords!,
            fare: fare,
            proposedFare: fare,
            status: 'searching', // Initially searching/negotiating
            riderId: 'u1',
            driverId: driverId,
            serviceType: selectedService,
            timestamp: Date.now(),
            distance: currentRoute?.distance || 0,
            duration: currentRoute?.duration || 0,
            route: currentRoute!
        };

        startRide(newRide);
        setViewState('tracking');
        addToast('info', `Request sent to ${driver?.name}`);

        // Simulate Acceptance
        setTimeout(() => {
            updateRideStatus('accepted');
            addToast('success', `${driver?.name} accepted your offer!`);
        }, 3000);
