// This mimics a real WebSocket service for the frontend structure
import { useAppStore } from '../store';
import { DriverMarker } from '../types';

class MockSocketService {
    private isConnected: boolean = false;
    private listeners: Record<string, Function[]> = {};
    private updateInterval: any;

    connect() {
        console.log("🔌 Connecting to iTaxi Realtime Server...");
        setTimeout(() => {
            this.isConnected = true;
            console.log("✅ Connected securely.");
            this.emit('connection_status', 'connected');
            this.startSimulation();
        }, 800);
    }

    disconnect() {
        this.isConnected = false;
        if (this.updateInterval) clearInterval(this.updateInterval);
        console.log("❌ Disconnected.");
    }

    on(event: string, callback: Function) {
        if (!this.listeners[event]) {
            this.listeners[event] = [];
        }
        this.listeners[event].push(callback);
    }

    off(event: string, callback: Function) {
        if (!this.listeners[event]) return;
        this.listeners[event] = this.listeners[event].filter(cb => cb !== callback);
    }

    // Simulate sending data to backend
    emit(event: string, data: any) {
        console.log(`📡 Emitting [${event}]:`, data);

        // Simulate backend responses
        if (event === 'request_ride') {
            setTimeout(() => {
                const store = useAppStore.getState();
                if (store.activeRide) {
                    store.updateRideStatus('assigned');
                    this.triggerListeners('ride_update', { status: 'assigned', driverId: 'd99' });
                }
            }, 3000);
        }
    }

    private triggerListeners(event: string, data: any) {
        if (this.listeners[event]) {
            this.listeners[event].forEach(cb => cb(data));
        }
    }

    // Simulate driver movement
    private startSimulation() {
        this.updateInterval = setInterval(() => {
            const store = useAppStore.getState();
            const drivers = store.drivers;

            const updatedDrivers = drivers.map(driver => {
                // Add random small movement
                const moveLat = (Math.random() - 0.5) * 0.0004;
                const moveLng = (Math.random() - 0.5) * 0.0004;

                return {
                    ...driver,
                    location: {
                        lat: driver.location.lat + moveLat,
                        lng: driver.location.lng + moveLng,
                        bearing: driver.location.bearing // Simplification: keep bearing static for now or calculate later
                    }
                };
            });

            store.updateDrivers(updatedDrivers);
        }, 2000); // Update every 2 seconds
    }
}

