            <div className="flex justify-around items-center h-16">
                {getTabs().map((tab) => {
                    // Map generic IDs to AppView types where necessary, or assume IDs match AppView for simplicity in this implementation
                    const targetView = tab.id === 'messages' ? 'support' : tab.id === 'trips' ? 'activity' : tab.id as AppView; 
                    const isActive = currentView === targetView;

                    return (
