export const useAppStore = create<AppState>()(
    persist(
        (set, get) => ({
            appMode: 'landing',
            user: null, 
            currentRole: 'rider',
            activeRide: null,
            isDarkMode: true,
            language: 'en',
            notifications: [],
            toasts: [],
            currentView: 'home',

            adminSettings: DEFAULT_ADMIN_SETTINGS,

            userLocation: DEFAULT_LOCATION,
            drivers: [],
            hotels: INITIAL_HOTELS,
            currentRoute: null,

            setAppMode: (mode) => set({ appMode: mode }),
            setUser: (user) => set({ user, appMode: 'app' }),
            setRole: (role) => set({ currentRole: role, currentView: 'home' }), 
            setView: (view) => set({ currentView: view }),
            startRide: (ride) => set((state) => ({ activeRide: ride, currentRoute: ride?.route || state.currentRoute })),
            updateRideStatus: (status) => set((state) => ({
                activeRide: state.activeRide ? { ...state.activeRide, status } : null
            })),
            toggleDarkMode: () => set((state) => ({ isDarkMode: !state.isDarkMode })),
            setLanguage: (lang) => set({ language: lang }),
            logout: () => set({ user: null, activeRide: null, appMode: 'landing', currentView: 'home', currentRoute: null }),

            updateUserLocation: (loc) => set({ userLocation: loc }),
            updateDrivers: (drivers) => set({ drivers }),

            generateLocalDrivers: (center) => {
                const newDrivers = Array.from({ length: 6 }).map((_, i) => ({
                    id: `d_${Date.now()}_${i}`,
                    name: `Driver ${i + 1}`,
                    vehicle: i % 2 === 0 ? 'Toyota Corolla' : 'Honda Civic',
                    rating: 4.5 + Math.random() * 0.5,
                    location: {
                        lat: center.lat + (Math.random() - 0.5) * 0.015,
                        lng: center.lng + (Math.random() - 0.5) * 0.015,
                        bearing: Math.random() * 360
                    },
                    status: (Math.random() > 0.3 ? 'available' : 'busy') as 'available' | 'busy',
                    type: ['eco', 'plus', 'lux'][Math.floor(Math.random() * 3)] as 'eco' | 'plus' | 'lux',
                    baseFare: 50 + Math.floor(Math.random() * 20),
                    perKmRate: 20 + Math.floor(Math.random() * 10),
                    eta: Math.floor(Math.random() * 10) + 2
                }));
                set({ drivers: newDrivers });
            },

            setRoute: (route) => set({ currentRoute: route }),

            updateAdminSettings: (newSettings) => set((state) => ({
                adminSettings: { ...state.adminSettings, ...newSettings }
            })),

            addHotel: (hotel) => set((state) => ({ hotels: [...state.hotels, hotel] })),
            removeHotel: (id) => set((state) => ({ hotels: state.hotels.filter(h => h.id !== id) })),

            addToast: (type, message) => {
                const id = Math.random().toString(36).substring(7);
                set((state) => ({ toasts: [...state.toasts, { id, type, message }] }));
                setTimeout(() => get().removeToast(id), 4000);
            },
            removeToast: (id) => set((state) => ({ toasts: state.toasts.filter(t => t.id !== id) }))
        }),
        {
            name: 'itaxi-storage',
            partialize: (state) => ({ 
                isDarkMode: state.isDarkMode, 
                language: state.language,
                adminSettings: state.adminSettings,
                user: state.user
            }),
        }
    )
);

import React from 'react';
import { useAppStore, AppView } from '../../store';
import { Home, Map, Wallet, User, MessageCircle, List, Settings, Users, Briefcase } from 'lucide-react';

export const BottomTabNav: React.FC = () => {
    const { currentRole, currentView, setView } = useAppStore();

    const getTabs = () => {
        switch (currentRole) {
            case 'driver':
                return [
                    { id: 'home', icon: <Map size={24} />, label: 'Dashboard', view: 'home' },
                    { id: 'trips', icon: <List size={24} />, label: 'Trips', view: 'activity' },
                    { id: 'wallet', icon: <Wallet size={24} />, label: 'Earnings', view: 'wallet' }, // Drivers see earnings in wallet view
                    { id: 'messages', icon: <MessageCircle size={24} />, label: 'Chat', view: 'messages' },
                    { id: 'profile', icon: <User size={24} />, label: 'Profile', view: 'profile' },
                ];
            case 'admin':
                return [
                    { id: 'home', icon: <Map size={24} />, label: 'Live Map', view: 'home' },
                    { id: 'drivers', icon: <Users size={24} />, label: 'Drivers', view: 'drivers' },
                    { id: 'finance', icon: <Wallet size={24} />, label: 'Finance', view: 'finance' },
                    { id: 'messages', icon: <MessageCircle size={24} />, label: 'Support', view: 'messages' }, // Admin Support/Messages
                    { id: 'admin_settings', icon: <Settings size={24} />, label: 'Admin', view: 'admin_settings' },
                ];
            default: // rider
                return [
                    { id: 'home', icon: <Home size={24} />, label: 'Home', view: 'home' },
                    { id: 'trips', icon: <List size={24} />, label: 'Trips', view: 'activity' },
                    { id: 'wallet', icon: <Wallet size={24} />, label: 'Wallet', view: 'wallet' },
                    { id: 'messages', icon: <MessageCircle size={24} />, label: 'Messages', view: 'messages' },
                    { id: 'profile', icon: <User size={24} />, label: 'Profile', view: 'profile' },
                ];
        }
    };

    return (
        <div className="lg:hidden fixed bottom-0 left-0 right-0 bg-white/95 dark:bg-dark-950/95 backdrop-blur-md border-t border-dark-200 dark:border-white/10 pb-safe z-50 transition-colors duration-300 shadow-[0_-5px_20px_rgba(0,0,0,0.05)]">
            <div className="flex justify-around items-center h-16 px-2">
                {getTabs().map((tab) => {
                    const isActive = currentView === tab.view;
                    return (
                        <button
                            key={tab.id}
                            onClick={() => setView(tab.view as AppView)}
                            className="relative flex flex-col items-center justify-center w-full h-full space-y-1 group active:scale-95 transition-transform"
                        >
                            <div className={`transition-all duration-300 transform rounded-xl p-1 ${isActive ? 'bg-brand-50 dark:bg-brand-500/10 text-brand-600 dark:text-brand-400 -translate-y-1' : 'text-dark-400 dark:text-dark-500'}`}>
                                {tab.icon}
                            </div>
                            <span className={`text-[10px] font-bold transition-colors duration-300 ${isActive ? 'text-brand-600 dark:text-brand-400' : 'text-dark-400 dark:text-dark-500'}`}>
                                {tab.label}
                            </span>
                            {isActive && (
                                <div className="absolute -bottom-2 w-1 h-1 rounded-full bg-brand-600 dark:bg-brand-400"></div>
                            )}
                        </button>
                    );
                })}
            </div>
        </div>
    );
};

import React, { useState } from 'react';
import { MapBackground } from '../../components/Map/MapBackground';
import { Card } from '../../components/ui/Card';
import { Button } from '../../components/ui/Button';
import { MapPin, Navigation, Car, Building, Plane, Clock, User, MessageCircle, Phone, X, Star, Calendar, Flag } from 'lucide-react';
import { useAppStore } from '../../store';
import { Ride, ServiceType } from '../../types';
import { RoutingManager } from '../../services/routing/RoutingManager';

export const RiderHome: React.FC = () => {
    const { activeRide, startRide, updateRideStatus, addToast, userLocation, drivers, hotels, adminSettings, setRoute, currentRoute } = useAppStore();

    // View States: 'grid' | 'selecting' | 'drivers' | 'negotiating' | 'tracking'
    const [viewState, setViewState] = useState<'grid' | 'selecting' | 'drivers' | 'negotiating' | 'tracking'>('grid');
    const [selectedService, setSelectedService] = useState<ServiceType>('city');
    const [destination, setDestination] = useState('');
    const [destCoords, setDestCoords] = useState<{lat: number, lng: number} | null>(null);
    const [proposedFare, setProposedFare] = useState<string>('');
    const [isCalculating, setIsCalculating] = useState(false);
    const [selectedDriverId, setSelectedDriverId] = useState<string | null>(null);

    // --- Actions ---

    const handleServiceSelect = (service: ServiceType) => {
        setSelectedService(service);
        if (service === 'hotel') {
            setViewState('selecting'); // Show hotels on map, click to select
        } else {
            setViewState('selecting');
        }
    };

    const handleSetDestination = async () => {
        if (!destination) return;
        setIsCalculating(true);

        // Mock Geocoding (simulating User -> Kabul Airport)
        const target = { lat: 34.5650, lng: 69.2120 }; // Airport
        setDestCoords(target);

        try {
            const routeData = await RoutingManager.getRoute(userLocation, target, adminSettings);
            setRoute(routeData);
            setViewState('drivers'); // Go to driver selection

            // Auto-calculate suggested fare
            const distKm = routeData.distance / 1000;
            const suggested = Math.round(distKm * 20 + adminSettings.pricing.minFare);
            setProposedFare(suggested.toString());
        } catch (error) {
            addToast('error', "Could not calculate route.");
        } finally {
            setIsCalculating(false);
        }
    };

    const handleSelectDriver = (driverId: string, baseFare: number) => {
        setSelectedDriverId(driverId);
        // If driver has a higher base fare, update proposed, otherwise keep user's or set to match
        setProposedFare(Math.max(parseInt(proposedFare) || 0, baseFare).toString());
    };

    const handleRequestRide = () => {
        if (!selectedDriverId) return;

        const driver = drivers.find(d => d.id === selectedDriverId);
        const fare = parseInt(proposedFare);

        const newRide: Ride = {
            id: `ride_${Date.now()}`,
            pickup: 'Current Location',
            destination: destination,
            pickupLocation: userLocation,
            destinationLocation: destCoords!,
            fare: fare,
            proposedFare: fare,
            status: 'requested',
            riderId: 'u1',
            driverId: selectedDriverId,
            serviceType: selectedService,
            timestamp: Date.now(),
            distance: currentRoute?.distance || 0,
            duration: currentRoute?.duration || 0,
            route: currentRoute!
        };

        startRide(newRide);
        setViewState('tracking');
        addToast('info', `Request sent to ${driver?.name}. Waiting for acceptance...`);

        // Simulate Driver Acceptance Logic (Mock)
        setTimeout(() => {
            updateRideStatus('accepted');
            addToast('success', `${driver?.name} accepted your offer!`);
        }, 4000);
    };

    const resetFlow = () => {
        setViewState('grid');
        setDestCoords(null);
        setRoute(null);
        setDestination('');
        startRide(null);
        setSelectedDriverId(null);
    };

    // --- Sub-Components ---

    const ServiceGrid = () => (
        <div className="absolute bottom-0 left-0 right-0 p-6 bg-white dark:bg-dark-950 rounded-t-3xl shadow-[0_-10px_40px_rgba(0,0,0,0.1)] z-20 animate-in slide-in-from-bottom-10 duration-300">
            <h2 className="text-xl font-bold text-dark-900 dark:text-white mb-6">Choose Service</h2>
            <div className="grid grid-cols-3 gap-4 mb-20 md:mb-4">
                {[
                    { id: 'city', label: 'City Taxi', icon: <Car size={28} />, color: 'bg-blue-100 text-blue-600 dark:bg-blue-600/20 dark:text-blue-400' },
                    { id: 'intercity', label: 'Intercity', icon: <MapPin size={28} />, color: 'bg-green-100 text-green-600 dark:bg-green-600/20 dark:text-green-400' },
                    { id: 'airport', label: 'Airport', icon: <Plane size={28} />, color: 'bg-purple-100 text-purple-600 dark:bg-purple-600/20 dark:text-purple-400' },
                    { id: 'hotel', label: 'Hotel + Taxi', icon: <Building size={28} />, color: 'bg-orange-100 text-orange-600 dark:bg-orange-600/20 dark:text-orange-400' },
                    { id: 'scheduled', label: 'Schedule', icon: <Clock size={28} />, color: 'bg-slate-100 text-slate-600 dark:bg-slate-700/50 dark:text-slate-400' },
                    { id: 'subscription', label: 'Subs', icon: <User size={28} />, color: 'bg-slate-100 text-slate-600 dark:bg-slate-700/50 dark:text-slate-400' },
                ].map((item) => (
                    <button 
                        key={item.id} 
                        onClick={() => handleServiceSelect(item.id as ServiceType)}
                        className="flex flex-col items-center justify-center p-4 rounded-2xl bg-dark-50 dark:bg-white/5 active:scale-95 transition-transform hover:bg-dark-100 dark:hover:bg-white/10"
                    >
                        <div className={`w-14 h-14 rounded-full flex items-center justify-center mb-3 ${item.color}`}>
                            {item.icon}
                        </div>
                        <span className="text-xs font-bold text-dark-700 dark:text-dark-300">{item.label}</span>
                    </button>
                ))}
            </div>
        </div>
    );

    const LocationSelector = () => (
        <div className="absolute top-20 left-4 right-4 z-20 animate-in slide-in-from-top-5">
            <Card className="shadow-xl">
                <div className="flex items-center gap-2 mb-4">
                     <button onClick={resetFlow}><X size={20} className="text-dark-400" /></button>
                     <h3 className="font-bold text-lg text-dark-900 dark:text-white capitalize">{selectedService} Ride</h3>
                </div>
                <div className="space-y-4">
                    <div className="relative">
                        <div className="absolute left-3 top-3 w-2 h-2 rounded-full bg-green-500"></div>
                        <input type="text" value="Current Location" readOnly className="w-full pl-8 py-2 border-b border-dark-100 dark:border-white/10 bg-transparent text-sm font-medium text-dark-900 dark:text-white" />
                    </div>
                    <div className="relative">
                        <div className="absolute left-3 top-3 w-2 h-2 rounded-full bg-red-500"></div>
                        <input 
                            type="text" 
                            placeholder={selectedService === 'hotel' ? "Select Hotel on Map..." : "Where to?"}
                            className="w-full pl-8 py-2 border-b border-brand-500 bg-transparent text-lg font-bold text-dark-900 dark:text-white focus:outline-none"
                            value={destination}
                            onChange={(e) => setDestination(e.target.value)} 
                        />
                    </div>
                    <Button onClick={handleSetDestination} isLoading={isCalculating} className="w-full" disabled={!destination}>
                        {selectedService === 'hotel' ? 'Find Drivers to Hotel' : 'Set Destination'}
                    </Button>
                </div>
            </Card>
        </div>
    );

    const DriverSelectionPanel = () => (
        <div className="absolute bottom-0 left-0 right-0 bg-white dark:bg-dark-950 rounded-t-3xl shadow-[0_-10px_50px_rgba(0,0,0,0.2)] z-30 flex flex-col h-[70vh] animate-in slide-in-from-bottom-20 duration-300">
            <div className="p-4 border-b border-dark-100 dark:border-white/5 flex flex-col gap-3">
                <div className="flex justify-between items-center">
                    <h3 className="font-bold text-lg text-dark-900 dark:text-white">Nearby Drivers</h3>
                    <button onClick={resetFlow}><X size={20} className="text-dark-400" /></button>
                </div>

                {/* Negotiation Input */}
                <div className="flex items-center justify-between bg-brand-50 dark:bg-brand-900/20 p-3 rounded-xl border border-brand-200 dark:border-brand-500/30">
                    <span className="text-sm font-bold text-brand-700 dark:text-brand-300">Your Offer (AFN)</span>
                    <div className="flex items-center gap-2">
                        <button onClick={() => setProposedFare((parseInt(proposedFare)-10).toString())} className="w-8 h-8 rounded-full bg-white dark:bg-white/10 flex items-center justify-center font-bold text-dark-600 dark:text-white">-</button>
                        <input 
                            type="number" 
                            className="w-20 bg-transparent text-center font-black text-xl text-brand-700 dark:text-white focus:outline-none" 
                            value={proposedFare} 
                            onChange={(e) => setProposedFare(e.target.value)} 
                        />
                        <button onClick={() => setProposedFare((parseInt(proposedFare)+10).toString())} className="w-8 h-8 rounded-full bg-white dark:bg-white/10 flex items-center justify-center font-bold text-dark-600 dark:text-white">+</button>
                    </div>
                </div>
            </div>

            <div className="flex-1 overflow-y-auto p-4 space-y-3 pb-24">
                {drivers.map(driver => (
                    <div 
                        key={driver.id} 
                        onClick={() => handleSelectDriver(driver.id, driver.baseFare)}
                        className={`relative flex items-center p-3 rounded-xl border-2 cursor-pointer transition-all ${selectedDriverId === driver.id ? 'border-brand-500 bg-brand-50 dark:bg-brand-900/20' : 'border-dark-100 dark:border-white/5 hover:border-brand-200 dark:hover:border-white/20'}`}
                    >
                        <div className="w-14 h-14 rounded-full bg-dark-200 dark:bg-dark-800 flex items-center justify-center mr-3 relative shrink-0">
                            <Car size={28} className="text-dark-500" />
                            <div className="absolute -bottom-1 -right-1 bg-green-500 text-[10px] text-white px-1.5 py-0.5 rounded-full border-2 border-white dark:border-dark-900 font-bold">
                                {driver.eta}m
                            </div>
                        </div>
                        <div className="flex-1">
                            <div className="flex justify-between items-center mb-1">
                                <span className="font-bold text-dark-900 dark:text-white text-lg">{driver.name}</span>
                                <span className="font-black text-dark-900 dark:text-white">؋{driver.baseFare}</span>
                            </div>
                            <div className="flex justify-between items-center text-xs text-dark-500 dark:text-dark-400">
                                <span>{driver.vehicle} • {driver.type.toUpperCase()}</span>
                                <span className="flex items-center text-orange-500 font-bold"><Star size={12} fill="currentColor" className="mr-1"/> {driver.rating.toFixed(1)}</span>
                            </div>
                        </div>
                    </div>
                ))}
            </div>

            <div className="absolute bottom-0 left-0 right-0 p-4 border-t border-dark-100 dark:border-white/5 bg-white dark:bg-dark-950 mb-safe">
                 <Button size="lg" className="w-full h-14 text-lg" disabled={!selectedDriverId} onClick={handleRequestRide}>
                    Request Ride {selectedDriverId && `(؋${proposedFare})`}
                 </Button>
            </div>
        </div>
    );

    const ActiveTripPanel = () => {
        if (!activeRide) return null;
        const isPending = activeRide.status === 'requested';

        return (
            <div className="absolute bottom-0 left-0 right-0 bg-white dark:bg-dark-950 rounded-t-3xl shadow-[0_-10px_50px_rgba(0,0,0,0.2)] z-30 p-6 mb-16 md:mb-0 animate-in slide-in-from-bottom-20 duration-300">
                 {isPending ? (
