const CarIcon = createIcon('#3b82f6', 'car');
const PickupIcon = createIcon('#22c55e', 'pin');
const DestIcon = createIcon('#ef4444', 'pin');
const HotelIcon = createIcon('#8b5cf6', 'hotel');

interface RealMapProps {
    drivers?: Array<{ id: string; location: { lat: number; lng: number; bearing?: number }; status: string }>;
    hotels?: Hotel[];
    pickup?: { lat: number; lng: number } | null;
    destination?: { lat: number; lng: number } | null;
    center?: { lat: number; lng: number };
    zoom?: number;
    showUserLocation?: boolean;
    isDriverView?: boolean;
    route?: RouteData | null;
    showHotels?: boolean;
}

export const RealMap: React.FC<RealMapProps> = ({ 
    drivers = [], 
    hotels = [],
    pickup, 
    destination, 
    center, 
    zoom = 15,
    showUserLocation = true,
    isDriverView = false,
    route,
    showHotels = false
}) => {
    const mapContainerRef = useRef<HTMLDivElement>(null);
    const mapInstanceRef = useRef<L.Map | null>(null);
    const markersRef = useRef<L.LayerGroup | null>(null);
    const driverMarkersRef = useRef<Record<string, L.Marker>>({});
    const routeLayerRef = useRef<L.LayerGroup | null>(null);
    const { isDarkMode, userLocation } = useAppStore();

    // Initialize Map
    useEffect(() => {
        if (!mapContainerRef.current) return;
        if (mapInstanceRef.current) return;

        const map = L.map(mapContainerRef.current, {
            zoomControl: false,
            attributionControl: false
        }).setView([userLocation.lat, userLocation.lng], zoom);

        const tileUrl = isDarkMode 
            ? 'https://{s}.basemaps.cartocdn.com/dark_all/{z}/{x}/{y}{r}.png' 
            : 'https://{s}.basemaps.cartocdn.com/light_all/{z}/{x}/{y}{r}.png';

        L.tileLayer(tileUrl, { maxZoom: 20, subdomains: 'abcd' }).addTo(map);

        markersRef.current = L.layerGroup().addTo(map);
        routeLayerRef.current = L.layerGroup().addTo(map);
        mapInstanceRef.current = map;

        return () => {
            map.remove();
            mapInstanceRef.current = null;
        };
    }, []);

    // Theme Updates
    useEffect(() => {
        const map = mapInstanceRef.current;
        if (!map) return;
        const tileUrl = isDarkMode 
            ? 'https://{s}.basemaps.cartocdn.com/dark_all/{z}/{x}/{y}{r}.png' 
            : 'https://{s}.basemaps.cartocdn.com/light_all/{z}/{x}/{y}{r}.png';

        map.eachLayer((layer) => {
            if (layer instanceof L.TileLayer) map.removeLayer(layer);
        });
        L.tileLayer(tileUrl, { maxZoom: 20, subdomains: 'abcd' }).addTo(map);
    }, [isDarkMode]);

    // Drivers Update (Smooth Transition)
    useEffect(() => {
        const map = mapInstanceRef.current;
        if (!map) return;

        const currentIds = new Set<string>();

        drivers.forEach(driver => {
            currentIds.add(driver.id);
            const pos = new L.LatLng(driver.location.lat, driver.location.lng);

            if (driverMarkersRef.current[driver.id]) {
                // Update position
                driverMarkersRef.current[driver.id].setLatLng(pos);
            } else {
                // Create new
                const marker = L.marker(pos, { icon: CarIcon });
                marker.addTo(map);
                driverMarkersRef.current[driver.id] = marker;
            }
        });

        // Remove old drivers
        Object.keys(driverMarkersRef.current).forEach(id => {
            if (!currentIds.has(id)) {
                driverMarkersRef.current[id].remove();
                delete driverMarkersRef.current[id];
            }
        });

    }, [drivers]);

    // Static Markers & Route Update
    useEffect(() => {
        const map = mapInstanceRef.current;
        const markersLayer = markersRef.current;
        const routeLayer = routeLayerRef.current;

        if (!map || !markersLayer || !routeLayer) return;

        markersLayer.clearLayers();
        routeLayer.clearLayers();

        // Pickup
        if (pickup) {
            L.marker([pickup.lat, pickup.lng], { icon: PickupIcon }).addTo(markersLayer);
        }

        // Destination
        if (destination) {
            L.marker([destination.lat, destination.lng], { icon: DestIcon }).addTo(markersLayer);
        }

        // User Location
        if (showUserLocation && !isDriverView && !pickup) {
             L.marker([userLocation.lat, userLocation.lng], { icon: PickupIcon }).addTo(markersLayer);
        }

        // Hotels
        if (showHotels) {
            hotels.forEach(hotel => {
                L.marker([hotel.location.lat, hotel.location.lng], { icon: HotelIcon })
                 .bindPopup(`<b>${hotel.name}</b><br>${hotel.priceRange}`)
                 .addTo(markersLayer);
            });
        }

        // Route
        if (route) {
            const routeColor = isDarkMode ? '#60a5fa' : '#2563eb';
            L.polyline(route.coordinates, {
                color: isDarkMode ? '#000' : '#ccc',
                weight: 7,
                opacity: 0.3,
                className: 'blur-[2px]' 
            }).addTo(routeLayer);

            L.polyline(route.coordinates, {
                color: routeColor,
                weight: 5,
                opacity: 0.8,
                lineCap: 'round',
                lineJoin: 'round',
                dashArray: '1, 10'
            }).addTo(routeLayer);

            if (route.bbox) {
                 map.fitBounds([
                    [route.bbox[0], route.bbox[1]],
                    [route.bbox[2], route.bbox[3]]
                ], { padding: [50, 50] });
            }
        } else {
            const targetCenter: [number, number] = center 
                ? [center.lat, center.lng] 
                : pickup 
                    ? [pickup.lat, pickup.lng] 
                    : [userLocation.lat, userLocation.lng];
            map.flyTo(targetCenter, zoom, { duration: 1.5 });
        }

    }, [pickup, destination, center, zoom, showUserLocation, isDriverView, route, userLocation, isDarkMode, showHotels, hotels]);

    return <div ref={mapContainerRef} className="w-full h-full absolute inset-0 z-0 bg-slate-100 dark:bg-slate-900" />;
};

