import React, { useEffect, useRef } from 'react';
import L from 'leaflet';
import { useAppStore } from '../../store';
import { RouteData, Hotel } from '../../types';

// Icons
const createIcon = (color: string, type: 'car' | 'pin' | 'hotel') => {
    let svg = '';
    if (type === 'car') {
        svg = `<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="${color}" stroke="white" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" class="w-8 h-8 drop-shadow-lg"><path d="M19 17h2c.6 0 1-.4 1-1v-3c0-.9-.7-1.7-1.5-1.9C18.7 10.6 16 10 16 10s-1.3-1.4-2.2-2.3c-.5-.4-1.1-.7-1.8-.7H5c-.6 0-1.1.4-1.4.9l-1.4 2.9A3.7 3.7 0 0 0 2 12v4c0 .6.4 1 1 1h2"/><circle cx="7" cy="17" r="2"/><circle cx="17" cy="17" r="2"/><path d="M5 17h12"/></svg>`;
    } else if (type === 'hotel') {
        svg = `<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="${color}" stroke="white" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" class="w-10 h-10 drop-shadow-xl"><path d="M6 22V4a2 2 0 0 1 2-2h8a2 2 0 0 1 2 2v18Z"/><path d="M6 12H4a2 2 0 0 0-2 2v6a2 2 0 0 0 2 2h2"/><path d="M18 9h2a2 2 0 0 1 2 2v9a2 2 0 0 1-2 2h-2"/><path d="M10 6h4"/><path d="M10 10h4"/><path d="M10 14h4"/><path d="M10 18h4"/></svg>`;
    } else {
        svg = `<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="${color}" stroke="white" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" class="w-10 h-10 drop-shadow-xl"><path d="M20 10c0 6-8 12-8 12s-8-6-8-12a8 8 0 0 1 16 0Z"/><circle cx="12" cy="10" r="3"/></svg>`;
    }

    return L.divIcon({
        className: 'custom-icon',
        html: svg,
        iconSize: type === 'car' ? [32, 32] : [40, 40],
        iconAnchor: type === 'car' ? [16, 16] : [20, 40],
        popupAnchor: [0, -40]
    });
};

const CarIcon = createIcon('#3b82f6', 'car');
const PickupIcon = createIcon('#22c55e', 'pin');
const DestIcon = createIcon('#ef4444', 'pin');
const HotelIcon = createIcon('#f97316', 'hotel');

interface RealMapProps {
    drivers?: Array<{ id: string; location: { lat: number; lng: number; bearing?: number }; status: string }>;
    hotels?: Hotel[];
    pickup?: { lat: number; lng: number } | null;
    destination?: { lat: number; lng: number } | null;
    center?: { lat: number; lng: number };
    zoom?: number;
    showUserLocation?: boolean;
    isDriverView?: boolean;
    route?: RouteData | null;
    showHotels?: boolean;
}

export const RealMap: React.FC<RealMapProps> = ({ 
    drivers = [], 
    hotels = [],
    pickup, 
    destination, 
    center, 
    zoom = 15,
    showUserLocation = true,
    isDriverView = false,
    route,
    showHotels = false
}) => {
    const mapContainerRef = useRef<HTMLDivElement>(null);
    const mapInstanceRef = useRef<L.Map | null>(null);
    const markersRef = useRef<L.LayerGroup | null>(null);
    const driverMarkersRef = useRef<Record<string, L.Marker>>({});
    const routeLayerRef = useRef<L.LayerGroup | null>(null);
    const { isDarkMode, userLocation } = useAppStore();

    // Initialize Map
    useEffect(() => {
        if (!mapContainerRef.current) return;
        if (mapInstanceRef.current) return;

        const map = L.map(mapContainerRef.current, {
            zoomControl: false,
            attributionControl: false
        }).setView([userLocation.lat, userLocation.lng], zoom);

        const tileUrl = isDarkMode 
            ? 'https://{s}.basemaps.cartocdn.com/dark_all/{z}/{x}/{y}{r}.png' 
            : 'https://{s}.basemaps.cartocdn.com/light_all/{z}/{x}/{y}{r}.png';

        L.tileLayer(tileUrl, { maxZoom: 20, subdomains: 'abcd' }).addTo(map);

        markersRef.current = L.layerGroup().addTo(map);
        routeLayerRef.current = L.layerGroup().addTo(map);
        mapInstanceRef.current = map;

        return () => {
            map.remove();
            mapInstanceRef.current = null;
        };
    }, []);

    // Theme Updates
    useEffect(() => {
        const map = mapInstanceRef.current;
        if (!map) return;
        const tileUrl = isDarkMode 
            ? 'https://{s}.basemaps.cartocdn.com/dark_all/{z}/{x}/{y}{r}.png' 
            : 'https://{s}.basemaps.cartocdn.com/light_all/{z}/{x}/{y}{r}.png';

        map.eachLayer((layer) => {
            if (layer instanceof L.TileLayer) map.removeLayer(layer);
        });
        L.tileLayer(tileUrl, { maxZoom: 20, subdomains: 'abcd' }).addTo(map);
    }, [isDarkMode]);

    // Drivers Update (Smooth Transition)
    useEffect(() => {
        const map = mapInstanceRef.current;
        if (!map) return;

        const currentIds = new Set<string>();

        drivers.forEach(driver => {
            currentIds.add(driver.id);
            const pos = new L.LatLng(driver.location.lat, driver.location.lng);

            if (driverMarkersRef.current[driver.id]) {
                // Update position
                driverMarkersRef.current[driver.id].setLatLng(pos);
            } else {
                // Create new
                const marker = L.marker(pos, { icon: CarIcon });
                marker.addTo(map);
                driverMarkersRef.current[driver.id] = marker;
            }
        });

        // Remove old drivers
        Object.keys(driverMarkersRef.current).forEach(id => {
            if (!currentIds.has(id)) {
                driverMarkersRef.current[id].remove();
                delete driverMarkersRef.current[id];
            }
        });

    }, [drivers]);

    // Static Markers & Route Update
    useEffect(() => {
        const map = mapInstanceRef.current;
        const markersLayer = markersRef.current;
        const routeLayer = routeLayerRef.current;

        if (!map || !markersLayer || !routeLayer) return;

        markersLayer.clearLayers();
        routeLayer.clearLayers();

        // Pickup
        if (pickup) {
            L.marker([pickup.lat, pickup.lng], { icon: PickupIcon }).addTo(markersLayer);
        }

        // Destination
        if (destination) {
            L.marker([destination.lat, destination.lng], { icon: DestIcon }).addTo(markersLayer);
        }

        // User Location
        if (showUserLocation && !isDriverView && !pickup) {
             L.marker([userLocation.lat, userLocation.lng], { icon: PickupIcon }).addTo(markersLayer);
        }

        // Hotels Logic
        if (showHotels) {
            hotels.forEach(hotel => {
                const marker = L.marker([hotel.location.lat, hotel.location.lng], { icon: HotelIcon });
                // Simple popup for now, can be complex component later
                const popupContent = `
                    <div style="text-align:center; font-family:sans-serif;">
                        <h3 style="margin:0; font-weight:bold;">${hotel.name}</h3>
                        <p style="margin:2px 0; color:#666;">${hotel.priceRange}</p>
                        <button style="margin-top:4px; background:#f97316; color:white; border:none; padding:4px 8px; border-radius:4px; cursor:pointer;" onclick="window.dispatchEvent(new CustomEvent('select-hotel', {detail: '${hotel.id}'}))">Select</button>
                    </div>
                `;
                marker.bindPopup(popupContent).addTo(markersLayer);
            });
        }

        // Route
        if (route) {
            const routeColor = isDarkMode ? '#60a5fa' : '#2563eb';
            L.polyline(route.coordinates, {
                color: isDarkMode ? '#000' : '#ccc',
                weight: 7,
                opacity: 0.3,
                className: 'blur-[2px]' 
            }).addTo(routeLayer);

            L.polyline(route.coordinates, {
                color: routeColor,
                weight: 5,
                opacity: 0.8,
                lineCap: 'round',
                lineJoin: 'round',
                dashArray: '1, 10'
            }).addTo(routeLayer);

            if (route.bbox) {
                 map.fitBounds([
                    [route.bbox[0], route.bbox[1]],
                    [route.bbox[2], route.bbox[3]]
                ], { padding: [50, 50] });
            }
        } else {
            const targetCenter: [number, number] = center 
                ? [center.lat, center.lng] 
                : pickup 
                    ? [pickup.lat, pickup.lng] 
                    : [userLocation.lat, userLocation.lng];
            map.flyTo(targetCenter, zoom, { duration: 1.5 });
        }

    }, [pickup, destination, center, zoom, showUserLocation, isDriverView, route, userLocation, isDarkMode, showHotels, hotels]);

    return <div ref={mapContainerRef} className="w-full h-full absolute inset-0 z-0 bg-slate-100 dark:bg-slate-900" />;
};

export type UserRole = 'rider' | 'driver' | 'admin' | null;

export interface Location {
    lat: number;
    lng: number;
    bearing?: number; // 0-360 degrees
}

export interface User {
    id: string;
    name: string;
    email: string;
    avatar?: string;
    role: UserRole;
    rating?: number;
    phone?: string;
}

export type ServiceType = 'city' | 'intercity' | 'airport' | 'hotel' | 'scheduled' | 'subscription';

export interface Ride {
    id: string;
    pickup: string;
    destination: string;
    pickupLocation: Location;
    destinationLocation: Location;
    fare: number; // Agreed fare
    proposedFare?: number; // Rider's offer
    status: 'searching' | 'negotiating' | 'requested' | 'accepted' | 'arrived' | 'in_progress' | 'completed' | 'cancelled';
    driverId?: string;
    riderId: string;
    serviceType: ServiceType;
    timestamp: number;
    distance: number;
    duration: number;
    route?: RouteData;
}

export interface Hotel {
    id: string;
    name: string;
    address: string;
    rating: number;
    priceRange: string;
    location: Location;
    image: string;
    commission: number;
}

export interface DriverMarker {
    id: string;
    name: string;
    vehicle: string;
    rating: number;
    location: Location;
    status: 'available' | 'busy' | 'offline';
    baseFare: number; // Driver set base fare
    perKmRate: number; // Driver set per km rate
    type: 'eco' | 'plus' | 'lux';
    distance?: number; // Calculated distance to rider
    eta?: number; // Calculated ETA
}

export interface Notification {
    id: string;
    title: string;
    message: string;
    type: 'info' | 'success' | 'warning' | 'error';
    read: boolean;
}

export interface RouteData {
    coordinates: [number, number][]; // Array of [lat, lng]
    distance: number; // meters
    duration: number; // seconds
    bbox?: [number, number, number, number]; // [minLat, minLng, maxLat, maxLng]
}

export type RoutingProviderType = 'ors' | 'mapbox' | 'mock';
export type MapProviderType = 'osm' | 'mapbox' | 'google';

export interface AdminSettings {
    routingProvider: RoutingProviderType;
    mapProvider: MapProviderType;
    apiKeys: {
        ors: string;
        mapbox: string;
        google: string;
    };
    pricing: {
        minFare: number;
        commissionRate: number; // Percentage
        cancellationFee: number;
        intercityMultiplier: number;
    };
    system: {
        defaultCenter: Location;
        driverUpdateInterval: number;
        enableManualFare: boolean;
        radiusLimit: number; // km
    };
    hotelsModule: {
        enabled: boolean;
        commission: number;
    };
}

export interface Toast {
    id: string;
    type: 'success' | 'error' | 'warning' | 'info';
    message: string;
}

