                                        onChange={e => setSystem({...system, radiusLimit: parseInt(e.target.value)})}
                                    />
                                </div>

                                <Button onClick={handleSaveSystem} icon={<Save size={18}/>} className="w-full">Update System Config</Button>
                            </div>
                        </Card>
                    </div>
                )}
            </div>
        </div>
    );
};

