export const RiderHome: React.FC = () => {
    const { activeRide, startRide, updateRideStatus, addToast, userLocation, drivers, hotels, adminSettings, setRoute, currentRoute } = useAppStore();

    // View States: 'grid' | 'selecting' | 'drivers' | 'negotiating' | 'tracking'
    const [viewState, setViewState] = useState<'grid' | 'selecting' | 'drivers' | 'negotiating' | 'tracking'>('grid');
    const [selectedService, setSelectedService] = useState<ServiceType>('city');
    const [destination, setDestination] = useState('');
    const [destCoords, setDestCoords] = useState<{lat: number, lng: number} | null>(null);
    const [proposedFare, setProposedFare] = useState<string>('');
    const [isCalculating, setIsCalculating] = useState(false);
    const [selectedDriverId, setSelectedDriverId] = useState<string | null>(null);

    // --- Actions ---

    const handleServiceSelect = (service: ServiceType) => {
        setSelectedService(service);
        if (service === 'hotel') {
            setViewState('selecting'); // Show hotels on map, click to select
        } else {
            setViewState('selecting');
        }
    };

    const handleSetDestination = async () => {
        if (!destination) return;
        setIsCalculating(true);

        // Mock Geocoding (simulating User -> Kabul Airport)
        const target = { lat: 34.5650, lng: 69.2120 }; // Airport
        setDestCoords(target);

        try {
            const routeData = await RoutingManager.getRoute(userLocation, target, adminSettings);
            setRoute(routeData);
            setViewState('drivers'); // Go to driver selection

            // Auto-calculate suggested fare
            const distKm = routeData.distance / 1000;
            const suggested = Math.round(distKm * 20 + adminSettings.pricing.minFare);
            setProposedFare(suggested.toString());
        } catch (error) {
            addToast('error', "Could not calculate route.");
        } finally {
            setIsCalculating(false);
        }
    };

