export const useAppStore = create<AppState>()(
    persist(
        (set, get) => ({
            appMode: 'landing',
            user: null, 
            currentRole: 'rider',
            activeRide: null,
            isDarkMode: true,
            language: 'en',
            notifications: [],
            toasts: [],
            currentView: 'home',

            adminSettings: DEFAULT_ADMIN_SETTINGS,

            userLocation: DEFAULT_LOCATION,
            drivers: [],
            hotels: INITIAL_HOTELS,
            currentRoute: null,

            setAppMode: (mode) => set({ appMode: mode }),
            setUser: (user) => set({ user, appMode: 'app' }),
            setRole: (role) => set({ currentRole: role, currentView: 'home' }), 
            setView: (view) => set({ currentView: view }),

            startRide: (ride) => set((state) => ({ 
                activeRide: ride, 
                currentRoute: ride?.route || state.currentRoute 
            })),

            updateRideStatus: (status) => set((state) => ({
                activeRide: state.activeRide ? { ...state.activeRide, status } : null
            })),

            toggleDarkMode: () => set((state) => ({ isDarkMode: !state.isDarkMode })),
            setLanguage: (lang) => set({ language: lang }),
            logout: () => set({ user: null, activeRide: null, appMode: 'landing', currentView: 'home', currentRoute: null }),

            updateUserLocation: (loc) => set({ userLocation: loc }),

            updateDrivers: (drivers) => set({ drivers }),

            registerDriver: (driver) => set((state) => {
                // Remove existing if same ID
                const filtered = state.drivers.filter(d => d.id !== driver.id);
                return { drivers: [...filtered, driver] };
            }),

            generateLocalDrivers: (center) => {
                const existingRealDrivers = get().drivers.filter(d => d.id === 'real_driver'); // Keep real driver if exists

                const newDrivers = Array.from({ length: 5 }).map((_, i) => ({
                    id: `sim_${Date.now()}_${i}`,
                    name: `Driver ${i + 1}`,
                    vehicle: i % 2 === 0 ? 'Toyota Corolla' : 'Honda Civic',
                    rating: 4.5 + Math.random() * 0.5,
