// Icons
const createIcon = (color: string, type: 'car' | 'pin' | 'hotel') => {
    let svg = '';
    if (type === 'car') {
        svg = `<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="${color}" stroke="white" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" class="w-8 h-8 drop-shadow-lg"><path d="M19 17h2c.6 0 1-.4 1-1v-3c0-.9-.7-1.7-1.5-1.9C18.7 10.6 16 10 16 10s-1.3-1.4-2.2-2.3c-.5-.4-1.1-.7-1.8-.7H5c-.6 0-1.1.4-1.4.9l-1.4 2.9A3.7 3.7 0 0 0 2 12v4c0 .6.4 1 1 1h2"/><circle cx="7" cy="17" r="2"/><circle cx="17" cy="17" r="2"/><path d="M5 17h12"/></svg>`;
    } else if (type === 'hotel') {
        svg = `<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="${color}" stroke="white" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" class="w-10 h-10 drop-shadow-xl"><path d="M6 22V4a2 2 0 0 1 2-2h8a2 2 0 0 1 2 2v18Z"/><path d="M6 12H4a2 2 0 0 0-2 2v6a2 2 0 0 0 2 2h2"/><path d="M18 9h2a2 2 0 0 1 2 2v9a2 2 0 0 1-2 2h-2"/><path d="M10 6h4"/><path d="M10 10h4"/><path d="M10 14h4"/><path d="M10 18h4"/></svg>`;
    } else {
        svg = `<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="${color}" stroke="white" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" class="w-10 h-10 drop-shadow-xl"><path d="M20 10c0 6-8 12-8 12s-8-6-8-12a8 8 0 0 1 16 0Z"/><circle cx="12" cy="10" r="3"/></svg>`;
    }

    return L.divIcon({
        className: 'custom-icon',
        html: svg,
        iconSize: type === 'car' ? [32, 32] : [40, 40],
        iconAnchor: type === 'car' ? [16, 16] : [20, 40],
        popupAnchor: [0, -40]
    });
};

const CarIcon = createIcon('#3b82f6', 'car');
const PickupIcon = createIcon('#22c55e', 'pin');
const DestIcon = createIcon('#ef4444', 'pin');
const HotelIcon = createIcon('#f97316', 'hotel');

interface RealMapProps {
    drivers?: Array<{ id: string; location: { lat: number; lng: number; bearing?: number }; status: string }>;
    hotels?: Hotel[];
    pickup?: { lat: number; lng: number } | null;
    destination?: { lat: number; lng: number } | null;
    center?: { lat: number; lng: number };
    zoom?: number;
    showUserLocation?: boolean;
    isDriverView?: boolean;
    route?: RouteData | null;
    showHotels?: boolean;
}

export const RealMap: React.FC<RealMapProps> = ({ 
    drivers = [], 
    hotels = [],
    pickup, 
    destination, 
    center, 
    zoom = 15,
    showUserLocation = true,
    isDriverView = false,
    route,
    showHotels = false
}) => {
    const mapContainerRef = useRef<HTMLDivElement>(null);
    const mapInstanceRef = useRef<L.Map | null>(null);
    const markersRef = useRef<L.LayerGroup | null>(null);
    const driverMarkersRef = useRef<Record<string, L.Marker>>({});
    const routeLayerRef = useRef<L.LayerGroup | null>(null);
    const { isDarkMode, userLocation } = useAppStore();

    // Initialize Map
    useEffect(() => {
        if (!mapContainerRef.current) return;
        if (mapInstanceRef.current) return;

        const map = L.map(mapContainerRef.current, {
            zoomControl: false,
            attributionControl: false
        }).setView([userLocation.lat, userLocation.lng], zoom);

        const tileUrl = isDarkMode 
            ? 'https://{s}.basemaps.cartocdn.com/dark_all/{z}/{x}/{y}{r}.png' 
            : 'https://{s}.basemaps.cartocdn.com/light_all/{z}/{x}/{y}{r}.png';

        L.tileLayer(tileUrl, { maxZoom: 20, subdomains: 'abcd' }).addTo(map);

        markersRef.current = L.layerGroup().addTo(map);
        routeLayerRef.current = L.layerGroup().addTo(map);
        mapInstanceRef.current = map;

        return () => {
            map.remove();
            mapInstanceRef.current = null;
        };
    }, []);

    // Theme Updates
    useEffect(() => {
        const map = mapInstanceRef.current;
        if (!map) return;
        const tileUrl = isDarkMode 
            ? 'https://{s}.basemaps.cartocdn.com/dark_all/{z}/{x}/{y}{r}.png' 
            : 'https://{s}.basemaps.cartocdn.com/light_all/{z}/{x}/{y}{r}.png';

        map.eachLayer((layer) => {
            if (layer instanceof L.TileLayer) map.removeLayer(layer);
        });
        L.tileLayer(tileUrl, { maxZoom: 20, subdomains: 'abcd' }).addTo(map);
    }, [isDarkMode]);

    // Drivers Update (Smooth Transition)
    useEffect(() => {
        const map = mapInstanceRef.current;
        if (!map) return;

        const currentIds = new Set<string>();

        drivers.forEach(driver => {
            currentIds.add(driver.id);
            const pos = new L.LatLng(driver.location.lat, driver.location.lng);

            if (driverMarkersRef.current[driver.id]) {
                // Update position
                driverMarkersRef.current[driver.id].setLatLng(pos);
            } else {
                // Create new
                const marker = L.marker(pos, { icon: CarIcon });
                marker.addTo(map);
                driverMarkersRef.current[driver.id] = marker;
            }
        });

        // Remove old drivers
        Object.keys(driverMarkersRef.current).forEach(id => {
            if (!currentIds.has(id)) {
                driverMarkersRef.current[id].remove();
                delete driverMarkersRef.current[id];
            }
        });

    }, [drivers]);

    // Static Markers & Route Update
    useEffect(() => {
        const map = mapInstanceRef.current;
        const markersLayer = markersRef.current;
        const routeLayer = routeLayerRef.current;

        if (!map || !markersLayer || !routeLayer) return;

        markersLayer.clearLayers();
        routeLayer.clearLayers();

        // Pickup
        if (pickup) {
            L.marker([pickup.lat, pickup.lng], { icon: PickupIcon }).addTo(markersLayer);
        }

        // Destination
        if (destination) {
            L.marker([destination.lat, destination.lng], { icon: DestIcon }).addTo(markersLayer);
        }

        // User Location
        if (showUserLocation && !isDriverView && !pickup) {
             L.marker([userLocation.lat, userLocation.lng], { icon: PickupIcon }).addTo(markersLayer);
        }

        // Hotels Logic
        if (showHotels && hotels) {
            hotels.forEach(hotel => {
                const marker = L.marker([hotel.location.lat, hotel.location.lng], { icon: HotelIcon });
                // Simple popup to select hotel
                const container = document.createElement('div');
                container.innerHTML = `
                    <div style="text-align:center; font-family:sans-serif;">
                        <h3 style="margin:0; font-weight:bold;">${hotel.name}</h3>
                        <p style="margin:2px 0; color:#666;">${hotel.priceRange}</p>
                        <button id="btn-${hotel.id}" style="margin-top:4px; background:#f97316; color:white; border:none; padding:4px 8px; border-radius:4px; cursor:pointer;">Select</button>
                    </div>
                `;
                marker.bindPopup(container).addTo(markersLayer);

                // Add event listener via DOM logic since innerHTML removes react events
                // Using global custom event dispatch for bridge
                container.querySelector(`#btn-${hotel.id}`)?.addEventListener('click', () => {
                    window.dispatchEvent(new CustomEvent('select-hotel', {detail: hotel}));
                });
            });
        }

        // Route
        if (route) {
            const routeColor = isDarkMode ? '#60a5fa' : '#2563eb';
            L.polyline(route.coordinates, {
                color: isDarkMode ? '#000' : '#ccc',
                weight: 7,
                opacity: 0.3,
                className: 'blur-[2px]' 
            }).addTo(routeLayer);

            L.polyline(route.coordinates, {
                color: routeColor,
                weight: 5,
                opacity: 0.8,
                lineCap: 'round',
                lineJoin: 'round',
                dashArray: '1, 10'
            }).addTo(routeLayer);

            if (route.bbox) {
                 map.fitBounds([
                    [route.bbox[0], route.bbox[1]],
                    [route.bbox[2], route.bbox[3]]
                ], { padding: [50, 50] });
            }
        } else {
            const targetCenter: [number, number] = center 
                ? [center.lat, center.lng] 
                : pickup 
                    ? [pickup.lat, pickup.lng] 
                    : [userLocation.lat, userLocation.lng];
            map.flyTo(targetCenter, zoom, { duration: 1.5 });
        }

    }, [pickup, destination, center, zoom, showUserLocation, isDriverView, route, userLocation, isDarkMode, showHotels, hotels]);

    return <div ref={mapContainerRef} className="w-full h-full absolute inset-0 z-0 bg-slate-100 dark:bg-slate-900" />;
};

import React, { useState, useEffect } from 'react';
import { MapBackground } from '../../components/Map/MapBackground';
import { Card } from '../../components/ui/Card';
import { Button } from '../../components/ui/Button';
import { MapPin, Navigation, Car, Building, Plane, Clock, User, MessageCircle, Phone, X, Star, Calendar, Flag } from 'lucide-react';
import { useAppStore } from '../../store';
import { Ride, ServiceType, Hotel } from '../../types';
import { RoutingManager } from '../../services/routing/RoutingManager';
import { socketService } from '../../services/mockSocket';

export const RiderHome: React.FC = () => {
    const { activeRide, startRide, updateRideStatus, addToast, userLocation, drivers, hotels, adminSettings, setRoute, currentRoute } = useAppStore();

    // View States
    const [viewState, setViewState] = useState<'grid' | 'selecting' | 'drivers' | 'negotiating' | 'tracking'>('grid');
    const [selectedService, setSelectedService] = useState<ServiceType>('city');
    const [destination, setDestination] = useState('');
    const [destCoords, setDestCoords] = useState<{lat: number, lng: number} | null>(null);
    const [proposedFare, setProposedFare] = useState<string>('');
    const [isCalculating, setIsCalculating] = useState(false);
    const [selectedDriverId, setSelectedDriverId] = useState<string | null>(null);

    // Listen for Hotel Selection from Map
    useEffect(() => {
        const handleHotelSelect = (e: any) => {
            const hotel = e.detail as Hotel;
            setDestination(hotel.name);
            setDestCoords(hotel.location);
            setViewState('selecting'); // Move to confirmation
        };
        window.addEventListener('select-hotel', handleHotelSelect);
        return () => window.removeEventListener('select-hotel', handleHotelSelect);
    }, []);

    // Actions
    const handleServiceSelect = (service: ServiceType) => {
        setSelectedService(service);
        if (service === 'hotel') {
            setViewState('selecting'); 
        } else {
            setViewState('selecting');
        }
    };

    const handleSetDestination = async () => {
        if (!destination) return;
        setIsCalculating(true);

        // Mock Geocoding if not set by Hotel click
        let target = destCoords;
        if (!target) {
            target = { lat: 34.5650, lng: 69.2120 }; // Default to Airport
            setDestCoords(target);
        }

        try {
            const routeData = await RoutingManager.getRoute(userLocation, target, adminSettings);
            setRoute(routeData);
            setViewState('drivers');

            // Auto-calculate suggested fare
            const distKm = routeData.distance / 1000;
            const suggested = Math.round(distKm * 20 + adminSettings.pricing.minFare);
            setProposedFare(suggested.toString());
        } catch (error) {
            addToast('error', "Could not calculate route.");
        } finally {
            setIsCalculating(false);
        }
    };

    const handleSelectDriver = (driverId: string, baseFare: number) => {
        setSelectedDriverId(driverId);
        setProposedFare(Math.max(parseInt(proposedFare) || 0, baseFare).toString());
    };

    const handleRequestRide = () => {
        if (!selectedDriverId) return;

        const driver = drivers.find(d => d.id === selectedDriverId);
        const fare = parseInt(proposedFare);

        const newRide: Ride = {
            id: `ride_${Date.now()}`,
            pickup: 'Current Location',
            destination: destination,
            pickupLocation: userLocation,
            destinationLocation: destCoords!,
            fare: fare,
            proposedFare: fare,
            status: 'requested',
            riderId: 'u1',
            driverId: selectedDriverId,
            serviceType: selectedService,
            timestamp: Date.now(),
            distance: currentRoute?.distance || 0,
            duration: currentRoute?.duration || 0,
            route: currentRoute!
        };

        startRide(newRide);
        socketService.emit('request_ride', newRide); // Send to mock socket
        setViewState('tracking');
    };

    const resetFlow = () => {
        setViewState('grid');
        setDestCoords(null);
        setRoute(null);
        setDestination('');
        startRide(null);
        setSelectedDriverId(null);
    };

    // Sub-Components
    const ServiceGrid = () => (
        <div className="absolute bottom-0 left-0 right-0 p-6 bg-white dark:bg-dark-950 rounded-t-3xl shadow-[0_-10px_40px_rgba(0,0,0,0.1)] z-20 animate-in slide-in-from-bottom-10 duration-300">
            <h2 className="text-xl font-bold text-dark-900 dark:text-white mb-6">Choose Service</h2>
            <div className="grid grid-cols-3 gap-4 mb-20 md:mb-4">
                {[
                    { id: 'city', label: 'City Taxi', icon: <Car size={28} />, color: 'bg-blue-100 text-blue-600 dark:bg-blue-600/20 dark:text-blue-400' },
                    { id: 'intercity', label: 'Intercity', icon: <MapPin size={28} />, color: 'bg-green-100 text-green-600 dark:bg-green-600/20 dark:text-green-400' },
                    { id: 'airport', label: 'Airport', icon: <Plane size={28} />, color: 'bg-purple-100 text-purple-600 dark:bg-purple-600/20 dark:text-purple-400' },
                    { id: 'hotel', label: 'Hotel + Taxi', icon: <Building size={28} />, color: 'bg-orange-100 text-orange-600 dark:bg-orange-600/20 dark:text-orange-400' },
                    { id: 'scheduled', label: 'Schedule', icon: <Clock size={28} />, color: 'bg-slate-100 text-slate-600 dark:bg-slate-700/50 dark:text-slate-400' },
                    { id: 'subscription', label: 'Subs', icon: <User size={28} />, color: 'bg-slate-100 text-slate-600 dark:bg-slate-700/50 dark:text-slate-400' },
                ].map((item) => (
                    <button 
                        key={item.id} 
                        onClick={() => handleServiceSelect(item.id as ServiceType)}
                        className="flex flex-col items-center justify-center p-4 rounded-2xl bg-dark-50 dark:bg-white/5 active:scale-95 transition-transform hover:bg-dark-100 dark:hover:bg-white/10"
                    >
                        <div className={`w-14 h-14 rounded-full flex items-center justify-center mb-3 ${item.color}`}>
                            {item.icon}
                        </div>
                        <span className="text-xs font-bold text-dark-700 dark:text-dark-300">{item.label}</span>
                    </button>
                ))}
            </div>
        </div>
    );

    const LocationSelector = () => (
        <div className="absolute top-20 left-4 right-4 z-20 animate-in slide-in-from-top-5">
            <Card className="shadow-xl">
                <div className="flex items-center gap-2 mb-4">
                     <button onClick={resetFlow}><X size={20} className="text-dark-400" /></button>
                     <h3 className="font-bold text-lg text-dark-900 dark:text-white capitalize">{selectedService} Ride</h3>
                </div>
                <div className="space-y-4">
                    <div className="relative">
                        <div className="absolute left-3 top-3 w-2 h-2 rounded-full bg-green-500"></div>
                        <input type="text" value="Current Location" readOnly className="w-full pl-8 py-2 border-b border-dark-100 dark:border-white/10 bg-transparent text-sm font-medium text-dark-900 dark:text-white" />
                    </div>
                    <div className="relative">
                        <div className="absolute left-3 top-3 w-2 h-2 rounded-full bg-red-500"></div>
                        <input 
                            type="text" 
                            placeholder={selectedService === 'hotel' ? "Select Hotel on Map..." : "Where to?"}
                            className="w-full pl-8 py-2 border-b border-brand-500 bg-transparent text-lg font-bold text-dark-900 dark:text-white focus:outline-none"
                            value={destination}
                            onChange={(e) => setDestination(e.target.value)} 
                        />
                    </div>
                    <Button onClick={handleSetDestination} isLoading={isCalculating} className="w-full" disabled={!destination}>
                        {selectedService === 'hotel' ? 'Find Drivers to Hotel' : 'Set Destination'}
                    </Button>
                </div>
            </Card>
        </div>
    );

    const DriverSelectionPanel = () => (
        <div className="absolute bottom-0 left-0 right-0 bg-white dark:bg-dark-950 rounded-t-3xl shadow-[0_-10px_50px_rgba(0,0,0,0.2)] z-30 flex flex-col h-[70vh] animate-in slide-in-from-bottom-20 duration-300">
            <div className="p-4 border-b border-dark-100 dark:border-white/5 flex flex-col gap-3">
                <div className="flex justify-between items-center">
                    <h3 className="font-bold text-lg text-dark-900 dark:text-white">Nearby Drivers</h3>
                    <button onClick={resetFlow}><X size={20} className="text-dark-400" /></button>
                </div>

                <div className="flex items-center justify-between bg-brand-50 dark:bg-brand-900/20 p-3 rounded-xl border border-brand-200 dark:border-brand-500/30">
                    <span className="text-sm font-bold text-brand-700 dark:text-brand-300">Your Offer (AFN)</span>
                    <div className="flex items-center gap-2">
                        <button onClick={() => setProposedFare((parseInt(proposedFare)-10).toString())} className="w-8 h-8 rounded-full bg-white dark:bg-white/10 flex items-center justify-center font-bold text-dark-600 dark:text-white">-</button>
                        <input 
                            type="number" 
                            className="w-20 bg-transparent text-center font-black text-xl text-brand-700 dark:text-white focus:outline-none" 
                            value={proposedFare} 
                            onChange={(e) => setProposedFare(e.target.value)} 
                        />
                        <button onClick={() => setProposedFare((parseInt(proposedFare)+10).toString())} className="w-8 h-8 rounded-full bg-white dark:bg-white/10 flex items-center justify-center font-bold text-dark-600 dark:text-white">+</button>
                    </div>
                </div>
            </div>

            <div className="flex-1 overflow-y-auto p-4 space-y-3 pb-24">
                {drivers.map(driver => (
                    <div 
                        key={driver.id} 
                        onClick={() => handleSelectDriver(driver.id, driver.baseFare)}
                        className={`relative flex items-center p-3 rounded-xl border-2 cursor-pointer transition-all ${selectedDriverId === driver.id ? 'border-brand-500 bg-brand-50 dark:bg-brand-900/20' : 'border-dark-100 dark:border-white/5 hover:border-brand-200 dark:hover:border-white/20'}`}
                    >
                        <div className="w-14 h-14 rounded-full bg-dark-200 dark:bg-dark-800 flex items-center justify-center mr-3 relative shrink-0">
                            <Car size={28} className="text-dark-500" />
                            <div className="absolute -bottom-1 -right-1 bg-green-500 text-[10px] text-white px-1.5 py-0.5 rounded-full border-2 border-white dark:border-dark-900 font-bold">
                                {driver.eta}m
                            </div>
                        </div>
                        <div className="flex-1">
                            <div className="flex justify-between items-center mb-1">
                                <span className="font-bold text-dark-900 dark:text-white text-lg">{driver.name}</span>
                                <span className="font-black text-dark-900 dark:text-white">؋{driver.baseFare}</span>
                            </div>
                            <div className="flex justify-between items-center text-xs text-dark-500 dark:text-dark-400">
                                <span>{driver.vehicle} • {driver.type.toUpperCase()}</span>
                                <span className="flex items-center text-orange-500 font-bold"><Star size={12} fill="currentColor" className="mr-1"/> {driver.rating.toFixed(1)}</span>
                            </div>
                        </div>
                    </div>
                ))}
            </div>

            <div className="absolute bottom-0 left-0 right-0 p-4 border-t border-dark-100 dark:border-white/5 bg-white dark:bg-dark-950 mb-safe">
                 <Button size="lg" className="w-full h-14 text-lg" disabled={!selectedDriverId} onClick={handleRequestRide}>
                    Request Ride {selectedDriverId && `(؋${proposedFare})`}
                 </Button>
            </div>
        </div>
    );

    const ActiveTripPanel = () => {
        if (!activeRide) return null;
        const isPending = activeRide.status === 'requested';

        return (
            <div className="absolute bottom-0 left-0 right-0 bg-white dark:bg-dark-950 rounded-t-3xl shadow-[0_-10px_50px_rgba(0,0,0,0.2)] z-30 p-6 mb-16 md:mb-0 animate-in slide-in-from-bottom-20 duration-300">
                 {isPending ? (
                     <div className="text-center py-6">
                         <div className="w-16 h-16 rounded-full border-4 border-brand-500 border-t-transparent animate-spin mx-auto mb-4"></div>
                         <h2 className="text-xl font-bold text-dark-900 dark:text-white mb-1">Contacting Driver...</h2>
                         <p className="text-dark-500">Waiting for acceptance</p>
                         <Button variant="ghost" className="mt-4 text-red-500" onClick={() => updateRideStatus('cancelled')}>Cancel Request</Button>
                     </div>
                 ) : (
                     <>
                        <div className="flex items-center justify-between mb-6">
                            <div>
                                <div className="text-xs font-bold text-brand-600 uppercase tracking-wider mb-1">
                                    {activeRide.status === 'accepted' ? 'Driver Arriving' : 'On Trip'}
                                </div>
                                <h2 className="text-2xl font-bold text-dark-900 dark:text-white">Heading to Destination</h2>
                            </div>
                            <div className="text-right">
                                <div className="text-2xl font-black text-dark-900 dark:text-white">12 <span className="text-sm font-medium text-dark-500">min</span></div>
                                <div className="text-xs text-dark-500">Estimated Arrival</div>
                            </div>
                        </div>

                        <div className="flex items-center gap-4 bg-dark-50 dark:bg-white/5 p-4 rounded-xl mb-6 border border-dark-100 dark:border-white/5">
                            <div className="w-12 h-12 rounded-full bg-dark-200 dark:bg-dark-800 overflow-hidden">
                                <img src="https://ui-avatars.com/api/?name=Driver&background=random" className="w-full h-full" alt="driver"/>
                            </div>
                            <div className="flex-1">
                                <div className="font-bold text-dark-900 dark:text-white">Ahmad Driver</div>
                                <div className="text-xs text-dark-500">Toyota Corolla • <span className="font-mono bg-dark-200 dark:bg-white/10 px-1 rounded">KBL-992</span></div>
                            </div>
                            <div className="flex gap-2">
                                <button className="w-10 h-10 rounded-full bg-white dark:bg-white/10 flex items-center justify-center text-brand-600 dark:text-brand-400 shadow-sm border border-dark-100 dark:border-white/5"><MessageCircle size={20}/></button>
                                <button className="w-10 h-10 rounded-full bg-white dark:bg-white/10 flex items-center justify-center text-green-600 dark:text-green-400 shadow-sm border border-dark-100 dark:border-white/5"><Phone size={20}/></button>
                            </div>
                        </div>

                        <div className="flex gap-3">
                            <Button variant="secondary" className="flex-1" icon={<Flag size={18}/>}>Share</Button>
                            <Button variant="danger" className="flex-1" onClick={() => { updateRideStatus('cancelled'); setTimeout(resetFlow, 1000); }}>Cancel</Button>
                        </div>
                     </>
                 )}
            </div>
        );
    };

    if (activeRide && activeRide.status !== 'cancelled' && activeRide.status !== 'completed') {
        return (
            <div className="relative h-full w-full">
                <MapBackground pickup={activeRide.pickupLocation} destination={activeRide.destinationLocation} route={activeRide.route} />
                <ActiveTripPanel />
            </div>
        );
    }

    return (
        <div className="relative h-full w-full">
            <MapBackground 
                pickup={viewState !== 'grid' ? userLocation : undefined} 
                destination={destCoords} 
                route={currentRoute}
                showHotels={selectedService === 'hotel'} 
                hotels={hotels}
            />

            <div className="absolute top-4 left-4 right-4 z-10 flex justify-between pointer-events-none">
                <button className="pointer-events-auto w-10 h-10 bg-white dark:bg-dark-900 rounded-full shadow-lg flex items-center justify-center text-dark-900 dark:text-white">
                    <Navigation size={20} />
                </button>
            </div>

            {viewState === 'grid' && <ServiceGrid />}
            {viewState === 'selecting' && <LocationSelector />}
            {viewState === 'drivers' && <DriverSelectionPanel />}
        </div>
    );
};

import React, { useState, useEffect } from 'react';
import { MapBackground } from '../../components/Map/MapBackground';
