            {/* Active Ride Controls */}
            {activeRide && (
                <div className="absolute bottom-0 left-0 right-0 bg-white dark:bg-dark-900 p-6 pb-24 rounded-t-3xl shadow-[0_-10px_40px_rgba(0,0,0,0.2)] z-20">
