                 <Button size="lg" className="w-full h-14 text-lg shadow-xl" disabled={!selectedDriverId} onClick={handleRequestRide}>
                    Request Ride
                 </Button>
            </div>
        </div>
    );

    const ActiveTripPanel = () => {
        if (!activeRide) return null;
        const isPending = activeRide.status === 'requested';

        return (
            <div className="absolute bottom-0 left-0 right-0 bg-white dark:bg-dark-950 rounded-t-3xl shadow-[0_-10px_50px_rgba(0,0,0,0.2)] z-30 p-6 mb-16 md:mb-0 animate-in slide-in-from-bottom-20 duration-300">
                 {isPending ? (
                     <div className="text-center py-6">
                         <div className="w-16 h-16 rounded-full border-4 border-brand-500 border-t-transparent animate-spin mx-auto mb-4"></div>
                         <h2 className="text-xl font-bold text-dark-900 dark:text-white mb-1">Contacting Driver...</h2>
                         <p className="text-dark-500">Waiting for acceptance</p>
                         <Button variant="ghost" className="mt-4 text-red-500" onClick={() => updateRideStatus('cancelled')}>Cancel Request</Button>
                     </div>
                 ) : (
                     <>
                        <div className="flex items-center justify-between mb-6">
                            <div>
                                <div className="text-xs font-bold text-brand-600 uppercase tracking-wider mb-1">
                                    {activeRide.status === 'accepted' ? 'Driver Arriving' : 'On Trip'}
                                </div>
                                <h2 className="text-2xl font-bold text-dark-900 dark:text-white">Heading to Destination</h2>
                            </div>
                            <div className="text-right">
                                <div className="text-2xl font-black text-dark-900 dark:text-white">12 <span className="text-sm font-medium text-dark-500">min</span></div>
                            </div>
                        </div>

                        <div className="flex items-center gap-4 bg-dark-50 dark:bg-white/5 p-4 rounded-xl mb-6 border border-dark-100 dark:border-white/5">
                            <div className="w-12 h-12 rounded-full bg-dark-200 dark:bg-dark-800 overflow-hidden">
                                <img src="https://ui-avatars.com/api/?name=Driver&background=random" className="w-full h-full" alt="driver"/>
                            </div>
                            <div className="flex-1">
                                <div className="font-bold text-dark-900 dark:text-white">Ahmad Driver</div>
                                <div className="text-xs text-dark-500">Toyota Corolla • <span className="font-mono bg-dark-200 dark:bg-white/10 px-1 rounded">KBL-992</span></div>
                            </div>
                            <div className="flex gap-2">
                                <button className="w-10 h-10 rounded-full bg-white dark:bg-white/10 flex items-center justify-center text-brand-600 dark:text-brand-400 shadow-sm border border-dark-100 dark:border-white/5"><MessageCircle size={20}/></button>
                                <button className="w-10 h-10 rounded-full bg-white dark:bg-white/10 flex items-center justify-center text-green-600 dark:text-green-400 shadow-sm border border-dark-100 dark:border-white/5"><Phone size={20}/></button>
                            </div>
                        </div>

                        <div className="flex gap-3">
                            <Button variant="secondary" className="flex-1" icon={<Flag size={18}/>}>Share</Button>
                            <Button variant="danger" className="flex-1" onClick={() => { updateRideStatus('cancelled'); setTimeout(resetFlow, 1000); }}>Cancel</Button>
                        </div>
                     </>
                 )}
            </div>
        );
    };

    // --- Main Render ---

    if (activeRide && activeRide.status !== 'cancelled' && activeRide.status !== 'completed') {
        return (
            <div className="relative h-full w-full">
                <MapBackground pickup={activeRide.pickupLocation} destination={activeRide.destinationLocation} route={activeRide.route} />
                <ActiveTripPanel />
            </div>
        );
    }

    return (
        <div className="relative h-full w-full bg-slate-100 dark:bg-slate-900">
            {/* Map */}
            <MapBackground 
                pickup={viewState !== 'grid' && viewState !== 'selecting' ? userLocation : undefined} 
                destination={destCoords} 
                route={currentRoute}
                showHotels={selectedService === 'hotel'} 
                hotels={hotels}
                onCameraChange={handleCameraChange}
                center={mapCenter}
                zoom={selectedService === 'hotel' ? 13 : 16}
            />

            {/* Recenter Button (Only in grid/selecting modes) */}
            <div className="absolute top-4 right-4 z-10 pointer-events-auto">
                <button 
                    onClick={() => setMapCenter(userLocation)}
                    className="w-10 h-10 bg-white dark:bg-dark-900 rounded-full shadow-lg flex items-center justify-center text-dark-900 dark:text-white active:scale-95 transition-transform"
                >
                    <Navigation size={20} />
                </button>
            </div>

            {/* UI Layers */}
            {viewState === 'grid' && <ServiceGrid />}
            {viewState === 'selecting' && <MapSelectionOverlay />}
            {viewState === 'drivers' && <DriverSelectionPanel />}
        </div>
    );
};

