export const useAppStore = create<AppState>()(
    persist(
        (set, get) => ({
            appMode: 'landing',
            user: null, 
            currentRole: 'rider',
            activeRide: null,
            pastTrips: [],
            transactions: INITIAL_TRANSACTIONS,
            notifications: INITIAL_NOTIFICATIONS,
            isDarkMode: true,
            language: 'en',
            toasts: [],
            currentView: 'home',

            adminSettings: DEFAULT_ADMIN_SETTINGS,

            userLocation: DEFAULT_LOCATION,
            drivers: [],
            hotels: INITIAL_HOTELS,
            currentRoute: null,

            setAppMode: (mode) => set({ appMode: mode }),
            setUser: (user) => set({ user, appMode: 'app' }),
            setRole: (role) => set({ currentRole: role, currentView: 'home' }), 
            setView: (view) => set({ currentView: view }),

            startRide: (ride) => set((state) => ({ 
                activeRide: ride, 
                currentRoute: ride?.route || state.currentRoute 
            })),

            updateRideStatus: (status) => set((state) => ({
                activeRide: state.activeRide ? { ...state.activeRide, status } : null
            })),

            completeRide: () => {
                const { activeRide, adminSettings } = get();
                if (!activeRide) return;

                const fare = activeRide.fare;
                const commission = (fare * adminSettings.pricing.commissionRate) / 100;
                const driverEarnings = fare - commission;

                // Create Transaction Logic
                // If Driver: Credit
                // If Rider: Debit (We simulate wallet deduction)

                const newTx: Transaction = {
                    id: `tx_${Date.now()}`,
                    amount: get().currentRole === 'driver' ? driverEarnings : fare,
                    type: get().currentRole === 'driver' ? 'credit' : 'debit',
                    date: Date.now(),
                    description: `Trip to ${activeRide.destination}`,
                    status: 'completed'
                };

                const completedRide: Ride = { ...activeRide, status: 'completed' };

                set((state) => ({
                    pastTrips: [completedRide, ...state.pastTrips],
                    activeRide: null,
                    currentRoute: null,
                    transactions: [newTx, ...state.transactions],
                    user: state.user ? {
                        ...state.user,
                        balance: (state.user.balance || 0) + (newTx.type === 'credit' ? newTx.amount : -newTx.amount),
                        totalTrips: (state.user.totalTrips || 0) + 1
                    } : null
                }));
            },

            toggleDarkMode: () => set((state) => ({ isDarkMode: !state.isDarkMode })),
            setLanguage: (lang) => set({ language: lang }),
            logout: () => set({ user: null, activeRide: null, appMode: 'landing', currentView: 'home', currentRoute: null }),

            markNotificationRead: (id) => set(state => ({
                notifications: state.notifications.map(n => n.id === id ? { ...n, read: true } : n)
            })),

            markAllNotificationsRead: () => set(state => ({
                notifications: state.notifications.map(n => ({ ...n, read: true }))
            })),

            updateUserLocation: (loc) => set({ userLocation: loc }),

            updateDrivers: (drivers) => set({ drivers }),

            registerDriver: (driver) => set((state) => {
                const filtered = state.drivers.filter(d => d.id !== driver.id);
                return { drivers: [...filtered, driver] };
            }),

            generateLocalDrivers: (center) => {
                const existingRealDrivers = get().drivers.filter(d => d.id === 'real_driver'); 

                const newDrivers = Array.from({ length: 5 }).map((_, i) => ({
                    id: `sim_${Date.now()}_${i}`,
                    name: `Driver ${i + 1}`,
                    vehicle: i % 2 === 0 ? 'Toyota Corolla' : 'Honda Civic',
                    rating: 4.5 + Math.random() * 0.5,
                    location: {
                        lat: center.lat + (Math.random() - 0.5) * 0.015,
                        lng: center.lng + (Math.random() - 0.5) * 0.015,
                        bearing: Math.random() * 360
                    },
                    status: (Math.random() > 0.3 ? 'available' : 'busy') as 'available' | 'busy',
                    type: ['eco', 'plus', 'lux'][Math.floor(Math.random() * 3)] as 'eco' | 'plus' | 'lux',
                    baseFare: 50 + Math.floor(Math.random() * 20),
                    perKmRate: 20 + Math.floor(Math.random() * 10),
                    eta: Math.floor(Math.random() * 10) + 2
                }));

                set({ drivers: [...existingRealDrivers, ...newDrivers] });
            },

            setRoute: (route) => set({ currentRoute: route }),

            updateAdminSettings: (newSettings) => set((state) => ({
                adminSettings: { ...state.adminSettings, ...newSettings }
            })),

            addHotel: (hotel) => set((state) => ({ hotels: [...state.hotels, hotel] })),
            removeHotel: (id) => set((state) => ({ hotels: state.hotels.filter(h => h.id !== id) })),

            addToast: (type, message) => {
                const id = Math.random().toString(36).substring(7);
                set((state) => ({ toasts: [...state.toasts, { id, type, message }] }));
                setTimeout(() => get().removeToast(id), 4000);
            },
            removeToast: (id) => set((state) => ({ toasts: state.toasts.filter(t => t.id !== id) }))
        }),
        {
            name: 'itaxi-storage',
            partialize: (state) => ({ 
                isDarkMode: state.isDarkMode, 
                language: state.language,
                adminSettings: state.adminSettings,
                user: state.user,
                hotels: state.hotels,
                pastTrips: state.pastTrips,
                transactions: state.transactions,
                notifications: state.notifications
            }),
        }
    )
);

import { useAppStore } from '../store';
import { Location } from '../types';

class MockSocketService {
    private isConnected: boolean = false;
    private listeners: Record<string, Function[]> = {};
    private simulationInterval: any;

    connect() {
        if (this.isConnected) return;
        console.log("🔌 Connecting to iTaxi Realtime Server...");
        setTimeout(() => {
            this.isConnected = true;
            console.log("✅ Connected securely.");
            this.emit('connection_status', 'connected');
            this.startGlobalSimulation();
        }, 800);
    }

    disconnect() {
        this.isConnected = false;
        if (this.simulationInterval) clearInterval(this.simulationInterval);
        console.log("❌ Disconnected.");
    }

    on(event: string, callback: Function) {
        if (!this.listeners[event]) {
            this.listeners[event] = [];
        }
        this.listeners[event].push(callback);
    }

    off(event: string, callback: Function) {
        if (!this.listeners[event]) return;
        this.listeners[event] = this.listeners[event].filter(cb => cb !== callback);
    }

    emit(event: string, data: any) {
        // --- Simulation Logic ---

        // 1. Rider requests a ride
        if (event === 'request_ride') {
            setTimeout(() => {
                this.triggerListeners('new_request', data);
            }, 1000);

            // Auto accept if simulation
            setTimeout(() => {
                const store = useAppStore.getState();
                if (store.activeRide?.id === data.id && store.activeRide.status === 'requested') {
                    store.updateRideStatus('accepted');
                    store.addToast('success', 'Driver accepted your ride!');
                }
            }, 8000);
        }

        // 2. Driver accepts request
        if (event === 'accept_ride') {
            const store = useAppStore.getState();
            if (store.activeRide?.id === data.rideId) {
                store.updateRideStatus('accepted');
                this.triggerListeners('ride_status_update', { status: 'accepted', rideId: data.rideId });
            }
        }

        // 3. Status Changes
        if (event === 'update_status') {
            const store = useAppStore.getState();
             if (store.activeRide?.id === data.rideId) {
                store.updateRideStatus(data.status);
                this.triggerListeners('ride_status_update', { status: data.status, rideId: data.rideId });
             }
        }
    }

    private triggerListeners(event: string, data: any) {
        if (this.listeners[event]) {
            this.listeners[event].forEach(cb => cb(data));
        }
    }

    private lerp(start: number, end: number, t: number) {
        return start * (1 - t) + end * t;
    }

    private moveTowards(current: Location, target: Location, speed: number): Location {
        const dx = target.lat - current.lat;
        const dy = target.lng - current.lng;
        const distance = Math.sqrt(dx * dx + dy * dy);

        if (distance < speed) return target;

        const ratio = speed / distance;
        return {
            lat: current.lat + dx * ratio,
            lng: current.lng + dy * ratio,
            bearing: Math.atan2(dy, dx) * (180 / Math.PI)
        };
    }

    private startGlobalSimulation() {
        if(this.simulationInterval) clearInterval(this.simulationInterval);

        this.simulationInterval = setInterval(() => {
            const store = useAppStore.getState();
            const { activeRide, drivers } = store;

            // 1. Simulate Driver Movement
            const updatedDrivers = drivers.map(driver => {
                // If this driver is involved in an active ride
                if (activeRide && activeRide.driverId === driver.id) {
                    let target: Location | null = null;

                    if (activeRide.status === 'accepted') {
                        target = activeRide.pickupLocation;
                    } else if (activeRide.status === 'in_progress') {
                        target = activeRide.destinationLocation;
                    }

                    if (target) {
                        const newLoc = this.moveTowards(driver.location, target, 0.0003); // Speed factor

                        // Check if arrived
                        const distToTarget = Math.sqrt(Math.pow(newLoc.lat - target.lat, 2) + Math.pow(newLoc.lng - target.lng, 2));

                        // Auto-update status for simulation if close
                        if (distToTarget < 0.0005 && activeRide.driverId.startsWith('sim_')) {
                            if (activeRide.status === 'accepted') {
                                store.updateRideStatus('arrived');
                                store.addToast('info', 'Driver has arrived!');
                            }
                            // Don't auto-complete 'in_progress' to let user see the end
                        }

                        return { ...driver, location: newLoc };
                    }
                } else if (driver.status === 'available' && driver.id !== 'real_driver') {
                    // Random jitter for idle drivers
                    return {
                        ...driver,
                        location: {
                            lat: driver.location.lat + (Math.random() - 0.5) * 0.0001,
                            lng: driver.location.lng + (Math.random() - 0.5) * 0.0001,
                            bearing: (driver.location.bearing || 0) + (Math.random() - 0.5) * 10
                        }
                    };
                }
                return driver;
            });

            store.updateDrivers(updatedDrivers);

        }, 2000);
    }
}

