                        )}

                        {activeRide.status === 'in_progress' && (
                            <Button 
                                className="h-14 text-lg w-full bg-red-600 text-white" 
                                onClick={() => handleStatusUpdate('completed')}
                                icon={<Flag size={20}/>}
                            >
                                Complete Trip
                            </Button>
                        )}
                    </div>
                </div>
            )}
        </div>
    );
};

