export const useAppStore = create<AppState>()(
    persist(
        (set, get) => ({
            appMode: 'landing',
            user: null, 
            currentRole: 'rider',
            activeRide: null,
            pastTrips: [],
            transactions: INITIAL_TRANSACTIONS,
            notifications: INITIAL_NOTIFICATIONS,
            isDarkMode: true,
            language: 'en',
            toasts: [],
            currentView: 'home',
            chatState: { isOpen: false, recipientId: '', recipientName: '', recipientRole: '' },

            adminSettings: DEFAULT_ADMIN_SETTINGS,

            userLocation: DEFAULT_LOCATION,
            drivers: [],
            hotels: INITIAL_HOTELS,
            currentRoute: null,

            setAppMode: (mode) => set({ appMode: mode }),
            setUser: (user) => set({ user, appMode: 'app' }),
            setRole: (role) => set({ currentRole: role, currentView: 'home' }), 
            setView: (view) => set({ currentView: view }),

            startRide: (ride) => set((state) => ({ 
                activeRide: ride, 
                currentRoute: ride?.route || state.currentRoute 
            })),

            updateRideStatus: (status) => set((state) => ({
                activeRide: state.activeRide ? { ...state.activeRide, status } : null
            })),

            completeRide: () => {
                const { activeRide, adminSettings } = get();
                if (!activeRide) return;

                const fare = activeRide.fare;
                const commission = (fare * adminSettings.pricing.commissionRate) / 100;
                const driverEarnings = fare - commission;

                const newTx: Transaction = {
                    id: `tx_${Date.now()}`,
                    amount: get().currentRole === 'driver' ? driverEarnings : fare,
                    type: get().currentRole === 'driver' ? 'credit' : 'debit',
                    date: Date.now(),
                    description: `Trip to ${activeRide.destination}`,
                    status: 'completed'
                };

                const completedRide: Ride = { ...activeRide, status: 'completed' };

                set((state) => ({
                    pastTrips: [completedRide, ...state.pastTrips],
                    activeRide: null,
                    currentRoute: null,
                    transactions: [newTx, ...state.transactions],
                    user: state.user ? {
                        ...state.user,
                        balance: (state.user.balance || 0) + (newTx.type === 'credit' ? newTx.amount : -newTx.amount),
                        totalTrips: (state.user.totalTrips || 0) + 1
                    } : null
                }));
            },

            toggleDarkMode: () => set((state) => ({ isDarkMode: !state.isDarkMode })),
            setLanguage: (lang) => set({ language: lang }),
            logout: () => set({ user: null, activeRide: null, appMode: 'landing', currentView: 'home', currentRoute: null }),

            openChat: (recipientId, name, role) => set({ chatState: { isOpen: true, recipientId, recipientName: name, recipientRole: role } }),
            closeChat: () => set((state) => ({ chatState: { ...state.chatState, isOpen: false } })),

            markNotificationRead: (id) => set(state => ({
                notifications: state.notifications.map(n => n.id === id ? { ...n, read: true } : n)
            })),

            markAllNotificationsRead: () => set(state => ({
                notifications: state.notifications.map(n => ({ ...n, read: true }))
            })),

            updateUserLocation: (loc) => set({ userLocation: loc }),

            updateDrivers: (drivers) => set({ drivers }),

            registerDriver: (driver) => set((state) => {
                const filtered = state.drivers.filter(d => d.id !== driver.id);
                return { drivers: [...filtered, driver] };
            }),

            generateLocalDrivers: (center) => {
                const existingRealDrivers = get().drivers.filter(d => d.id === 'real_driver'); 

                const newDrivers = Array.from({ length: 5 }).map((_, i) => ({
                    id: `sim_${Date.now()}_${i}`,
                    name: `Driver ${i + 1}`,
                    vehicle: i % 2 === 0 ? 'Toyota Corolla' : 'Honda Civic',
                    rating: 4.5 + Math.random() * 0.5,
                    location: {
                        lat: center.lat + (Math.random() - 0.5) * 0.015,
                        lng: center.lng + (Math.random() - 0.5) * 0.015,
                        bearing: Math.random() * 360
                    },
                    status: (Math.random() > 0.3 ? 'available' : 'busy') as 'available' | 'busy',
                    type: ['eco', 'plus', 'lux'][Math.floor(Math.random() * 3)] as 'eco' | 'plus' | 'lux',
                    baseFare: 50 + Math.floor(Math.random() * 20),
                    perKmRate: 20 + Math.floor(Math.random() * 10),
                    eta: Math.floor(Math.random() * 10) + 2
                }));

                set({ drivers: [...existingRealDrivers, ...newDrivers] });
            },

            setRoute: (route) => set({ currentRoute: route }),

            updateAdminSettings: (newSettings) => set((state) => ({
                adminSettings: { ...state.adminSettings, ...newSettings }
            })),

            addHotel: (hotel) => set((state) => ({ hotels: [...state.hotels, hotel] })),
            removeHotel: (id) => set((state) => ({ hotels: state.hotels.filter(h => h.id !== id) })),

            addToast: (type, message) => {
                const id = Math.random().toString(36).substring(7);
                set((state) => ({ toasts: [...state.toasts, { id, type, message }] }));
                setTimeout(() => get().removeToast(id), 4000);
            },
            removeToast: (id) => set((state) => ({ toasts: state.toasts.filter(t => t.id !== id) }))
        }),
        {
            name: 'itaxi-storage',
            partialize: (state) => ({ 
                isDarkMode: state.isDarkMode, 
                language: state.language,
                adminSettings: state.adminSettings,
                user: state.user,
                hotels: state.hotels,
                pastTrips: state.pastTrips,
                transactions: state.transactions,
                notifications: state.notifications
            }),
        }
    )
);

