import { AdminSettings } from './pages/Admin/AdminSettings';
import { WalletPage } from './pages/Shared/WalletPage';
import { SettingsPage } from './pages/Shared/SettingsPage';
import { ActivityPage } from './pages/Shared/ActivityPage';
import { SupportPage } from './pages/Shared/SupportPage';
import { NotificationsPage } from './pages/Shared/NotificationsPage';
import { MessagesPage } from './pages/Shared/MessagesPage';
import { LandingPage } from './pages/Landing/LandingPage';
import { LoginPage } from './pages/Auth/LoginPage';
import { ToastContainer } from './components/ui/ToastContainer';
import { RatingModal } from './components/Ride/RatingModal';
import { ChatSheet } from './components/Chat/ChatSheet';
import { useAppStore } from './store';
import { socketService } from './services/mockSocket';

const App: React.FC = () => {
    // Select specific state slices to avoid re-rendering App on every store change
    const user = useAppStore((state) => state.user);
    const currentRole = useAppStore((state) => state.currentRole);
    const currentView = useAppStore((state) => state.currentView);
    const appMode = useAppStore((state) => state.appMode);
    const isDarkMode = useAppStore((state) => state.isDarkMode);
    const language = useAppStore((state) => state.language);
    const chatState = useAppStore((state) => state.chatState);
    const closeChat = useAppStore((state) => state.closeChat);

    // Map actions
    const updateUserLocation = useAppStore((state) => state.updateUserLocation);
    const generateLocalDrivers = useAppStore((state) => state.generateLocalDrivers);
    const addToast = useAppStore((state) => state.addToast);

    // Sync Dark Mode Class
    useEffect(() => {
        if (isDarkMode) {
            document.documentElement.classList.add('dark');
        } else {
            document.documentElement.classList.remove('dark');
        }
    }, [isDarkMode]);

    // Sync Language & Direction
    useEffect(() => {
        if (language === 'fa') {
            document.documentElement.dir = 'rtl';
            document.documentElement.lang = 'fa';
            document.body.classList.add('font-fa');
            document.body.classList.remove('font-sans');
        } else {
            document.documentElement.dir = 'ltr';
            document.documentElement.lang = 'en';
            document.body.classList.add('font-sans');
            document.body.classList.remove('font-fa');
        }
    }, [language]);

    useEffect(() => {
        socketService.connect();

        // --- Geolocation Logic ---
        if (navigator.geolocation) {
            navigator.geolocation.getCurrentPosition(
                (position) => {
                    const { latitude, longitude } = position.coords;
                    const newLocation = { lat: latitude, lng: longitude };

                    console.log("📍 GPS Location Found:", newLocation);

                    // Update user location in store
                    updateUserLocation(newLocation);

                    // Spawn new drivers around this real location
                    generateLocalDrivers(newLocation);

                    addToast('success', 'Location updated to GPS coordinates');
                },
                (error) => {
                    console.error("Geolocation error:", error);
                    addToast('warning', 'Could not fetch GPS. Using default location.');
                },
                { enableHighAccuracy: true, timeout: 15000, maximumAge: 0 }
            );
        } else {
            addToast('error', 'Geolocation is not supported by this browser.');
        }

        return () => {
            socketService.disconnect();
        };
    }, []);

    // 1. Landing Page Mode
    if (appMode === 'landing') {
        return <LandingPage />;
    }

    // 2. Auth Mode - Logic to show login if user is not set, or if explicitly in auth mode
    if (appMode === 'auth' && !user) {
        return <LoginPage />;
    }

    // 3. Authenticated App Portal
    const renderContent = () => {
        // --- Admin Role Special Routing ---
        if (currentRole === 'admin') {
            if (currentView === 'settings' || currentView === 'profile') return <SettingsPage />;
            if (currentView === 'admin_settings') return <AdminSettings />;
            if (currentView === 'messages') return <MessagesPage />;
            return <AdminDashboard />;
        }

        // --- Shared Views ---
        if (currentView === 'wallet' || currentView === 'finance') return <WalletPage />;
        if (currentView === 'profile' || currentView === 'settings') return <SettingsPage />;
        if (currentView === 'activity' || currentView === 'trips' || currentView === 'drivers') return <ActivityPage />;
        if (currentView === 'support') return <SupportPage />;
        if (currentView === 'notifications') return <NotificationsPage />;
        if (currentView === 'messages') return <MessagesPage />;

        // --- Role Specific Home ---
        switch (currentRole) {
            case 'driver':
                return <DriverHome />;
            case 'rider':
            default:
                return <RiderHome />;
        }
    };

    return (
        <>
            <ToastContainer />
            <RatingModal />
            <ChatSheet 
                isOpen={chatState.isOpen} 
                onClose={closeChat} 
                recipientName={chatState.recipientName} 
                recipientRole={chatState.recipientRole} 
            />
            <Layout>
                {renderContent()}
            </Layout>
        </>
    );
};

export default App;

import React, { useState, useRef, useEffect } from 'react';
import { Send, X, Phone, User } from 'lucide-react';
import { Button } from '../ui/Button';

interface Message {
    id: string;
    text: string;
    sender: 'me' | 'other';
    time: string;
}

interface ChatSheetProps {
    isOpen: boolean;
    onClose: () => void;
    recipientName: string;
    recipientRole: string;
}

export const ChatSheet: React.FC<ChatSheetProps> = ({ isOpen, onClose, recipientName, recipientRole }) => {
    const [messages, setMessages] = useState<Message[]>([
        { id: '1', text: 'Hi! I am on my way.', sender: 'other', time: '12:30 PM' },
    ]);
    const [input, setInput] = useState('');
    const messagesEndRef = useRef<HTMLDivElement>(null);

    const scrollToBottom = () => {
        messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
    };

    useEffect(() => {
        if (isOpen) scrollToBottom();
    }, [messages, isOpen]);

    const handleSend = (e: React.FormEvent) => {
        e.preventDefault();
        if (!input.trim()) return;
        setMessages([...messages, { 
            id: Date.now().toString(), 
            text: input, 
            sender: 'me', 
            time: new Date().toLocaleTimeString([], { hour: '2-digit', minute:'2-digit' }) 
        }]);
        setInput('');

        // Simulate reply
        setTimeout(() => {
            setMessages(prev => [...prev, {
                id: Date.now().toString() + 'r',
                text: "Sounds good, see you soon!",
                sender: 'other',
                time: new Date().toLocaleTimeString([], { hour: '2-digit', minute:'2-digit' })
            }]);
        }, 2000);
    };

    if (!isOpen) return null;

    return (
        <div className="fixed inset-0 z-[60] flex items-end md:items-center justify-center pointer-events-none">
            {/* Backdrop */}
            <div className="absolute inset-0 bg-black/40 dark:bg-black/60 backdrop-blur-sm pointer-events-auto animate-in fade-in duration-300" onClick={onClose} />

            {/* Chat Window */}
            <div className="pointer-events-auto w-full md:w-[400px] h-[80vh] md:h-[600px] bg-white dark:bg-slate-900 md:rounded-2xl rounded-t-2xl shadow-2xl border border-slate-200 dark:border-white/10 flex flex-col animate-in slide-in-from-bottom-10 duration-300 transition-colors">
                {/* Header */}
                <div className="p-4 border-b border-slate-100 dark:border-white/5 flex items-center justify-between bg-slate-50 dark:bg-white/5 md:rounded-t-2xl">
                    <div className="flex items-center gap-3">
                        <div className="w-10 h-10 rounded-full bg-white dark:bg-slate-700 flex items-center justify-center border border-slate-200 dark:border-white/10 shadow-sm">
                            <User size={20} className="text-slate-500 dark:text-slate-400" />
                        </div>
                        <div>
                            <div className="font-bold text-slate-900 dark:text-white text-sm">{recipientName || 'Driver'}</div>
                            <div className="text-xs text-brand-600 dark:text-brand-400 font-medium capitalize">{recipientRole || 'Partner'}</div>
                        </div>
                    </div>
                    <div className="flex gap-2">
                        <button className="p-2 rounded-full hover:bg-slate-200 dark:hover:bg-white/10 text-brand-600 dark:text-brand-400 transition-colors">
                            <Phone size={18} />
                        </button>
                        <button onClick={onClose} className="p-2 rounded-full hover:bg-slate-200 dark:hover:bg-white/10 text-slate-400 transition-colors">
                            <X size={18} />
                        </button>
                    </div>
                </div>

                {/* Messages Area */}
                <div className="flex-1 overflow-y-auto p-4 space-y-4 bg-slate-50 dark:bg-slate-950/50">
                    <div className="text-center text-xs text-slate-400 dark:text-slate-500 my-4 font-medium uppercase tracking-wider">Today</div>
                    {messages.map((msg) => (
                        <div key={msg.id} className={`flex ${msg.sender === 'me' ? 'justify-end' : 'justify-start'}`}>
                            <div className={`max-w-[80%] rounded-2xl px-4 py-3 text-sm shadow-sm ${
                                msg.sender === 'me' 
                                ? 'bg-brand-600 text-white rounded-br-none' 
                                : 'bg-white dark:bg-slate-800 text-slate-800 dark:text-slate-200 rounded-bl-none border border-slate-100 dark:border-transparent'
                            }`}>
                                {msg.text}
                                <div className={`text-[10px] mt-1 opacity-70 ${msg.sender === 'me' ? 'text-brand-100' : 'text-slate-400'}`}>
                                    {msg.time}
                                </div>
                            </div>
                        </div>
                    ))}
                    <div ref={messagesEndRef} />
                </div>

                {/* Input Area */}
                <form onSubmit={handleSend} className="p-4 border-t border-slate-100 dark:border-white/5 bg-white dark:bg-slate-900 flex gap-2">
                    <input 
                        type="text" 
                        value={input}
                        onChange={(e) => setInput(e.target.value)}
                        placeholder="Type a message..."
                        className="flex-1 bg-slate-50 dark:bg-slate-950 border border-slate-200 dark:border-white/10 rounded-xl px-4 py-3 text-sm text-slate-900 dark:text-white placeholder:text-slate-400 dark:placeholder:text-slate-600 focus:outline-none focus:border-brand-500 focus:ring-1 focus:ring-brand-500 transition-all"
                    />
                    <Button type="submit" size="sm" className="w-12 h-12 !px-0 rounded-xl flex items-center justify-center">
                        <Send size={18} />
                    </Button>
                </form>
            </div>
        </div>
    );
};

import React, { useState, useEffect, useCallback } from 'react';
import { MapBackground } from '../../components/Map/MapBackground';
import { Button } from '../../components/ui/Button';
import { MapPin, Navigation, Car, Building, Plane, Clock, User, MessageCircle, Phone, X, Star, Flag, ArrowLeft } from 'lucide-react';
import { useAppStore } from '../../store';
import { Ride, ServiceType, Hotel, Location } from '../../types';
import { RoutingManager } from '../../services/routing/RoutingManager';
import { socketService } from '../../services/mockSocket';

export const RiderHome: React.FC = () => {
    const { activeRide, startRide, updateRideStatus, addToast, userLocation, drivers, hotels, adminSettings, setRoute, currentRoute, openChat } = useAppStore();

    // View States
    const [viewState, setViewState] = useState<'grid' | 'selecting' | 'confirm_pickup' | 'drivers' | 'negotiating' | 'tracking'>('grid');
    const [selectedService, setSelectedService] = useState<ServiceType>('city');

    // Selection Data
    const [mapCenter, setMapCenter] = useState<Location>(userLocation);
    const [destination, setDestination] = useState<string>('');
    const [destCoords, setDestCoords] = useState<Location | null>(null);
    const [pickupCoords, setPickupCoords] = useState<Location | null>(null);

    // Request Data
    const [proposedFare, setProposedFare] = useState<string>('');
    const [selectedDriverId, setSelectedDriverId] = useState<string | null>(null);

    // Initial map sync
    useEffect(() => {
        setMapCenter(userLocation);
    }, [userLocation]);

    // Handle Hotel Selection from Map Popup
    useEffect(() => {
        const handleHotelSelect = (e: any) => {
            const hotel = e.detail as Hotel;
            setDestination(hotel.name);
            setDestCoords(hotel.location);
            setViewState('selecting'); 
            // Add slight delay to allow map to settle before route calculation visual
            setTimeout(() => handleSetDestination(hotel.location, hotel.name), 200);
        };
        window.addEventListener('select-hotel', handleHotelSelect);
        return () => window.removeEventListener('select-hotel', handleHotelSelect);
    }, []);

    // --- Actions ---

    const handleServiceSelect = (service: ServiceType) => {
        setSelectedService(service);
        if (service === 'hotel') {
            setViewState('selecting');
        } else {
            setViewState('selecting');
            setMapCenter(userLocation);
        }
    };

    const handleCameraChange = useCallback((center: Location) => {
        setMapCenter(center);
    }, []);

    const handleSetDestination = async (coords: Location, name: string) => {
        setDestCoords(coords);
        setDestination(name);

        try {
            const pickup = pickupCoords || userLocation;

            const routeData = await RoutingManager.getRoute(pickup, coords, adminSettings);
            setRoute(routeData);
            setViewState('drivers');

            // Auto-calculate suggested fare
            const distKm = routeData.distance / 1000;
            const suggested = Math.round(distKm * 20 + adminSettings.pricing.minFare);
            setProposedFare(suggested.toString());
        } catch (error) {
            addToast('error', "Could not calculate route.");
        }
    };

    const handleConfirmSelection = () => {
        if (viewState === 'selecting') {
             handleSetDestination(mapCenter, "Pinned Location");
        }
    };

    const handleSelectDriver = (driverId: string, baseFare: number) => {
        setSelectedDriverId(driverId);
        setProposedFare(Math.max(parseInt(proposedFare) || 0, baseFare).toString());
    };

    const handleRequestRide = () => {
        if (!selectedDriverId) return;

        const fare = parseInt(proposedFare);
        const finalPickup = pickupCoords || userLocation;

        const newRide: Ride = {
            id: `ride_${Date.now()}`,
            pickup: 'Current Location',
            destination: destination || "Pinned Location",
            pickupLocation: finalPickup,
            destinationLocation: destCoords || mapCenter,
            fare: fare,
            proposedFare: fare,
            status: 'requested',
            riderId: 'u1',
            driverId: selectedDriverId,
            serviceType: selectedService,
            timestamp: Date.now(),
            distance: currentRoute?.distance || 0,
            duration: currentRoute?.duration || 0,
            route: currentRoute!
        };

        startRide(newRide);
        socketService.emit('request_ride', newRide);
        setViewState('tracking');
    };

    const resetFlow = () => {
        setViewState('grid');
        setDestCoords(null);
        setPickupCoords(null);
        setRoute(null);
        setDestination('');
        startRide(null);
        setSelectedDriverId(null);
        setMapCenter(userLocation);
    };

    const handleContactDriver = () => {
         openChat(activeRide?.driverId || 'd1', 'Ahmad Driver', 'Driver');
    };

    const handleCallDriver = () => {
        addToast('info', 'Calling Driver...');
    };

    // --- UI Components ---

    const ServiceGrid = () => (
        <div className="absolute bottom-0 left-0 right-0 bg-white dark:bg-dark-950 rounded-t-3xl shadow-[0_-10px_40px_rgba(0,0,0,0.1)] z-20 animate-in slide-in-from-bottom-10 duration-300">
            <div className="p-6">
                <h2 className="text-xl font-bold text-dark-900 dark:text-white mb-6">Where to?</h2>
                <div className="grid grid-cols-3 gap-4 mb-20 md:mb-4">
                    {[
                        { id: 'city', label: 'City Taxi', icon: <Car size={28} />, color: 'bg-blue-100 text-blue-600 dark:bg-blue-600/20 dark:text-blue-400' },
                        { id: 'intercity', label: 'Intercity', icon: <MapPin size={28} />, color: 'bg-green-100 text-green-600 dark:bg-green-600/20 dark:text-green-400' },
                        { id: 'airport', label: 'Airport', icon: <Plane size={28} />, color: 'bg-purple-100 text-purple-600 dark:bg-purple-600/20 dark:text-purple-400' },
                        { id: 'hotel', label: 'Hotels', icon: <Building size={28} />, color: 'bg-orange-100 text-orange-600 dark:bg-orange-600/20 dark:text-orange-400' },
                        { id: 'scheduled', label: 'Schedule', icon: <Clock size={28} />, color: 'bg-slate-100 text-slate-600 dark:bg-slate-700/50 dark:text-slate-400' },
                        { id: 'subscription', label: 'Subs', icon: <User size={28} />, color: 'bg-slate-100 text-slate-600 dark:bg-slate-700/50 dark:text-slate-400' },
                    ].map((item) => (
                        <button 
                            key={item.id} 
                            onClick={() => handleServiceSelect(item.id as ServiceType)}
                            className="flex flex-col items-center justify-center p-4 rounded-2xl bg-dark-50 dark:bg-white/5 active:scale-95 transition-transform hover:bg-dark-100 dark:hover:bg-white/10"
                        >
                            <div className={`w-14 h-14 rounded-full flex items-center justify-center mb-3 ${item.color}`}>
                                {item.icon}
                            </div>
                            <span className="text-xs font-bold text-dark-700 dark:text-dark-300">{item.label}</span>
                        </button>
                    ))}
                </div>
            </div>
        </div>
    );

    const MapSelectionOverlay = () => (
        <>
            <div className="absolute top-0 left-0 right-0 p-4 z-20 flex items-center gap-3 bg-gradient-to-b from-black/40 to-transparent pt-safe">
                <button onClick={resetFlow} className="w-10 h-10 rounded-full bg-white dark:bg-dark-900 shadow-lg flex items-center justify-center text-dark-900 dark:text-white">
                    <ArrowLeft size={20} />
                </button>
                <div className="flex-1 bg-white dark:bg-dark-900 rounded-xl shadow-lg flex items-center px-4 h-12">
                    <div className="w-2 h-2 rounded-full bg-red-500 mr-3"></div>
                    <span className="font-bold text-dark-900 dark:text-white truncate">
                        {selectedService === 'hotel' ? 'Select Hotel from Map' : 'Set Destination'}
                    </span>
                </div>
            </div>

            {selectedService !== 'hotel' && (
                <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 -mt-4 z-10 pointer-events-none flex flex-col items-center">
                    <div className="w-10 h-10 bg-dark-900 text-white rounded-full flex items-center justify-center shadow-xl mb-1 relative">
                        <MapPin size={20} fill="currentColor" />
                        <div className="absolute -bottom-1 left-1/2 -translate-x-1/2 w-1 h-3 bg-dark-900"></div>
                    </div>
                    <div className="bg-white dark:bg-dark-800 px-3 py-1.5 rounded-lg shadow-lg text-xs font-bold whitespace-nowrap">
                        Release to set
                    </div>
                </div>
            )}

            <div className="absolute bottom-10 left-4 right-4 z-20">
                {selectedService === 'hotel' ? (
                     <div className="bg-white dark:bg-dark-900 p-4 rounded-xl shadow-xl text-center">
                         <p className="text-sm font-bold mb-0 text-dark-700 dark:text-dark-300">Tap a hotel icon to select</p>
                     </div>
                ) : (
                    <Button size="lg" className="w-full shadow-xl" onClick={handleConfirmSelection}>
                        Confirm Destination
                    </Button>
                )}
            </div>
        </>
    );

    const DriverSelectionPanel = () => (
        <div className="absolute bottom-0 left-0 right-0 bg-white dark:bg-dark-950 rounded-t-3xl shadow-[0_-10px_50px_rgba(0,0,0,0.2)] z-30 flex flex-col h-[60vh] animate-in slide-in-from-bottom-20 duration-300">
            <div className="p-4 border-b border-dark-100 dark:border-white/5">
                 <div className="flex justify-between items-center mb-4">
                    <h3 className="font-bold text-lg text-dark-900 dark:text-white">Nearby Drivers</h3>
                    <button onClick={() => setViewState('selecting')} className="p-2 hover:bg-dark-100 dark:hover:bg-white/10 rounded-full"><X size={20} /></button>
                </div>

                <div className="flex items-center justify-between bg-brand-50 dark:bg-brand-900/20 p-3 rounded-xl border border-brand-200 dark:border-brand-500/30">
                    <span className="text-sm font-bold text-brand-700 dark:text-brand-300">Your Offer (AFN)</span>
                    <div className="flex items-center gap-2">
                        <button onClick={() => setProposedFare((parseInt(proposedFare)-10).toString())} className="w-8 h-8 rounded-full bg-white dark:bg-white/10 flex items-center justify-center font-bold text-dark-600 dark:text-white shadow-sm">-</button>
                        <input 
                            type="number" 
                            className="w-20 bg-transparent text-center font-black text-xl text-brand-700 dark:text-white focus:outline-none" 
                            value={proposedFare} 
                            onChange={(e) => setProposedFare(e.target.value)} 
                        />
                        <button onClick={() => setProposedFare((parseInt(proposedFare)+10).toString())} className="w-8 h-8 rounded-full bg-white dark:bg-white/10 flex items-center justify-center font-bold text-dark-600 dark:text-white shadow-sm">+</button>
                    </div>
                </div>
            </div>

            <div className="flex-1 overflow-y-auto p-4 space-y-3 pb-24">
                {drivers.map(driver => (
                    <div 
                        key={driver.id} 
                        onClick={() => handleSelectDriver(driver.id, driver.baseFare)}
                        className={`relative flex items-center p-3 rounded-xl border-2 cursor-pointer transition-all ${selectedDriverId === driver.id ? 'border-brand-500 bg-brand-50 dark:bg-brand-900/20' : 'border-dark-100 dark:border-white/5 hover:border-brand-200 dark:hover:border-white/20'}`}
                    >
                        <div className="w-14 h-14 rounded-full bg-dark-200 dark:bg-dark-800 flex items-center justify-center mr-3 relative shrink-0">
                            <Car size={28} className="text-dark-500" />
                        </div>
                        <div className="flex-1">
                            <div className="flex justify-between items-center mb-1">
                                <span className="font-bold text-dark-900 dark:text-white text-lg">{driver.name}</span>
                                <span className="font-black text-dark-900 dark:text-white">؋{driver.baseFare}</span>
                            </div>
                            <div className="flex justify-between items-center text-xs text-dark-500 dark:text-dark-400">
                                <span>{driver.vehicle}</span>
                                <span className="flex items-center text-orange-500 font-bold"><Star size={12} fill="currentColor" className="mr-1"/> {driver.rating.toFixed(1)}</span>
                            </div>
                        </div>
                    </div>
                ))}
            </div>

            <div className="absolute bottom-0 left-0 right-0 p-4 border-t border-dark-100 dark:border-white/5 bg-white dark:bg-dark-950 mb-safe z-40">
                 <Button size="lg" className="w-full h-14 text-lg shadow-xl" disabled={!selectedDriverId} onClick={handleRequestRide}>
                    Request Ride
                 </Button>
            </div>
        </div>
    );

    const ActiveTripPanel = () => {
        if (!activeRide) return null;
        const isPending = activeRide.status === 'requested';
        const isArrived = activeRide.status === 'arrived';
        const isInProgress = activeRide.status === 'in_progress';

        return (
            <div className="absolute bottom-0 left-0 right-0 bg-white dark:bg-dark-950 rounded-t-3xl shadow-[0_-10px_50px_rgba(0,0,0,0.2)] z-30 p-6 mb-16 md:mb-0 animate-in slide-in-from-bottom-20 duration-300">
                 {isPending ? (
                     <div className="text-center py-6">
                         <div className="w-16 h-16 rounded-full border-4 border-brand-500 border-t-transparent animate-spin mx-auto mb-4"></div>
                         <h2 className="text-xl font-bold text-dark-900 dark:text-white mb-1">Contacting Driver...</h2>
                         <p className="text-dark-500">Waiting for acceptance</p>
                         <Button variant="ghost" className="mt-4 text-red-500" onClick={() => updateRideStatus('cancelled')}>Cancel Request</Button>
                     </div>
                 ) : (
                     <>
                        <div className="flex items-center justify-between mb-6">
                            <div>
                                <div className="text-xs font-bold text-brand-600 uppercase tracking-wider mb-1">
                                    {isArrived ? 'Driver is Here!' : isInProgress ? 'On Trip' : 'Driver Arriving'}
                                </div>
                                <h2 className="text-2xl font-bold text-dark-900 dark:text-white">
                                    {isArrived ? 'Meet at Pickup Point' : isInProgress ? 'Heading to Destination' : 'Driver En Route'}
                                </h2>
                            </div>
                            <div className="text-right">
                                <div className="text-2xl font-black text-dark-900 dark:text-white">
                                    {isArrived ? '0' : '12'} <span className="text-sm font-medium text-dark-500">min</span>
                                </div>
                            </div>
                        </div>

                        <div className="flex items-center gap-4 bg-dark-50 dark:bg-white/5 p-4 rounded-xl mb-6 border border-dark-100 dark:border-white/5">
                            <div className="w-12 h-12 rounded-full bg-dark-200 dark:bg-dark-800 overflow-hidden">
