                            </div>
                            <div className={`text-lg font-black tracking-tight ${tx.type === 'debit' ? 'text-dark-900 dark:text-white' : 'text-green-600 dark:text-green-400'}`}>
                                {tx.type === 'debit' ? '-' : '+'}؋{tx.amount.toFixed(0)}
                            </div>
                        </div>
                    ))}
                </div>
            </Card>

            {/* Top Up Modal Overlay */}
            {showTopUp && (
                <div className="absolute inset-0 z-50 bg-black/50 backdrop-blur-sm flex items-center justify-center p-4 animate-in fade-in duration-200">
                    <Card className="w-full max-w-sm p-6 relative">
                        <button onClick={() => setShowTopUp(false)} className="absolute top-4 right-4 text-dark-400 hover:text-dark-900 dark:hover:text-white">
                            <X size={20}/>
                        </button>
                        <h3 className="text-xl font-bold text-dark-900 dark:text-white mb-4">Top Up Wallet</h3>
                        <p className="text-sm text-dark-500 mb-6">Enter amount to add to your balance.</p>

                        <div className="flex gap-2 mb-4">
                            {[100, 500, 1000].map(val => (
                                <button 
                                    key={val}
                                    onClick={() => setAmount(val.toString())}
                                    className="flex-1 py-2 rounded-lg border border-dark-200 dark:border-white/10 hover:bg-dark-50 dark:hover:bg-white/5 text-sm font-bold"
                                >
                                    ؋{val}
                                </button>
                            ))}
                        </div>

                        <input 
                            type="number" 
                            className="w-full p-3 rounded-xl bg-dark-50 dark:bg-white/5 border border-dark-200 dark:border-white/10 text-xl font-bold mb-4 focus:ring-2 focus:ring-brand-500 outline-none"
                            placeholder="Amount"
                            value={amount}
                            onChange={(e) => setAmount(e.target.value)}
                            autoFocus
                        />

                        <Button size="lg" className="w-full" onClick={handleTopUp}>Confirm Payment</Button>
                    </Card>
                </div>
            )}
        </div>
    );
};

export type UserRole = 'rider' | 'driver' | 'admin' | null;

export interface Location {
    lat: number;
    lng: number;
    bearing?: number; // 0-360 degrees
}

export interface User {
    id: string;
    name: string;
    email: string;
    avatar?: string;
    role: UserRole;
    rating?: number;
    phone?: string;
    totalTrips?: number;
    balance?: number;
}

export type ServiceType = 'city' | 'intercity' | 'airport' | 'hotel' | 'scheduled' | 'subscription';

export interface Ride {
    id: string;
    pickup: string;
    destination: string;
    pickupLocation: Location;
    destinationLocation: Location;
    fare: number; // Final agreed fare
    proposedFare?: number; // Negotiation start
    status: 'searching' | 'negotiating' | 'requested' | 'accepted' | 'arrived' | 'in_progress' | 'completed' | 'cancelled';
    driverId?: string;
    riderId: string;
    serviceType: ServiceType;
    timestamp: number;
    distance: number;
    duration: number;
    route?: RouteData;
}

export interface Hotel {
    id: string;
    name: string;
    address: string;
    rating: number;
    priceRange: string;
    location: Location;
    image: string;
    commission: number;
}

export interface DriverMarker {
    id: string;
    name: string;
    vehicle: string;
    rating: number;
    location: Location;
    status: 'available' | 'busy' | 'offline';
    baseFare: number; // Driver set base fare
    perKmRate: number; // Driver set per km rate
    type: 'eco' | 'plus' | 'lux';
    distance?: number; // Calculated distance to rider
    eta?: number; // Calculated ETA
}

export interface RouteData {
    coordinates: [number, number][]; // Array of [lat, lng]
    distance: number; // meters
    duration: number; // seconds
    bbox?: [number, number, number, number];
}

export type RoutingProviderType = 'ors' | 'mapbox' | 'mock';
export type MapProviderType = 'osm' | 'mapbox' | 'google';

export interface AdminSettings {
    routingProvider: RoutingProviderType;
    mapProvider: MapProviderType;
    apiKeys: {
        ors: string;
