export type AppMode = 'landing' | 'auth' | 'app';
export type AppView = 'home' | 'trips' | 'wallet' | 'messages' | 'profile' | 'settings' | 'earnings' | 'drivers' | 'analytics' | 'notifications' | 'finance' | 'admin_settings' | 'activity' | 'support';
