    const [pricing, setPricing] = useState(adminSettings.pricing);
    const [system, setSystem] = useState(adminSettings.system);
    const [newHotel, setNewHotel] = useState({ name: '', address: '', priceRange: '$$' });

    // Dynamic Chart Data Calculation
    const { revenueData, driverStats, totalRevenue, totalTrips } = useMemo(() => {
        // Group transactions by day (last 7 days)
        const days = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];
        const today = new Date();
        const last7Days = Array.from({length: 7}, (_, i) => {
            const d = new Date(today);
            d.setDate(d.getDate() - (6-i));
            return d;
        });

        const revData = last7Days.map(date => {
            const dayStr = days[date.getDay()];
            const dailyTotal = transactions
                .filter(t => new Date(t.date).toDateString() === date.toDateString() && t.type === 'credit')
                .reduce((acc, t) => acc + t.amount, 0);
            return { name: dayStr, revenue: dailyTotal };
        });

        // Mock stats for driver performance based on online drivers (since we don't store driver historical data fully)
        const dStats = last7Days.map(date => ({
            name: days[date.getDay()],
            online: drivers.length + Math.floor(Math.random() * 10), // Simulated fluctuation
            rides: pastTrips.filter(t => new Date(t.timestamp).toDateString() === date.toDateString()).length
        }));

        const totalRev = transactions.filter(t => t.type === 'credit').reduce((acc, t) => acc + t.amount, 0);

        return {
            revenueData: revData,
            driverStats: dStats,
            totalRevenue: totalRev,
            totalTrips: pastTrips.length
