export type UserRole = 'rider' | 'driver' | 'admin' | null;

export interface Location {
    lat: number;
    lng: number;
    bearing?: number; // 0-360 degrees
}

export interface User {
    id: string;
    name: string;
    email: string;
    avatar?: string;
    role: UserRole;
    rating?: number;
    phone?: string;
    totalTrips?: number;
    balance?: number;
}

export type ServiceType = 'city' | 'intercity' | 'airport' | 'hotel' | 'scheduled' | 'subscription';

export interface Ride {
    id: string;
    pickup: string;
    destination: string;
    pickupLocation: Location;
    destinationLocation: Location;
    fare: number; // Final agreed fare
    proposedFare?: number; // Negotiation start
    status: 'searching' | 'negotiating' | 'requested' | 'accepted' | 'arrived' | 'in_progress' | 'completed' | 'cancelled';
    driverId?: string;
    riderId: string;
    serviceType: ServiceType;
    timestamp: number;
    distance: number;
    duration: number;
    route?: RouteData;
}

export interface Hotel {
    id: string;
    name: string;
    address: string;
    rating: number;
    priceRange: string;
    location: Location;
    image: string;
    commission: number;
}

export interface DriverMarker {
    id: string;
    name: string;
    vehicle: string;
    rating: number;
    location: Location;
    status: 'available' | 'busy' | 'offline';
    baseFare: number; // Driver set base fare
    perKmRate: number; // Driver set per km rate
    type: 'eco' | 'plus' | 'lux';
    distance?: number; // Calculated distance to rider
    eta?: number; // Calculated ETA
}

export interface RouteData {
    coordinates: [number, number][]; // Array of [lat, lng]
    distance: number; // meters
    duration: number; // seconds
    bbox?: [number, number, number, number];
}

export type RoutingProviderType = 'ors' | 'mapbox' | 'mock';
export type MapProviderType = 'osm' | 'mapbox' | 'google';

export interface ServiceClass {
    id: string;
    name: string;
    baseFare: number;
    perKm: number;
    perMin: number;
    minFare: number;
    commission: number;
    icon: string;
}

export interface AdminSettings {
    routingProvider: RoutingProviderType;
    mapProvider: MapProviderType;
    apiKeys: {
        ors: string;
        mapbox: string;
        google: string;
    };
    pricing: {
        minFare: number;
        commissionRate: number; // Percentage
        cancellationFee: number;
        intercityMultiplier: number;
    };
    services: ServiceClass[];
    system: {
        defaultCenter: Location;
        driverUpdateInterval: number;
        enableManualFare: boolean;
        radiusLimit: number; // km
        dispatchTimeout: number; // seconds
    };
    hotelsModule: {
        enabled: boolean;
        commission: number;
    };
}

export interface Toast {
    id: string;
    type: 'success' | 'error' | 'warning' | 'info';
    message: string;
}

export interface Transaction {
    id: string;
    amount: number;
    type: 'credit' | 'debit';
    date: number;
    description: string;
    status: 'completed' | 'pending' | 'failed';
}

export interface AppNotification {
    id: string;
    type: 'promo' | 'system' | 'success' | 'alert';
    title: string;
    message: string;
    timestamp: number;
    read: boolean;
}

export interface ChatMessage {
    id: string;
    text: string;
    sender: 'me' | 'other';
    time: string;
}

export interface ChatState {
    isOpen: boolean;
    recipientId: string;
    recipientName: string;
    recipientRole: string;
    messages: Record<string, ChatMessage[]>; // Keyed by recipientId
}

import { create } from 'zustand';
import { persist } from 'zustand/middleware';
import { User, Ride, UserRole, AdminSettings, RouteData, Location, DriverMarker, Hotel, Toast, Transaction, AppNotification, ChatState, ChatMessage } from './types';

export type AppMode = 'landing' | 'auth' | 'app';
export type AppView = 'home' | 'trips' | 'wallet' | 'messages' | 'profile' | 'settings' | 'earnings' | 'drivers' | 'analytics' | 'notifications' | 'finance' | 'admin_settings' | 'activity' | 'support';
export type Language = 'en' | 'fa';

interface AppState {
    appMode: AppMode;
    user: User | null;
    currentRole: UserRole;
    activeRide: Ride | null;
    pastTrips: Ride[];
    transactions: Transaction[];
    notifications: AppNotification[];
    isDarkMode: boolean;
    language: Language;
    toasts: Toast[];
    currentView: AppView;
    chatState: ChatState;

    // Admin & Config
    adminSettings: AdminSettings;

    // Map & Location Data
    userLocation: Location;
    drivers: DriverMarker[];
    hotels: Hotel[];
    currentRoute: RouteData | null;

    // Actions
    setAppMode: (mode: AppMode) => void;
    setUser: (user: User | null) => void;
    updateUserProfile: (data: Partial<User>) => void;
    setRole: (role: UserRole) => void;
    setView: (view: AppView) => void;
    startRide: (ride: Ride | null) => void;
    updateRideStatus: (status: Ride['status']) => void;
    completeRide: () => void; 
    toggleDarkMode: () => void;
    setLanguage: (lang: Language) => void;
    logout: () => void;

    // Chat Actions
    openChat: (recipientId: string, name: string, role: string) => void;
    closeChat: () => void;
    sendMessage: (recipientId: string, text: string, sender: 'me' | 'other') => void;

    // Data Actions
    addNotification: (notification: AppNotification) => void;
    markNotificationRead: (id: string) => void;
    markAllNotificationsRead: () => void;
    addTransaction: (tx: Transaction) => void;

    // Map Actions
    updateUserLocation: (loc: Location) => void;
    updateDrivers: (drivers: DriverMarker[]) => void;
    registerDriver: (driver: DriverMarker) => void; 
    generateLocalDrivers: (center: Location) => void; 
    setRoute: (route: RouteData | null) => void;

    // Admin Actions
    updateAdminSettings: (settings: Partial<AdminSettings>) => void;
    addHotel: (hotel: Hotel) => void;
    removeHotel: (id: string) => void;

    // Toast Actions
    addToast: (type: Toast['type'], message: string) => void;
    removeToast: (id: string) => void;
}

