const INITIAL_TRANSACTIONS: Transaction[] = [
    { id: 'tx_1', amount: 500, type: 'credit', date: Date.now() - 86400000, description: 'Wallet Top-up', status: 'completed' }
];

const INITIAL_NOTIFICATIONS: AppNotification[] = [
    { id: 'n1', type: 'promo', title: 'Welcome to iTaxi', message: 'Get 50% off your first ride!', timestamp: Date.now(), read: false }
];

export const useAppStore = create<AppState>()(
    persist(
        (set, get) => ({
            appMode: 'landing',
            user: null, 
            currentRole: 'rider',
            activeRide: null,
            pastTrips: [],
            transactions: INITIAL_TRANSACTIONS,
            notifications: INITIAL_NOTIFICATIONS,
            isDarkMode: true,
            language: 'en',
            toasts: [],
            currentView: 'home',
            chatState: { 
                isOpen: false, 
                recipientId: '', 
                recipientName: '', 
                recipientRole: '', 
                messages: {} 
            },

            adminSettings: DEFAULT_ADMIN_SETTINGS,

            userLocation: DEFAULT_LOCATION,
            drivers: [],
            hotels: INITIAL_HOTELS,
            currentRoute: null,

            setAppMode: (mode) => set({ appMode: mode }),
            setUser: (user) => set({ user, appMode: 'app' }),
            updateUserProfile: (data) => set((state) => ({ user: state.user ? { ...state.user, ...data } : null })),
            setRole: (role) => set({ currentRole: role, currentView: 'home' }), 
            setView: (view) => set({ currentView: view }),

            startRide: (ride) => set((state) => ({ 
                activeRide: ride, 
                currentRoute: ride?.route || state.currentRoute 
            })),

            updateRideStatus: (status) => {
                const state = get();
                if (state.activeRide) {
                    let notifTitle = '';
                    let notifMsg = '';

                    if (status === 'accepted') {
                        notifTitle = 'Driver Found';
                        notifMsg = 'A driver has accepted your request.';
                    } else if (status === 'arrived') {
                        notifTitle = 'Driver Arrived';
                        notifMsg = 'Your driver is waiting at the pickup location.';
                    } else if (status === 'in_progress') {
                        notifTitle = 'Trip Started';
                        notifMsg = 'You are on your way to the destination.';
                    } else if (status === 'completed') {
                        notifTitle = 'Trip Completed';
                        notifMsg = 'You have arrived. Thank you for riding with iTaxi.';
                    }

                    if (notifTitle) {
                        get().addNotification({
                            id: `n_${Date.now()}`,
                            type: status === 'completed' ? 'success' : 'system',
                            title: notifTitle,
                            message: notifMsg,
                            timestamp: Date.now(),
                            read: false
                        });
                    }

                    set({ activeRide: { ...state.activeRide, status } });
                }
            },

            completeRide: () => {
                const { activeRide, adminSettings, addNotification } = get();
                if (!activeRide) return;

                const fare = activeRide.fare;
                const commission = (fare * adminSettings.pricing.commissionRate) / 100;
                const driverEarnings = fare - commission;

                const newTx: Transaction = {
                    id: `tx_${Date.now()}`,
                    amount: get().currentRole === 'driver' ? driverEarnings : fare,
                    type: get().currentRole === 'driver' ? 'credit' : 'debit',
                    date: Date.now(),
                    description: `Trip to ${activeRide.destination}`,
                    status: 'completed'
                };

                const completedRide: Ride = { ...activeRide, status: 'completed' };

                addNotification({
                    id: `n_end_${Date.now()}`,
                    type: 'success',
                    title: 'Payment Successful',
                    message: `Trip fare of ؋${fare} has been processed.`,
                    timestamp: Date.now(),
                    read: false
                });

                set((state) => ({
                    pastTrips: [completedRide, ...state.pastTrips],
                    activeRide: null,
                    currentRoute: null,
                    transactions: [newTx, ...state.transactions],
                    user: state.user ? {
                        ...state.user,
                        balance: (state.user.balance || 0) + (newTx.type === 'credit' ? newTx.amount : -newTx.amount),
                        totalTrips: (state.user.totalTrips || 0) + 1
                    } : null
                }));
            },

            toggleDarkMode: () => set((state) => ({ isDarkMode: !state.isDarkMode })),
            setLanguage: (lang) => set({ language: lang }),
            logout: () => set({ user: null, activeRide: null, appMode: 'landing', currentView: 'home', currentRoute: null }),

            openChat: (recipientId, name, role) => set((state) => ({ 
                chatState: { ...state.chatState, isOpen: true, recipientId, recipientName: name, recipientRole: role } 
            })),
            closeChat: () => set((state) => ({ chatState: { ...state.chatState, isOpen: false } })),

            sendMessage: (recipientId, text, sender) => set((state) => {
                const currentMessages = state.chatState.messages[recipientId] || [];
                const newMessage: ChatMessage = {
                    id: Date.now().toString(),
                    text,
                    sender,
                    time: new Date().toLocaleTimeString([], { hour: '2-digit', minute:'2-digit' }) 
                };
                return {
                    chatState: {
                        ...state.chatState,
                        messages: {
                            ...state.chatState.messages,
                            [recipientId]: [...currentMessages, newMessage]
                        }
                    }
                };
            }),

            addNotification: (notification) => set((state) => ({ notifications: [notification, ...state.notifications] })),
            markNotificationRead: (id) => set(state => ({
                notifications: state.notifications.map(n => n.id === id ? { ...n, read: true } : n)
            })),

            markAllNotificationsRead: () => set(state => ({
                notifications: state.notifications.map(n => ({ ...n, read: true }))
            })),

            addTransaction: (tx) => set((state) => {
                const newBalance = (state.user?.balance || 0) + (tx.type === 'credit' ? tx.amount : -tx.amount);
                return {
                    transactions: [tx, ...state.transactions],
                    user: state.user ? { ...state.user, balance: newBalance } : null
                };
            }),

            updateUserLocation: (loc) => set({ userLocation: loc }),

            updateDrivers: (drivers) => set({ drivers }),

            registerDriver: (driver) => set((state) => {
                const filtered = state.drivers.filter(d => d.id !== driver.id);
                return { drivers: [...filtered, driver] };
            }),

            generateLocalDrivers: (center) => {
                const existingRealDrivers = get().drivers.filter(d => d.id === 'real_driver'); 

                const newDrivers = Array.from({ length: 5 }).map((_, i) => ({
                    id: `sim_${Date.now()}_${i}`,
                    name: `Driver ${i + 1}`,
                    vehicle: i % 2 === 0 ? 'Toyota Corolla' : 'Honda Civic',
                    rating: 4.5 + Math.random() * 0.5,
                    location: {
                        lat: center.lat + (Math.random() - 0.5) * 0.015,
                        lng: center.lng + (Math.random() - 0.5) * 0.015,
                        bearing: Math.random() * 360
                    },
                    status: (Math.random() > 0.3 ? 'available' : 'busy') as 'available' | 'busy',
                    type: ['eco', 'plus', 'lux'][Math.floor(Math.random() * 3)] as 'eco' | 'plus' | 'lux',
                    baseFare: 50 + Math.floor(Math.random() * 20),
                    perKmRate: 20 + Math.floor(Math.random() * 10),
                    eta: Math.floor(Math.random() * 10) + 2
                }));

                set({ drivers: [...existingRealDrivers, ...newDrivers] });
            },

            setRoute: (route) => set({ currentRoute: route }),

            updateAdminSettings: (newSettings) => set((state) => ({
                adminSettings: { ...state.adminSettings, ...newSettings }
            })),

            addHotel: (hotel) => set((state) => ({ hotels: [...state.hotels, hotel] })),
            removeHotel: (id) => set((state) => ({ hotels: state.hotels.filter(h => h.id !== id) })),

            addToast: (type, message) => {
                const id = Math.random().toString(36).substring(7);
                set((state) => ({ toasts: [...state.toasts, { id, type, message }] }));
                setTimeout(() => get().removeToast(id), 4000);
            },
            removeToast: (id) => set((state) => ({ toasts: state.toasts.filter(t => t.id !== id) }))
        }),
        {
            name: 'itaxi-storage',
            partialize: (state) => ({ 
                isDarkMode: state.isDarkMode, 
                language: state.language,
                adminSettings: state.adminSettings,
                user: state.user,
                hotels: state.hotels,
                pastTrips: state.pastTrips,
                transactions: state.transactions,
                notifications: state.notifications,
                chatState: { ...state.chatState, isOpen: false } // Reset open state on reload, keep messages
            }),
        }
    )
);

import { RouteData, AdminSettings, Location } from '../../types';

// Interface for all providers
export interface IRoutingProvider {
    calculateRoute(start: Location, end: Location, apiKey?: string): Promise<RouteData>;
}

// 1. Mock Provider (Fallback)
class MockProvider implements IRoutingProvider {
    async calculateRoute(start: Location, end: Location): Promise<RouteData> {
        // Simulate network delay
        await new Promise(resolve => setTimeout(resolve, 600));

        // Generate a simple L-shape polyline to look slightly realistic
        const midPoint = { lat: start.lat, lng: end.lng };

        return {
            coordinates: [
                [start.lat, start.lng],
                [midPoint.lat, midPoint.lng],
                [end.lat, end.lng]
            ],
            distance: 2500, // meters
            duration: 600, // seconds (10 mins)
            bbox: [
                Math.min(start.lat, end.lat),
                Math.min(start.lng, end.lng),
                Math.max(start.lat, end.lat),
                Math.max(start.lng, end.lng)
            ]
        };
    }
}

// 2. OpenRouteService Provider
class OpenRouteServiceProvider implements IRoutingProvider {
    async calculateRoute(start: Location, end: Location, apiKey?: string): Promise<RouteData> {
        if (!apiKey) {
            throw new Error("OpenRouteService API Key is missing. Please configure it in Admin Settings.");
        }

        const baseUrl = "https://api.openrouteservice.org/v2/directions/driving-car";

        // Exact format required by ORS: lng,lat
        const startCoord = `${start.lng},${start.lat}`;
        const endCoord = `${end.lng},${end.lat}`;

        const url = `${baseUrl}?api_key=${apiKey}&start=${startCoord}&end=${endCoord}`;

        try {
            const response = await fetch(url, {
                method: 'GET',
                headers: {
                    'Accept': 'application/json, application/geo+json, application/gpx+xml, img/png; charset=utf-8'
                }
            });

            if (!response.ok) {
                const err = await response.json();
                console.error("ORS API Error:", err);
                throw new Error(err.error?.message || `API Error: ${response.status} ${response.statusText}`);
            }

            const data = await response.json();

            if (!data.features || data.features.length === 0) {
                throw new Error("No route found in response");
            }

            const feature = data.features[0];
            const coords = feature.geometry.coordinates; // ORS returns [lng, lat]
            const props = feature.properties;

            // Convert [lng, lat] to [lat, lng] for Leaflet
            const latLngs: [number, number][] = coords.map((c: number[]) => [c[1], c[0]]);

            return {
                coordinates: latLngs,
                distance: props.summary.distance,
                duration: props.summary.duration,
                bbox: data.bbox ? [data.bbox[1], data.bbox[0], data.bbox[3], data.bbox[2]] : undefined
            };

        } catch (error) {
            console.error("ORS Calculation Failed:", error);
            throw error;
        }
    }
}

// 3. Mapbox Provider
class MapboxProvider implements IRoutingProvider {
    async calculateRoute(start: Location, end: Location, apiKey?: string): Promise<RouteData> {
        if (!apiKey) {
            throw new Error("Mapbox API Key is missing.");
        }

        const baseUrl = "https://api.mapbox.com/directions/v5/mapbox/driving";
        const url = `${baseUrl}/${start.lng},${start.lat};${end.lng},${end.lat}?steps=true&geometries=geojson&access_token=${apiKey}`;

        try {
            const response = await fetch(url);
            if (!response.ok) {
                const err = await response.json();
                throw new Error(err.message || 'Mapbox API Error');
            }

            const data = await response.json();
            if (!data.routes || data.routes.length === 0) {
                throw new Error("No route found");
            }

            const route = data.routes[0];
            const coords = route.geometry.coordinates;
            // Mapbox returns [lng, lat]
            const latLngs: [number, number][] = coords.map((c: number[]) => [c[1], c[0]]);

            return {
                coordinates: latLngs,
                distance: route.distance,
                duration: route.duration,
                // Simple bbox estimation (Mapbox doesn't always return bbox in this endpoint without extra params)
                bbox: [
                     Math.min(start.lat, end.lat), Math.min(start.lng, end.lng),
                     Math.max(start.lat, end.lat), Math.max(start.lng, end.lng)
                ]
            };
        } catch (error) {
            console.error("Mapbox Routing Error:", error);
            throw error;
        }
    }
}

// Manager Factory
export class RoutingManager {
    private static providers: Record<string, IRoutingProvider> = {
        'mock': new MockProvider(),
        'ors': new OpenRouteServiceProvider(),
        'mapbox': new MapboxProvider(),
    };

    static async getRoute(
        start: Location, 
        end: Location, 
        settings: AdminSettings
    ): Promise<RouteData> {
        const providerName = settings.routingProvider || 'mock';
        const provider = this.providers[providerName] || this.providers['mock'];

        let apiKey = '';
        if (providerName === 'ors') apiKey = settings.apiKeys.ors;
        if (providerName === 'mapbox') apiKey = settings.apiKeys.mapbox;

        return await provider.calculateRoute(start, end, apiKey);
    }
}

import React, { useEffect, useRef } from 'react';
import L from 'leaflet';
