                    </div>
                    <div className="w-10 h-10 rounded-full bg-green-100 dark:bg-green-500/20 text-green-600 dark:text-green-400 flex items-center justify-center"><CheckCircle size={20}/></div>
                </Card>
                <Card className="p-5 flex items-center justify-between bg-white dark:bg-white/5 border-transparent shadow-sm">
                    <div>
                        <div className="text-dark-500 text-xs font-bold uppercase tracking-wider mb-1">Avg Rating</div>
                        <div className="text-3xl font-black text-yellow-500">{avgRating}</div>
                    </div>
                    <div className="w-10 h-10 rounded-full bg-yellow-100 dark:bg-yellow-500/20 text-yellow-600 dark:text-yellow-400 flex items-center justify-center"><Star size={20}/></div>
                </Card>
                <Card className="p-5 flex items-center justify-between bg-white dark:bg-white/5 border-transparent shadow-sm">
                    <div>
                        <div className="text-dark-500 text-xs font-bold uppercase tracking-wider mb-1">Suspended</div>
                        <div className="text-3xl font-black text-red-500">{suspendedDrivers}</div>
                    </div>
                    <div className="w-10 h-10 rounded-full bg-red-100 dark:bg-red-500/20 text-red-600 dark:text-red-400 flex items-center justify-center"><Ban size={20}/></div>
                </Card>
            </div>

            {/* Toolbar */}
            <div className="flex flex-col md:flex-row gap-4 mb-6">
                <div className="relative flex-1">
                    <Search className="absolute left-3 top-3 text-dark-400" size={20} />
                    <input 
                        type="text" 
                        placeholder="Search by name, license plate, or phone..." 
                        className="w-full pl-10 pr-4 py-2.5 rounded-xl bg-white dark:bg-dark-900 border border-dark-200 dark:border-white/10 focus:ring-2 focus:ring-brand-500 outline-none"
                        value={searchTerm}
                        onChange={(e) => setSearchTerm(e.target.value)}
                    />
                </div>
                <div className="flex gap-2 overflow-x-auto pb-2 md:pb-0">
                    {['all', 'available', 'busy', 'offline', 'suspended'].map(status => (
                        <button
                            key={status}
                            onClick={() => setFilterStatus(status as any)}
                            className={`px-4 py-2 rounded-lg text-sm font-bold capitalize transition-colors whitespace-nowrap ${filterStatus === status ? 'bg-brand-600 text-white shadow-lg shadow-brand-500/25' : 'bg-white dark:bg-white/5 text-dark-500 hover:bg-dark-100 dark:hover:bg-white/10'}`}
                        >
                            {status}
                        </button>
                    ))}
                </div>
            </div>

            {/* Drivers List */}
            <div className="bg-white dark:bg-dark-900 rounded-2xl shadow-sm border border-dark-200 dark:border-white/5 overflow-hidden">
                <table className="w-full text-left border-collapse">
                    <thead>
                        <tr className="border-b border-dark-100 dark:border-white/5 text-xs font-bold text-dark-400 uppercase tracking-wider bg-dark-50 dark:bg-white/5">
                            <th className="p-4">Driver</th>
                            <th className="p-4">Status</th>
                            <th className="p-4">Vehicle Details</th>
                            <th className="p-4">Rating</th>
                            <th className="p-4">Total Earned</th>
                            <th className="p-4 text-right">Actions</th>
                        </tr>
                    </thead>
                    <tbody className="divide-y divide-dark-100 dark:divide-white/5">
                        {filteredDrivers.map((driver) => (
                            <tr key={driver.id} className="hover:bg-dark-50 dark:hover:bg-white/5 transition-colors group">
                                <td className="p-4">
                                    <div className="flex items-center gap-3">
                                        <div className="w-10 h-10 rounded-full bg-dark-200 dark:bg-dark-800 overflow-hidden">
                                            <img src={`https://ui-avatars.com/api/?name=${driver.name}&background=random`} alt={driver.name} className="w-full h-full object-cover"/>
                                        </div>
                                        <div>
                                            <div className="font-bold text-dark-900 dark:text-white text-sm">{driver.name}</div>
                                            <div className="text-xs text-dark-500 flex items-center gap-1"><Phone size={10}/> {driver.phone || '+93 700 000 000'}</div>
                                        </div>
                                    </div>
                                </td>
                                <td className="p-4">
                                    <span className={`inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-bold capitalize
                                        ${driver.status === 'available' ? 'bg-green-100 text-green-700 dark:bg-green-500/20 dark:text-green-400' : 
                                          driver.status === 'busy' ? 'bg-orange-100 text-orange-700 dark:bg-orange-500/20 dark:text-orange-400' : 
                                          driver.status === 'suspended' ? 'bg-red-100 text-red-700 dark:bg-red-500/20 dark:text-red-400' :
                                          'bg-dark-100 text-dark-600 dark:bg-white/10 dark:text-dark-400'}`}>
                                        <span className={`w-1.5 h-1.5 rounded-full mr-1.5 ${driver.status === 'available' ? 'bg-green-500' : driver.status === 'busy' ? 'bg-orange-500' : driver.status === 'suspended' ? 'bg-red-500' : 'bg-dark-400'}`}></span>
                                        {driver.status}
                                    </span>
                                </td>
                                <td className="p-4">
                                    <div className="text-sm font-medium text-dark-900 dark:text-white">{driver.vehicle}</div>
                                    <div className="text-xs text-dark-500 flex items-center gap-2">
                                        <span className="capitalize">{driver.type}</span>
                                        {driver.licensePlate && <span className="bg-dark-100 dark:bg-white/10 px-1 rounded font-mono text-[10px]">{driver.licensePlate}</span>}
                                    </div>
                                </td>
                                <td className="p-4">
                                    <div className="flex items-center gap-1 text-sm font-bold text-dark-900 dark:text-white">
                                        <Star size={14} className="fill-yellow-400 text-yellow-400" />
                                        {driver.rating.toFixed(1)}
                                    </div>
                                    <div className="text-[10px] text-dark-500">{driver.totalRides || 0} rides</div>
                                </td>
                                <td className="p-4">
                                    <div className="font-mono text-sm font-bold text-dark-900 dark:text-white">؋{(driver.earnings || 0).toLocaleString()}</div>
                                </td>
                                <td className="p-4 text-right">
                                    <div className="flex items-center justify-end gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                                        <button onClick={() => handleEditClick(driver)} className="p-2 rounded-lg hover:bg-dark-100 dark:hover:bg-white/10 text-brand-600 dark:text-brand-400 transition-colors" title="Edit">
                                            <Edit2 size={16} />
                                        </button>
                                        <button 
                                            onClick={() => handleBanDriver(driver.id, driver.status)} 
                                            className={`p-2 rounded-lg hover:bg-opacity-20 transition-colors ${driver.status === 'suspended' ? 'text-green-500 hover:bg-green-100' : 'text-red-500 hover:bg-red-100'}`}
                                            title={driver.status === 'suspended' ? 'Activate' : 'Suspend'}
                                        >
                                            {driver.status === 'suspended' ? <CheckCircle size={16} /> : <Ban size={16} />}
                                        </button>
                                    </div>
                                </td>
                            </tr>
                        ))}
                    </tbody>
                </table>
                {filteredDrivers.length === 0 && (
                    <div className="p-12 text-center text-dark-500">
                        No drivers found matching your criteria.
                    </div>
                )}
            </div>

            {/* Edit Driver Modal */}
            {isEditModalOpen && (
                <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm animate-in fade-in duration-200">
                    <Card className="w-full max-w-2xl bg-white dark:bg-dark-900 max-h-[90vh] overflow-hidden flex flex-col shadow-2xl">
                        <div className="p-6 border-b border-dark-100 dark:border-white/5 flex justify-between items-center">
                            <h2 className="text-xl font-bold text-dark-900 dark:text-white">Edit Driver Profile</h2>
                            <button onClick={() => setIsEditModalOpen(false)} className="text-dark-400 hover:text-dark-900 dark:hover:text-white"><XCircle size={24} /></button>
                        </div>

                        <div className="flex-1 overflow-y-auto p-6 space-y-6">
                            {/* Personal Info */}
                            <div className="space-y-4">
                                <h3 className="text-sm font-bold text-dark-500 uppercase tracking-wider border-b border-dark-100 dark:border-white/5 pb-2">Personal Details</h3>
                                <div className="grid grid-cols-2 gap-4">
                                    <div>
                                        <label className="text-xs font-bold text-dark-400 mb-1 block">Full Name</label>
                                        <input 
                                            type="text" 
                                            value={editForm.name || ''} 
                                            onChange={e => setEditForm({...editForm, name: e.target.value})}
                                            className="w-full p-3 bg-dark-50 dark:bg-white/5 border border-dark-200 dark:border-white/10 rounded-xl text-sm"
                                        />
                                    </div>
                                    <div>
                                        <label className="text-xs font-bold text-dark-400 mb-1 block">Phone Number</label>
                                        <input 
                                            type="text" 
                                            value={editForm.phone || ''} 
                                            onChange={e => setEditForm({...editForm, phone: e.target.value})}
                                            className="w-full p-3 bg-dark-50 dark:bg-white/5 border border-dark-200 dark:border-white/10 rounded-xl text-sm"
                                        />
                                    </div>
                                </div>
                            </div>

                            {/* Vehicle Info */}
                            <div className="space-y-4">
                                <h3 className="text-sm font-bold text-dark-500 uppercase tracking-wider border-b border-dark-100 dark:border-white/5 pb-2">Vehicle Information</h3>
                                <div className="grid grid-cols-2 gap-4">
                                    <div>
                                        <label className="text-xs font-bold text-dark-400 mb-1 block">Vehicle Model</label>
                                        <input 
                                            type="text" 
                                            value={editForm.vehicle || ''} 
                                            onChange={e => setEditForm({...editForm, vehicle: e.target.value})}
                                            className="w-full p-3 bg-dark-50 dark:bg-white/5 border border-dark-200 dark:border-white/10 rounded-xl text-sm"
                                        />
                                    </div>
                                    <div>
                                        <label className="text-xs font-bold text-dark-400 mb-1 block">License Plate</label>
                                        <input 
                                            type="text" 
                                            value={editForm.licensePlate || ''} 
                                            onChange={e => setEditForm({...editForm, licensePlate: e.target.value})}
                                            className="w-full p-3 bg-dark-50 dark:bg-white/5 border border-dark-200 dark:border-white/10 rounded-xl text-sm font-mono"
                                        />
                                    </div>
                                    <div>
                                        <label className="text-xs font-bold text-dark-400 mb-1 block">Service Class</label>
                                        <select 
                                            value={editForm.type} 
                                            onChange={e => setEditForm({...editForm, type: e.target.value as any})}
                                            className="w-full p-3 bg-dark-50 dark:bg-white/5 border border-dark-200 dark:border-white/10 rounded-xl text-sm"
                                        >
                                            <option value="eco">Eco</option>
                                            <option value="plus">Plus</option>
                                            <option value="lux">Lux</option>
                                        </select>
                                    </div>
                                </div>
                            </div>

                            {/* Documents Mock */}
                            <div className="space-y-4">
                                <h3 className="text-sm font-bold text-dark-500 uppercase tracking-wider border-b border-dark-100 dark:border-white/5 pb-2">Documents</h3>
                                <div className="grid grid-cols-2 gap-4">
                                    <div className="p-4 rounded-xl border border-green-200 bg-green-50 dark:bg-green-500/10 dark:border-green-500/20 flex items-center gap-3">
                                        <FileText className="text-green-600 dark:text-green-400" size={20} />
                                        <div>
                                            <div className="text-sm font-bold text-dark-900 dark:text-white">Driving License</div>
                                            <div className="text-xs text-green-600 dark:text-green-400 font-bold flex items-center gap-1"><CheckCircle size={10}/> Verified</div>
                                        </div>
                                    </div>
                                    <div className="p-4 rounded-xl border border-dark-200 dark:border-white/10 bg-dark-50 dark:bg-white/5 flex items-center gap-3 opacity-60">
                                        <FileText className="text-dark-400" size={20} />
                                        <div>
                                            <div className="text-sm font-bold text-dark-900 dark:text-white">Vehicle Insurance</div>
                                            <div className="text-xs text-dark-500">Expires in 30 days</div>
                                        </div>
                                    </div>
                                </div>
                            </div>
                        </div>

                        <div className="p-6 border-t border-dark-100 dark:border-white/5 bg-dark-50 dark:bg-white/5 flex justify-end gap-3">
                            <Button variant="ghost" onClick={() => setIsEditModalOpen(false)}>Cancel</Button>
                            <Button onClick={handleSaveDriver}>Save Changes</Button>
                        </div>
                    </Card>
                </div>
            )}
        </div>
    );
};
